INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633000,1,'设计模式','设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。 本教程将通过 Java 实例，一步一步向您讲解设计模式的概念。 无论您是新手，还是老手，本教程都值得一读。对于那些具有丰富的开发经验的开发人员，学习设计模式有助于了解在软件开发过程中所面临的问题的最佳解决方案；对于那些经验不足的开发人员，学习设计模式有助于通过一种简单快捷的方式来学习软件设计。 在您开始阅读本教程之前，您必须具备基本的 Java 编程的概念...','# 设计模式\n\n![图片](/api/uploads/files/runoob/design_pattern/dp-e3aa0ad68f.png)\n\n设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。\n\n本教程将通过 Java 实例，一步一步向您讲解设计模式的概念。\n\n[现在开始学习设计模式！](https://www.runoob.com/design-pattern/design-pattern-intro.html)\n\n无论您是新手，还是老手，本教程都值得一读。对于那些具有丰富的开发经验的开发人员，学习设计模式有助于了解在软件开发过程中所面临的问题的最佳解决方案；对于那些经验不足的开发人员，学习设计模式有助于通过一种简单快捷的方式来学习软件设计。\n\n在您开始阅读本教程之前，您必须具备基本的 Java 编程的概念。如果您还不了解这些概念，那么建议您先阅读我们的 [Java 教程](https://www.runoob.com/java/java-tutorial.html)。\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/design-pattern-tutorial.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-design-pattern-tutorial','设计模式 - 设计模式教程','设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。...',0,'PUBLISHED',2637,87,50,9,'2025-07-01 00:00:00','2025-07-01 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633001,1,'设计模式简介','设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。 设计模式是一套被反复使用的、多数人知晓的、经过分类编目的、代码设计经验的总结。使用设计模式是为了重用代码、让代码更容易被他人理解、保证代码可靠性。 毫无疑问，设计模式于己于他人于系统都是多赢的，设计模式使代码编制真正工程化，设计模式是软件工程的基石，如同大厦的一块块砖石一样。项目中合理地运用设计模式可以完美地解决很多问题，每种模式在现实中都有相应的原理来与...','# 设计模式简介\n\n设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。\n\n设计模式是一套被反复使用的、多数人知晓的、经过分类编目的、代码设计经验的总结。使用设计模式是为了重用代码、让代码更容易被他人理解、保证代码可靠性。 毫无疑问，设计模式于己于他人于系统都是多赢的，设计模式使代码编制真正工程化，设计模式是软件工程的基石，如同大厦的一块块砖石一样。项目中合理地运用设计模式可以完美地解决很多问题，每种模式在现实中都有相应的原理来与之对应，每种模式都描述了一个在我们周围不断重复发生的问题，以及该问题的核心解决方案，这也是设计模式能被广泛应用的原因。\n\n在 1994 年，由 Erich Gamma、Richard Helm、Ralph Johnson 和 John Vlissides 四人合著出版了一本名为 Design Patterns - Elements of Reusable Object-Oriented Software（中文译名：设计模式 - 可复用的面向对象软件元素） 的书，该书首次提到了软件开发中设计模式的概念。\n\n四位作者合称 GOF（全拼 Gang of Four）。他们所提出的设计模式主要是基于以下的面向对象设计原则。\n\n- 对接口编程而不是对实现编程。\n- 优先使用对象组合而不是继承。\n\n设计模式在软件开发中的两个主要用途。\n\n### 开发人员的共同平台\n\n设计模式提供了一个标准的术语系统，且具体到特定的情景。例如，单例设计模式意味着使用单个对象，这样所有熟悉单例设计模式的开发人员都能使用单个对象，并且可以通过这种方式告诉对方，程序使用的是单例模式。\n\n### 最佳的实践\n\n设计模式已经经历了很长一段时间的发展，它们提供了软件开发过程中面临的一般问题的最佳解决方案。学习这些模式有助于经验不足的开发人员通过一种简单快捷的方式来学习软件设计。\n\n根据设计模式的参考书 Design Patterns - Elements of Reusable Object-Oriented Software（中文译名：设计模式 - 可复用的面向对象软件元素） 中所提到的，总共有 23 种设计模式。这些模式可以分为三大类：创建型模式（Creational Patterns）、结构型模式（Structural Patterns）、行为型模式（Behavioral Patterns）。当然，我们还会讨论另一类设计模式：J2EE 设计模式。\n\n| 序号 | 模式 & 描述 | 包括 |\n| --- | --- | --- |\n| 1 | 创建型模式 这些设计模式提供了一种在创建对象的同时隐藏创建逻辑的方式，而不是使用 new 运算符直接实例化对象。这使得程序在判断针对某个给定实例需要创建哪些对象时更加灵活。 | 工厂模式（Factory Pattern） 抽象工厂模式（Abstract Factory Pattern） 单例模式（Singleton Pattern） 建造者模式（Builder Pattern） 原型模式（Prototype Pattern） |\n| 2 | 结构型模式 这些模式关注对象之间的组合和关系，旨在解决如何构建灵活且可复用的类和对象结构。 | 适配器模式（Adapter Pattern） 桥接模式（Bridge Pattern） 过滤器模式（Filter、Criteria Pattern） 组合模式（Composite Pattern） 装饰器模式（Decorator Pattern） 外观模式（Facade Pattern） 享元模式（Flyweight Pattern） 代理模式（Proxy Pattern） |\n| 3 | 行为型模式 这些模式关注对象之间的通信和交互，旨在解决对象之间的责任分配和算法的封装。 | 责任链模式（Chain of Responsibility Pattern） 命令模式（Command Pattern） 解释器模式（Interpreter Pattern） 迭代器模式（Iterator Pattern） 中介者模式（Mediator Pattern） 备忘录模式（Memento Pattern） 观察者模式（Observer Pattern） 状态模式（State Pattern） 空对象模式（Null Object Pattern） 策略模式（Strategy Pattern） 模板模式（Template Pattern） 访问者模式（Visitor Pattern） |\n| 4 | J2EE 模式 这些设计模式特别关注表示层。这些模式是由 Sun Java Center 鉴定的。 | MVC 模式（MVC Pattern） 业务代表模式（Business Delegate Pattern） 组合实体模式（Composite Entity Pattern） 数据访问对象模式（Data Access Object Pattern） 前端控制器模式（Front Controller Pattern） 拦截过滤器模式（Intercepting Filter Pattern） 服务定位器模式（Service Locator Pattern） 传输对象模式（Transfer Object Pattern） |\n\n下面用一个图片来整体描述一下设计模式之间的关系：\n\n![设计模式之间的关系](/api/uploads/files/runoob/design_pattern/mmexport1707099938077-a685930e78.png)\n\n- 提供了一种共享的设计词汇和概念，使开发人员能够更好地沟通和理解彼此的设计意图。\n- 提供了经过验证的解决方案，可以提高软件的可维护性、可复用性和灵活性。\n- 促进了代码的重用，避免了重复的设计和实现。\n- 通过遵循设计模式，可以减少系统中的错误和问题，提高代码质量。\n\n1、开闭原则（Open Close Principle）\n\n开闭原则的意思是：对扩展开放，对修改关闭。在程序需要进行拓展的时候，不能去修改原有的代码，实现一个热插拔的效果。简言之，是为了使程序的扩展性好，易于维护和升级。想要达到这样的效果，我们需要使用接口和抽象类，后面的具体设计中我们会提到这点。\n\n2、里氏代换原则（Liskov Substitution Principle）\n\n里氏代换原则是面向对象设计的基本原则之一。 里氏代换原则中说，任何基类可以出现的地方，子类一定可以出现。LSP 是继承复用的基石，只有当派生类可以替换掉基类，且软件单位的功能不受到影响时，基类才能真正被复用，而派生类也能够在基类的基础上增加新的行为。里氏代换原则是对开闭原则的补充。实现开闭原则的关键步骤就是抽象化，而基类与子类的继承关系就是抽象化的具体实现，所以里氏代换原则是对实现抽象化的具体步骤的规范。\n\n3、依赖倒转原则（Dependence Inversion Principle）\n\n这个原则是开闭原则的基础，具体内容：针对接口编程，依赖于抽象而不依赖于具体。\n\n4、接口隔离原则（Interface Segregation Principle）\n\n这个原则的意思是：使用多个隔离的接口，比使用单个接口要好。它还有另外一个意思是：降低类之间的耦合度。由此可见，其实设计模式就是从大型软件架构出发、便于升级和维护的软件设计思想，它强调降低依赖，降低耦合。\n\n5、迪米特法则，又称最少知道原则（Demeter Principle）\n\n最少知道原则是指：一个实体应当尽量少地与其他实体之间发生相互作用，使得系统功能模块相对独立。\n\n6、合成复用原则（Composite Reuse Principle）\n\n合成复用原则是指：尽量使用合成/聚合的方式，而不是使用继承。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/design-pattern-intro.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-design-pattern-intro','设计模式简介 - 设计模式教程','设计模式（Design pattern）代表了最佳的实践，通常被有经验的面向对象的软件开发人员所采用。设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。...',0,'PUBLISHED',2774,94,55,10,'2025-07-02 00:00:00','2025-07-02 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633002,1,'工厂模式','工厂模式（Factory Pattern）是 Java 中最常用的设计模式之一，它提供了一种创建对象的方式，使得创建对象的过程与使用对象的过程分离。 工厂模式提供了一种创建对象的方式，而无需指定要创建的具体类。 通过使用工厂模式，可以将对象的创建逻辑封装在一个工厂类中，而不是在客户端代码中直接实例化对象，这样可以提高代码的可维护性和可扩展性。 1、简单工厂模式（Simple Factory Pattern）：','# 工厂模式\n\n工厂模式（Factory Pattern）是 Java 中最常用的设计模式之一，它提供了一种创建对象的方式，使得创建对象的过程与使用对象的过程分离。\n\n工厂模式提供了一种创建对象的方式，而无需指定要创建的具体类。\n\n通过使用工厂模式，可以将对象的创建逻辑封装在一个工厂类中，而不是在客户端代码中直接实例化对象，这样可以提高代码的可维护性和可扩展性。\n\n### 工厂模式的类型\n\n1、简单工厂模式（Simple Factory Pattern）：\n\n- 简单工厂模式不是一个正式的设计模式，但它是工厂模式的基础。它使用一个单独的工厂类来创建不同的对象，根据传入的参数决定创建哪种类型的对象。\n\n2、工厂方法模式（Factory Method Pattern）：\n\n- 工厂方法模式定义了一个创建对象的接口，但由子类决定实例化哪个类。工厂方法将对象的创建延迟到子类。\n\n3、抽象工厂模式（Abstract Factory Pattern）：\n\n- 抽象工厂模式提供一个创建一系列相关或互相依赖对象的接口，而无需指定它们具体的类。\n\n## 概要\n\n### 意图\n\n定义一个创建对象的接口，让其子类决定实例化哪一个具体的类。工厂模式使对象的创建过程延迟到子类。\n\n### 主要解决\n\n接口选择的问题。\n\n### 何时使用\n\n当我们需要在不同条件下创建不同实例时。\n\n### 如何解决\n\n通过让子类实现工厂接口，返回一个抽象的产品。\n\n### 关键代码\n\n对象的创建过程在子类中实现。\n\n### 应用实例\n\n1. 汽车制造：你需要一辆汽车，只需从工厂提货，而不需要关心汽车的制造过程及其内部实现。\n2. Hibernate：更换数据库时，只需更改方言（Dialect）和数据库驱动（Driver），即可实现对不同数据库的切换。\n\n### 优点\n\n1. 调用者只需要知道对象的名称即可创建对象。\n2. 扩展性高，如果需要增加新产品，只需扩展一个工厂类即可。\n3. 屏蔽了产品的具体实现，调用者只关心产品的接口。\n\n### 缺点\n\n每次增加一个产品时，都需要增加一个具体类和对应的工厂，使系统中类的数量成倍增加，增加了系统的复杂度和具体类的依赖。\n\n### 使用场景\n\n1. 日志记录：日志可能记录到本地硬盘、系统事件、远程服务器等，用户可以选择记录日志的位置。\n2. 数据库访问：当用户不知道最终系统使用哪种数据库，或者数据库可能变化时。\n3. 连接服务器的框架设计：需要支持 "POP3"、"IMAP"、"HTTP" 三种协议，可以将这三种协议作为产品类，共同实现一个接口。\n\n### 注意事项\n\n工厂模式适用于生成复杂对象的场景。如果对象较为简单，通过 new 即可完成创建，则不必使用工厂模式。使用工厂模式会引入一个工厂类，增加系统复杂度。\n\n### 结构\n\n工厂模式包含以下几个主要角色：\n\n- 抽象产品（Abstract Product）：定义了产品的共同接口或抽象类。它可以是具体产品类的父类或接口，规定了产品对象的共同方法。\n- 具体产品（Concrete Product）：实现了抽象产品接口，定义了具体产品的特定行为和属性。\n- 抽象工厂（Abstract Factory）：声明了创建产品的抽象方法，可以是接口或抽象类。它可以有多个方法用于创建不同类型的产品。\n- 具体工厂（Concrete Factory）：实现了抽象工厂接口，负责实际创建具体产品的对象。\n\n我们将创建一个 Shape 接口和实现 Shape 接口的实体类。下一步是定义工厂类 ShapeFactory。\n\nFactoryPatternDemo 类使用 ShapeFactory 来获取 Shape 对象。它将向 ShapeFactory 传递信息（CIRCLE / RECTANGLE / SQUARE），以便获取它所需对象的类型。\n\n![工厂模式的 UML 图](/api/uploads/files/runoob/design_pattern/AB6B814A-0B09-4863-93D6-1E22D6B07FF8-6933233d2e.jpg)\n\n### 步骤 1\n\n创建一个接口:\n\n## Shape.java\n\npublic interface Shape {\nvoid draw();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## Rectangle.java\n\npublic class Rectangle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Rectangle::draw() method.");\n   }\n}\n\n## Square.java\n\npublic class Square implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Square::draw() method.");\n   }\n}\n\n## Circle.java\n\npublic class Circle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Circle::draw() method.");\n   }\n}\n\n### 步骤 3\n\n创建一个工厂，生成基于给定信息的实体类的对象。\n\n## ShapeFactory.java\n\npublic class ShapeFactory {\n//使用 getShape 方法获取形状类型的对象\npublic Shape getShape(String shapeType){\nif(shapeType == null){\nreturn null;\n      }\nif(shapeType.equalsIgnoreCase("CIRCLE")){\nreturn new Circle();\n      } else if(shapeType.equalsIgnoreCase("RECTANGLE")){\nreturn new Rectangle();\n      } else if(shapeType.equalsIgnoreCase("SQUARE")){\nreturn new Square();\n      }\nreturn null;\n   }\n}\n\n### 步骤 4\n\n使用该工厂，通过传递类型信息来获取实体类的对象。\n\n## FactoryPatternDemo.java\n\npublic class FactoryPatternDemo {\npublic static void main(String[] args) {\nShapeFactory shapeFactory = new ShapeFactory();\n\n      //获取 Circle 的对象，并调用它的 draw 方法\nShape shape1 = shapeFactory.getShape("CIRCLE");\n\n      //调用 Circle 的 draw 方法\nshape1.draw();\n\n      //获取 Rectangle 的对象，并调用它的 draw 方法\nShape shape2 = shapeFactory.getShape("RECTANGLE");\n\n      //调用 Rectangle 的 draw 方法\nshape2.draw();\n\n      //获取 Square 的对象，并调用它的 draw 方法\nShape shape3 = shapeFactory.getShape("SQUARE");\n\n      //调用 Square 的 draw 方法\nshape3.draw();\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nInside Circle::draw() method.\nInside Rectangle::draw() method.\nInside Square::draw() method.\n```\n\n### 其他相关文章\n\n> - [设计模式 – 工厂模式](https://www.runoob.com/w3cnote/factory-pattern.html)\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/factory-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-factory-pattern','工厂模式 - 设计模式教程','工厂模式（Factory Pattern）是 Java 中最常用的设计模式之一，它提供了一种创建对象的方式，使得创建对象的过程与使用对象的过程分离。 工厂模式提供了一种创建对象的方式，而无需指定要创建的具体类。 通过使用工厂模式，可以将对象...',0,'PUBLISHED',2911,101,60,11,'2025-07-03 00:00:00','2025-07-03 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633003,1,'抽象工厂模式','抽象工厂模式（Abstract Factory Pattern）是围绕一个超级工厂创建其他工厂。该超级工厂又称为其他工厂的工厂。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。 在抽象工厂模式中，接口是负责创建一个相关对象的工厂，不需要显式指定它们的类。每个生成的工厂都能按照工厂模式提供对象。 抽象工厂模式提供了一种创建一系列相关或相互依赖对象的接口，而无需指定具体实现类。通过使用抽象工厂模式，可以将客户端与具体产品的创建过程解耦，使得客户端可以通过工厂接口来创建一族产品。 提供一个创建一系列相关或相互依赖对象的接口，而无需指定它们的具体类。','# 抽象工厂模式\n\n抽象工厂模式（Abstract Factory Pattern）是围绕一个超级工厂创建其他工厂。该超级工厂又称为其他工厂的工厂。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。\n在抽象工厂模式中，接口是负责创建一个相关对象的工厂，不需要显式指定它们的类。每个生成的工厂都能按照工厂模式提供对象。\n\n抽象工厂模式提供了一种创建一系列相关或相互依赖对象的接口，而无需指定具体实现类。通过使用抽象工厂模式，可以将客户端与具体产品的创建过程解耦，使得客户端可以通过工厂接口来创建一族产品。\n\n### 意图\n\n提供一个创建一系列相关或相互依赖对象的接口，而无需指定它们的具体类。\n\n### 主要解决\n\n接口选择的问题。\n\n### 适用场景\n\n当系统需要创建多个相关或依赖的对象，而不需要指定具体类时。\n\n### 解决方案\n\n在一个产品族中定义多个产品，由具体工厂实现创建这些产品的方法。\n\n### 关键代码\n\n在一个工厂中聚合多个同类产品的创建方法。\n\n### 应用实例\n\n假设有不同类型的衣柜，每个衣柜（具体工厂）只能存放一类衣服（成套的具体产品），如商务装、时尚装等。每套衣服包括具体的上衣和裤子（具体产品）。所有衣柜都是衣柜类（抽象工厂）的具体实现，所有上衣和裤子分别实现上衣接口和裤子接口（抽象产品）。\n\n### 优点\n\n1. 确保同一产品族的对象一起工作。\n2. 客户端不需要知道每个对象的具体类，简化了代码。\n\n### 缺点\n\n扩展产品族非常困难。增加一个新的产品族需要修改抽象工厂和所有具体工厂的代码。\n\n### 使用场景\n\n1. QQ 换皮肤时，整套皮肤一起更换。\n2. 创建跨平台应用时，生成不同操作系统的程序。\n\n### 注意事项\n\n增加新的产品族相对容易，而增加新的产品等级结构比较困难。\n\n### 结构\n\n抽象工厂模式包含以下几个主要角色：\n\n- 抽象工厂（Abstract Factory）：声明了一组用于创建产品对象的方法，每个方法对应一种产品类型。抽象工厂可以是接口或抽象类。\n- 具体工厂（Concrete Factory）：实现了抽象工厂接口，负责创建具体产品对象的实例。\n- 抽象产品（Abstract Product）：定义了一组产品对象的共同接口或抽象类，描述了产品对象的公共方法。\n- 具体产品（Concrete Product）：实现了抽象产品接口，定义了具体产品的特定行为和属性。\n\n抽象工厂模式通常涉及一族相关的产品，每个具体工厂类负责创建该族中的具体产品。客户端通过使用抽象工厂接口来创建产品对象，而不需要直接使用具体产品的实现类。\n\n我们将创建 Shape 和 Color 接口和实现这些接口的实体类。下一步是创建抽象工厂类 AbstractFactory。接着定义工厂类 ShapeFactory 和 ColorFactory，这两个工厂类都是扩展了 AbstractFactory。然后创建一个工厂创造器/生成器类 FactoryProducer。\n\nAbstractFactoryPatternDemo 类使用 FactoryProducer 来获取 AbstractFactory 对象。它将向 AbstractFactory 传递形状信息 Shape（CIRCLE / RECTANGLE / SQUARE），以便获取它所需对象的类型。同时它还向 AbstractFactory 传递颜色信息 Color（RED / GREEN / BLUE），以便获取它所需对象的类型。\n\n[https://www.runoob.com/wp-content/uploads/2014/08/3E13CDD1-2CD2-4C66-BD33-DECBF172AE03.jpg](https://www.runoob.com/wp-content/uploads/2014/08/3E13CDD1-2CD2-4C66-BD33-DECBF172AE03.jpg)\n\n### 步骤 1\n\n为形状创建一个接口。\n\n## Shape.java\n\npublic interface Shape {\nvoid draw();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\nRectangle.java\n\n## Rectangle.java\n\npublic class Rectangle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Rectangle::draw() method.");\n   }\n}\n\n## Square.java\n\npublic class Square implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Square::draw() method.");\n   }\n}\n\n## Circle.java\n\npublic class Circle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Circle::draw() method.");\n   }\n}\n\n### 步骤 3\n\n为颜色创建一个接口。\n\n## Color.java\n\npublic interface Color {\nvoid fill();\n}\n\n### 步骤4\n\n创建实现接口的实体类。\n\n## Red.java\n\npublic class Red implements Color {\n\n   @Override\npublic void fill() {\nSystem.out.println("Inside Red::fill() method.");\n   }\n}\n\n## Green.java\n\npublic class Green implements Color {\n\n   @Override\npublic void fill() {\nSystem.out.println("Inside Green::fill() method.");\n   }\n}\n\n## Blue.java\n\npublic class Blue implements Color {\n\n   @Override\npublic void fill() {\nSystem.out.println("Inside Blue::fill() method.");\n   }\n}\n\n### 步骤 5\n\n为 Color 和 Shape 对象创建抽象类来获取工厂。\n\n## AbstractFactory.java\n\npublic abstract class AbstractFactory {\npublic abstract Color getColor(String color);\n   public abstract Shape getShape(String shape);\n}\n\n### 步骤 6\n\n创建扩展了 AbstractFactory 的工厂类，基于给定的信息生成实体类的对象。\n\n## ShapeFactory.java\n\npublic class ShapeFactory extends AbstractFactory {\n\n   @Override\npublic Shape getShape(String shapeType){\nif(shapeType == null){\nreturn null;\n      }\nif(shapeType.equalsIgnoreCase("CIRCLE")){\nreturn new Circle();\n      } else if(shapeType.equalsIgnoreCase("RECTANGLE")){\nreturn new Rectangle();\n      } else if(shapeType.equalsIgnoreCase("SQUARE")){\nreturn new Square();\n      }\nreturn null;\n   }\n\n   @Override\npublic Color getColor(String color) {\nreturn null;\n   }\n}\n\n## ColorFactory.java\n\npublic class ColorFactory extends AbstractFactory {\n\n   @Override\npublic Shape getShape(String shapeType){\nreturn null;\n   }\n\n   @Override\npublic Color getColor(String color) {\nif(color == null){\nreturn null;\n      }\nif(color.equalsIgnoreCase("RED")){\nreturn new Red();\n      } else if(color.equalsIgnoreCase("GREEN")){\nreturn new Green();\n      } else if(color.equalsIgnoreCase("BLUE")){\nreturn new Blue();\n      }\nreturn null;\n   }\n}\n\n### 步骤 7\n\n创建一个工厂创造器/生成器类，通过传递形状或颜色信息来获取工厂。\n\n## FactoryProducer.java\n\npublic class FactoryProducer {\npublic static AbstractFactory getFactory(String choice){\nif(choice.equalsIgnoreCase("SHAPE")){\nreturn new ShapeFactory();\n      } else if(choice.equalsIgnoreCase("COLOR")){\nreturn new ColorFactory();\n      }\nreturn null;\n   }\n}\n\n### 步骤 8\n\n使用 FactoryProducer 来获取 AbstractFactory，通过传递类型信息来获取实体类的对象。\n\n## AbstractFactoryPatternDemo.java\n\npublic class AbstractFactoryPatternDemo {\npublic static void main(String[] args) {\n//获取形状工厂\nAbstractFactory shapeFactory = FactoryProducer.getFactory("SHAPE");\n\n      //获取形状为 Circle 的对象\nShape shape1 = shapeFactory.getShape("CIRCLE");\n\n      //调用 Circle 的 draw 方法\nshape1.draw();\n\n      //获取形状为 Rectangle 的对象\nShape shape2 = shapeFactory.getShape("RECTANGLE");\n\n      //调用 Rectangle 的 draw 方法\nshape2.draw();\n\n      //获取形状为 Square 的对象\nShape shape3 = shapeFactory.getShape("SQUARE");\n\n      //调用 Square 的 draw 方法\nshape3.draw();\n\n      //获取颜色工厂\nAbstractFactory colorFactory = FactoryProducer.getFactory("COLOR");\n\n      //获取颜色为 Red 的对象\nColor color1 = colorFactory.getColor("RED");\n\n      //调用 Red 的 fill 方法\ncolor1.fill();\n\n      //获取颜色为 Green 的对象\nColor color2 = colorFactory.getColor("GREEN");\n\n      //调用 Green 的 fill 方法\ncolor2.fill();\n\n      //获取颜色为 Blue 的对象\nColor color3 = colorFactory.getColor("BLUE");\n\n      //调用 Blue 的 fill 方法\ncolor3.fill();\n   }\n}\n\n### 步骤 9\n\n执行程序，输出结果：\n\n```text\n\nInside Circle::draw() method.\nInside Rectangle::draw() method.\nInside Square::draw() method.\nInside Red::fill() method.\nInside Green::fill() method.\nInside Blue::fill() method.\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/abstract-factory-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-abstract-factory-pattern','抽象工厂模式 - 设计模式教程','抽象工厂模式（Abstract Factory Pattern）是围绕一个超级工厂创建其他工厂。该超级工厂又称为其他工厂的工厂。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。 在抽象工厂模式中，接口是负责创建一个相关对象...',0,'PUBLISHED',3048,108,65,12,'2025-07-04 00:00:00','2025-07-04 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633004,1,'单例模式','单例模式（Singleton Pattern）是 Java 中最简单的设计模式之一。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。 这种模式涉及到一个单一的类，该类负责创建自己的对象，同时确保只有单个对象被创建。这个类提供了一种访问其唯一的对象的方式，可以直接访问，不需要实例化该类的对象。 单例模式是一种创建型设计模式，它确保一个类只有一个实例，并提供了一个全局访问点来访问该实例。 确保一个类只有一个实例，并提供一个全局访问点来访问该实例。','# 单例模式\n\n单例模式（Singleton Pattern）是 Java 中最简单的设计模式之一。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。\n\n这种模式涉及到一个单一的类，该类负责创建自己的对象，同时确保只有单个对象被创建。这个类提供了一种访问其唯一的对象的方式，可以直接访问，不需要实例化该类的对象。\n\n单例模式是一种创建型设计模式，它确保一个类只有一个实例，并提供了一个全局访问点来访问该实例。\n\n注意：\n\n- 1、单例类只能有一个实例。\n- 2、单例类必须自己创建自己的唯一实例。\n- 3、单例类必须给所有其他对象提供这一实例。\n\n### 单例模式（Singleton Pattern）\n\n### 意图\n\n确保一个类只有一个实例，并提供一个全局访问点来访问该实例。\n\n### 主要解决\n\n频繁创建和销毁全局使用的类实例的问题。\n\n### 何时使用\n\n当需要控制实例数目，节省系统资源时。\n\n### 如何解决\n\n检查系统是否已经存在该单例，如果存在则返回该实例；如果不存在则创建一个新实例。\n\n### 关键代码\n\n构造函数是私有的。\n\n### 应用实例\n\n- 一个班级只有一个班主任。\n- Windows 在多进程多线程环境下操作文件时，避免多个进程或线程同时操作一个文件，需要通过唯一实例进行处理。\n- 设备管理器设计为单例模式，例如电脑有两台打印机，避免同时打印同一个文件。\n\n### 优点\n\n- 内存中只有一个实例，减少内存开销，尤其是频繁创建和销毁实例时（如管理学院首页页面缓存）。\n- 避免资源的多重占用（如写文件操作）。\n\n### 缺点\n\n- 没有接口，不能继承。\n- 与单一职责原则冲突，一个类应该只关心内部逻辑，而不关心实例化方式。\n\n### 使用场景\n\n- 生成唯一序列号。\n- WEB 中的计数器，避免每次刷新都在数据库中增加计数，先缓存起来。\n- 创建消耗资源过多的对象，如 I/O 与数据库连接等。\n\n### 注意事项\n\n- 线程安全：`getInstance()` 方法中需要使用同步锁 `synchronized (Singleton.class)` 防止多线程同时进入造成实例被多次创建。\n- 延迟初始化：实例在第一次调用 `getInstance()` 方法时创建。\n- 序列化和反序列化：重写 `readResolve` 方法以确保反序列化时不会创建新的实例。\n- 反射攻击：在构造函数中添加防护代码，防止通过反射创建新实例。\n- 类加载器问题：注意复杂类加载环境可能导致的多个实例问题。\n\n### 结构\n\n单例模式包含以下几个主要角色：\n\n- 单例类：包含单例实例的类，通常将构造函数声明为私有。\n- 静态成员变量：用于存储单例实例的静态成员变量。\n- 获取实例方法：静态方法，用于获取单例实例。\n- 私有构造函数：防止外部直接实例化单例类。\n- 线程安全处理：确保在多线程环境下单例实例的创建是安全的。\n\n我们将创建一个 SingleObject 类。SingleObject 类有它的私有构造函数和本身的一个静态实例。\n\nSingleObject 类提供了一个静态方法，供外界获取它的静态实例。SingletonPatternDemo 类使用 SingleObject 类来获取 SingleObject 对象。\n\n![单例模式的 UML 图](/api/uploads/files/runoob/design_pattern/62576915-36E0-4B67-B078-704699CA980A-62e5060921.jpg)\n\n### 步骤 1\n\n创建一个 Singleton 类。\n\n## SingleObject.java\n\npublic class SingleObject {\n//创建 SingleObject 的一个对象\nprivate static SingleObject instance = new SingleObject();\n\n   //让构造函数为 private，这样该类就不会被实例化\nprivate SingleObject(){}\n//获取唯一可用的对象\npublic static SingleObject getInstance(){\nreturn instance;\n   }\npublic void showMessage(){\nSystem.out.println("Hello World!");\n   }\n}\n\n### 步骤 2\n\n从 singleton 类获取唯一的对象。\n\n## SingletonPatternDemo.java\n\npublic class SingletonPatternDemo {\npublic static void main(String[] args) {\n//不合法的构造函数\n//编译时错误：构造函数 SingleObject() 是不可见的\n//SingleObject object = new SingleObject();\n//获取唯一可用的对象\nSingleObject object = SingleObject.getInstance();\n\n      //显示消息\nobject.showMessage();\n   }\n}\n\n### 步骤 3\n\n执行程序，输出结果：\n\n```text\n\nHello World!\n```\n\n单例模式的实现有多种方式，如下所示：\n\n### 1、懒汉式，线程不安全\n\n是否 Lazy 初始化：是\n\n是否多线程安全：否\n\n实现难度：易\n\n描述：这种方式是最基本的实现方式，这种实现最大的问题就是不支持多线程。因为没有加锁 synchronized，所以严格意义上它并不算单例模式。\n\n## 实例\n\npublic class Singleton {\nprivate static Singleton instance;\n    private Singleton (){}\npublic static Singleton getInstance() {\nif (instance == null) {\ninstance = new Singleton();\n        }\nreturn instance;\n    }\n}\n\n接下来介绍的几种实现方式都支持多线程，但是在性能上有所差异。\n\n### 2、懒汉式，线程安全\n\n是否 Lazy 初始化：是\n\n是否多线程安全：是\n\n实现难度：易\n\n描述：这种方式具备很好的 lazy loading，能够在多线程中很好的工作，但是，效率很低，99% 情况下不需要同步。\n\n优点：第一次调用才初始化，避免内存浪费。\n\n缺点：必须加锁 synchronized 才能保证单例，但加锁会影响效率。\n\ngetInstance() 的性能对应用程序不是很关键（该方法使用不太频繁）。\n\n## 实例\n\npublic class Singleton {\nprivate static Singleton instance;\n    private Singleton (){}\npublic static synchronized Singleton getInstance() {\nif (instance == null) {\ninstance = new Singleton();\n        }\nreturn instance;\n    }\n}\n\n### 3、饿汉式\n\n是否 Lazy 初始化：否\n\n是否多线程安全：是\n\n实现难度：易\n\n描述：这种方式比较常用，但容易产生垃圾对象。\n\n优点：没有加锁，执行效率会提高。\n\n缺点：类加载时就初始化，浪费内存。\n\n它基于 classloader 机制避免了多线程的同步问题，不过，instance 在类装载时就实例化，虽然导致类装载的原因有很多种，在单例模式中大多数都是调用 getInstance 方法， 但是也不能确定有其他的方式（或者其他的静态方法）导致类装载，这时候初始化 instance 显然没有达到 lazy loading 的效果。\n\n## 实例\n\npublic class Singleton {\nprivate static Singleton instance = new Singleton();\n    private Singleton (){}\npublic static Singleton getInstance() {\nreturn instance;\n    }\n}\n\n### 4、双检锁/双重校验锁（DCL，即 double-checked locking）\n\nJDK 版本：JDK1.5 起\n\n是否 Lazy 初始化：是\n\n是否多线程安全：是\n\n实现难度：较复杂\n\n描述：这种方式采用双锁机制，安全且在多线程情况下能保持高性能。\n\ngetInstance() 的性能对应用程序很关键。\n\n## 实例\n\npublic class Singleton {\nprivate volatile static Singleton singleton;\n    private Singleton (){}\npublic static Singleton getSingleton() {\nif (singleton == null) {\nsynchronized (Singleton.class) {\nif (singleton == null) {\nsingleton = new Singleton();\n            }\n}\n}\nreturn singleton;\n    }\n}\n\n### 5、登记式/静态内部类\n\n是否 Lazy 初始化：是\n\n是否多线程安全：是\n\n实现难度：一般\n\n描述：这种方式能达到双检锁方式一样的功效，但实现更简单。对静态域使用延迟初始化，应使用这种方式而不是双检锁方式。这种方式只适用于静态域的情况，双检锁方式可在实例域需要延迟初始化时使用。\n\n这种方式同样利用了 classloader 机制来保证初始化 instance 时只有一个线程，它跟第 3 种方式不同的是：第 3 种方式只要 Singleton 类被装载了，那么 instance 就会被实例化（没有达到 lazy loading 效果），而这种方式是 Singleton 类被装载了，instance 不一定被初始化。因为 SingletonHolder 类没有被主动使用，只有通过显式调用 getInstance 方法时，才会显式装载 SingletonHolder 类，从而实例化 instance。想象一下，如果实例化 instance 很消耗资源，所以想让它延迟加载，另外一方面，又不希望在 Singleton 类加载时就实例化，因为不能确保 Singleton 类还可能在其他的地方被主动使用从而被加载，那么这个时候实例化 instance 显然是不合适的。这个时候，这种方式相比第 3 种方式就显得很合理。\n\n## 实例\n\npublic class Singleton {\nprivate static class SingletonHolder {\nprivate static final Singleton INSTANCE = new Singleton();\n    }\nprivate Singleton (){}\npublic static final Singleton getInstance() {\nreturn SingletonHolder.INSTANCE;\n    }\n}\n\n### 6、枚举\n\nJDK 版本：JDK1.5 起\n\n是否 Lazy 初始化：否\n\n是否多线程安全：是\n\n实现难度：易\n\n描述：这种实现方式还没有被广泛采用，但这是实现单例模式的最佳方法。它更简洁，自动支持序列化机制，绝对防止多次实例化。\n\n这种方式是 Effective Java 作者 Josh Bloch 提倡的方式，它不仅能避免多线程同步问题，而且还自动支持序列化机制，防止反序列化重新创建新的对象，绝对防止多次实例化。不过，由于 JDK1.5 之后才加入 enum 特性，用这种方式写不免让人感觉生疏，在实际工作中，也很少用。\n\n不能通过 reflection attack 来调用私有构造方法。\n\n## 实例\n\npublic enum Singleton {\nINSTANCE;\n    public void whateverMethod() {\n}\n}\n\n经验之谈：一般情况下，不建议使用第 1 种和第 2 种懒汉方式，建议使用第 3 种饿汉方式。只有在要明确实现 lazy loading 效果时，才会使用第 5 种登记方式。如果涉及到反序列化创建对象时，可以尝试使用第 6 种枚举方式。如果有其他特殊的需求，可以考虑使用第 4 种双检锁方式。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/singleton-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-singleton-pattern','单例模式 - 设计模式教程','单例模式（Singleton Pattern）是 Java 中最简单的设计模式之一。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。 这种模式涉及到一个单一的类，该类负责创建自己的对象，同时确保只有单个对象被创建。这个类提...',0,'PUBLISHED',3185,115,70,13,'2025-07-05 00:00:00','2025-07-05 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633005,1,'建造者模式','建造者模式是一种创建型设计模式，它允许你创建复杂对象的步骤与表示方式相分离。 建造者模式是一种创建型设计模式，它的主要目的是将一个复杂对象的构建过程与其表示相分离，从而可以创建具有不同表示形式的对象。 将一个复杂的构建过程与其表示相分离，使得同样的构建过程可以创建不同的表示。 在软件系统中，一个复杂对象的创建通常由多个部分组成，这些部分的组合经常变化，但组合的算法相对稳定。','# 建造者模式\n\n建造者模式是一种创建型设计模式，它允许你创建复杂对象的步骤与表示方式相分离。\n\n建造者模式是一种创建型设计模式，它的主要目的是将一个复杂对象的构建过程与其表示相分离，从而可以创建具有不同表示形式的对象。\n\n### 意图\n\n将一个复杂的构建过程与其表示相分离，使得同样的构建过程可以创建不同的表示。\n\n### 主要解决\n\n在软件系统中，一个复杂对象的创建通常由多个部分组成，这些部分的组合经常变化，但组合的算法相对稳定。\n\n### 何时使用\n\n当一些基本部件不变，而其组合经常变化时。\n\n### 如何解决\n\n将变与不变的部分分离开。\n\n### 关键代码\n\n- 建造者：创建并提供实例。\n- 导演：管理建造出来的实例的依赖关系和控制构建过程。\n\n### 应用实例\n\n- 去肯德基，汉堡、可乐、薯条、炸鸡翅等是不变的，而其组合是经常变化的，生成出不同的"套餐"。\n- Java 中的 `StringBuilder`。\n\n### 优点\n\n- 分离构建过程和表示，使得构建过程更加灵活，可以构建不同的表示。\n- 可以更好地控制构建过程，隐藏具体构建细节。\n- 代码复用性高，可以在不同的构建过程中重复使用相同的建造者。\n\n### 缺点\n\n- 如果产品的属性较少，建造者模式可能会导致代码冗余。\n- 增加了系统的类和对象数量。\n\n### 使用场景\n\n- 需要生成的对象具有复杂的内部结构。\n- 需要生成的对象内部属性相互依赖。\n\n### 注意事项\n\n与工厂模式的区别是：建造者模式更加关注于零件装配的顺序。\n\n### 结构\n\n建造者模式包含以下几个主要角色：\n\n- 产品（Product）：要构建的复杂对象。产品类通常包含多个部分或属性。\n- 抽象建造者（Builder）：定义了构建产品的抽象接口，包括构建产品的各个部分的方法。\n- 具体建造者（Concrete Builder）：实现抽象建造者接口，具体确定如何构建产品的各个部分，并负责返回最终构建的产品。\n- 指导者（Director）：负责调用建造者的方法来构建产品，指导者并不了解具体的构建过程，只关心产品的构建顺序和方式。\n\n我们假设一个快餐店的商业案例，其中，一个典型的套餐可以是一个汉堡（Burger）和一杯冷饮（Cold drink）。汉堡（Burger）可以是素食汉堡（Veg Burger）或鸡肉汉堡（Chicken Burger），它们是包在纸盒中。冷饮（Cold drink）可以是可口可乐（coke）或百事可乐（pepsi），它们是装在瓶子中。\n\n我们将创建一个表示食物条目（比如汉堡和冷饮）的 Item 接口和实现 Item 接口的实体类，以及一个表示食物包装的 Packing 接口和实现 Packing 接口的实体类，汉堡是包在纸盒中，冷饮是装在瓶子中。\n\n然后我们创建一个 Meal 类，带有 Item 的 ArrayList 和一个通过结合 Item 来创建不同类型的 Meal 对象的 MealBuilder。BuilderPatternDemo 类使用 MealBuilder 来创建一个 Meal。\n\n![建造者模式的 UML 图](/api/uploads/files/runoob/design_pattern/20210315-builder-pattern-15a16fcf10.svg)\n\n### 步骤 1\n\n创建一个表示食物条目和食物包装的接口。\n\n## Item.java\n\npublic interface Item {\npublic String name();\n   public Packing packing();\n   public float price();\n}\n\n## Packing.java\n\npublic interface Packing {\npublic String pack();\n}\n\n### 步骤 2\n\n创建实现 Packing 接口的实体类。\n\n## Wrapper.java\n\npublic class Wrapper implements Packing {\n\n   @Override\npublic String pack() {\nreturn "Wrapper";\n   }\n}\n\n## Bottle.java\n\npublic class Bottle implements Packing {\n\n   @Override\npublic String pack() {\nreturn "Bottle";\n   }\n}\n\n### 步骤 3\n\n创建实现 Item 接口的抽象类，该类提供了默认的功能。\n\n## Burger.java\n\npublic abstract class Burger implements Item {\n\n   @Override\npublic Packing packing() {\nreturn new Wrapper();\n   }\n\n   @Override\npublic abstract float price();\n}\n\n## ColdDrink.java\n\npublic abstract class ColdDrink implements Item {\n\n    @Override\npublic Packing packing() {\nreturn new Bottle();\n    }\n\n    @Override\npublic abstract float price();\n}\n\n### 步骤 4\n\n创建扩展了 Burger 和 ColdDrink 的实体类。\n\n## VegBurger.java\n\npublic class VegBurger extends Burger {\n\n   @Override\npublic float price() {\nreturn 25.0f;\n   }\n\n   @Override\npublic String name() {\nreturn "Veg Burger";\n   }\n}\n\n## ChickenBurger.java\n\npublic class ChickenBurger extends Burger {\n\n   @Override\npublic float price() {\nreturn 50.5f;\n   }\n\n   @Override\npublic String name() {\nreturn "Chicken Burger";\n   }\n}\n\n## Coke.java\n\npublic class Coke extends ColdDrink {\n\n   @Override\npublic float price() {\nreturn 30.0f;\n   }\n\n   @Override\npublic String name() {\nreturn "Coke";\n   }\n}\n\n## Pepsi.java\n\npublic class Pepsi extends ColdDrink {\n\n   @Override\npublic float price() {\nreturn 35.0f;\n   }\n\n   @Override\npublic String name() {\nreturn "Pepsi";\n   }\n}\n\n### 步骤 5\n\n创建一个 Meal 类，带有上面定义的 Item 对象。\n\n## Meal.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Meal {\nprivate List<Item> items = new ArrayList<Item>();\n\n   public void addItem(Item item){\nitems.add(item);\n   }\npublic float getCost(){\nfloat cost = 0.0f;\n      for (Item item : items) {\ncost += item.price();\n      }\nreturn cost;\n   }\npublic void showItems(){\nfor (Item item : items) {\nSystem.out.print("Item : "+item.name());\n         System.out.print(", Packing : "+item.packing().pack());\n         System.out.println(", Price : "+item.price());\n      }\n}\n}\n\n### 步骤 6\n\n创建一个 MealBuilder 类，实际的 builder 类负责创建 Meal 对象。\n\n## MealBuilder.java\n\npublic class MealBuilder {\npublic Meal prepareVegMeal (){\nMeal meal = new Meal();\n      meal.addItem(new VegBurger());\n      meal.addItem(new Coke());\n      return meal;\n   }\npublic Meal prepareNonVegMeal (){\nMeal meal = new Meal();\n      meal.addItem(new ChickenBurger());\n      meal.addItem(new Pepsi());\n      return meal;\n   }\n}\n\n### 步骤 7\n\nBuiderPatternDemo 使用 MealBuilder 来演示建造者模式（Builder Pattern）。\n\n## BuilderPatternDemo.java\n\npublic class BuilderPatternDemo {\npublic static void main(String[] args) {\nMealBuilder mealBuilder = new MealBuilder();\n\n      Meal vegMeal = mealBuilder.prepareVegMeal();\n      System.out.println("Veg Meal");\n      vegMeal.showItems();\n      System.out.println("Total Cost: " +vegMeal.getCost());\n\n      Meal nonVegMeal = mealBuilder.prepareNonVegMeal();\n      System.out.println("\\n\\nNon-Veg Meal");\n      nonVegMeal.showItems();\n      System.out.println("Total Cost: " +nonVegMeal.getCost());\n   }\n}\n\n### 步骤 8\n\n执行程序，输出结果：\n\n```text\n\nVeg Meal\nItem : Veg Burger, Packing : Wrapper, Price : 25.0\nItem : Coke, Packing : Bottle, Price : 30.0\nTotal Cost: 55.0\n\n\nNon-Veg Meal\nItem : Chicken Burger, Packing : Wrapper, Price : 50.5\nItem : Pepsi, Packing : Bottle, Price : 35.0\nTotal Cost: 85.5\n```\n\n## 相关文章\n\n- [设计模式之建造者(Builder)模式](https://www.runoob.com/w3cnote/builder-pattern.html)\n- [设计模式：Builder模式](https://www.runoob.com/w3cnote/builder-pattern-2.html)\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/builder-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-builder-pattern','建造者模式 - 设计模式教程','建造者模式是一种创建型设计模式，它允许你创建复杂对象的步骤与表示方式相分离。 建造者模式是一种创建型设计模式，它的主要目的是将一个复杂对象的构建过程与其表示相分离，从而可以创建具有不同表示形式的对象。 将一个复杂的构建过程与其表示相分离，使...',0,'PUBLISHED',3322,122,75,14,'2025-07-06 00:00:00','2025-07-06 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633006,1,'原型模式','原型模式（Prototype Pattern）是用于创建重复的对象，同时又能保证性能。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式之一。 这种模式是实现了一个原型接口，该接口用于创建当前对象的克隆。当直接创建对象的代价比较大时，则采用这种模式。例如，一个对象需要在一个高代价的数据库操作之后被创建。我们可以缓存该对象，在下一个请求时返回它的克隆，在需要的时候更新数据库，以此来减少数据库调用。 意图：使用原型实例指定要创建对象的种类，并通过拷贝这些原型创建新的对象。 主要解决：在运行时动态建立和删除原型。','# 原型模式\n\n原型模式（Prototype Pattern）是用于创建重复的对象，同时又能保证性能。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式之一。\n\n这种模式是实现了一个原型接口，该接口用于创建当前对象的克隆。当直接创建对象的代价比较大时，则采用这种模式。例如，一个对象需要在一个高代价的数据库操作之后被创建。我们可以缓存该对象，在下一个请求时返回它的克隆，在需要的时候更新数据库，以此来减少数据库调用。\n\n### 原型模式\n\n意图：使用原型实例指定要创建对象的种类，并通过拷贝这些原型创建新的对象。\n\n主要解决：在运行时动态建立和删除原型。\n\n### 何时使用\n\n- 系统应独立于产品的创建、构成和表示。\n- 需要在运行时指定实例化的类，例如通过动态加载。\n- 避免创建与产品类层次平行的工厂类层次。\n- 类的实例只能有几种不同状态组合，克隆原型比手工实例化更方便。\n\n### 如何解决\n\n通过已有的一个原型对象，快速生成与原型对象相同的实例。\n\n### 关键代码\n\n- 实现克隆操作：\n  - 在 Java 中，实现 `Cloneable` 接口，重写 `clone()` 方法。\n  - 在 .NET 中，使用 `Object` 类的 `MemberwiseClone()` 方法实现浅拷贝，或通过序列化实现深拷贝。\n- 隔离类对象的使用者和具体类型之间的耦合关系，要求"易变类"拥有稳定的接口。\n\n### 应用实例\n\n- 细胞分裂\n- Java 中的 `Object.clone()` 方法\n\n### 优点\n\n- 性能提高\n- 避免构造函数的约束\n\n### 缺点\n\n- 配备克隆方法需要全面考虑类的功能，对已有类可能较难实现，特别是处理不支持串行化的间接对象或含有循环结构的引用时。\n- 必须实现 `Cloneable` 接口。\n\n### 使用场景\n\n- 资源优化\n- 类初始化需要消耗大量资源（如数据、硬件资源）\n- 性能和安全要求高的场景\n- 通过 `new` 创建对象需要复杂的数据准备或访问权限时\n- 一个对象需要多个修改者\n- 对象需提供给其他对象访问并可能被各个调用者修改时\n- 通常与工厂方法模式一起使用，通过 `clone` 创建对象，然后由工厂方法提供给调用者\n\n### 注意事项\n\n与直接实例化类创建新对象不同，原型模式通过拷贝现有对象生成新对象。浅拷贝通过实现 `Cloneable` 实现，深拷贝通过实现 `Serializable` 读取二进制流实现。\n\n### 结构\n\n原型模式包含以下几个主要角色：\n\n- 原型接口（Prototype Interface）：定义一个用于克隆自身的接口，通常包括一个 `clone()` 方法。\n- 具体原型类（Concrete Prototype）：实现原型接口的具体类，负责实际的克隆操作。这个类需要实现 `clone()` 方法，通常使用浅拷贝或深拷贝来复制自身。\n- 客户端（Client）：使用原型实例来创建新的对象。客户端调用原型对象的 `clone()` 方法来创建新的对象，而不是直接使用构造函数。\n\n我们将创建一个抽象类 Shape 和扩展了 Shape 类的实体类。下一步是定义类 ShapeCache，该类把 shape 对象存储在一个 Hashtable 中，并在请求的时候返回它们的克隆。\n\nPrototypePatternDemo 类使用 ShapeCache 类来获取 Shape 对象。\n\n![原型模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201202-prototype-pattern-bd83c422e9.png)\n\n### 步骤 1\n\n创建一个实现了 Cloneable 接口的抽象类。\n\n## Shape.java\n\npublic abstract class Shape implements Cloneable {\nprivate String id;\n   protected String type;\n\n   abstract void draw();\n\n   public String getType(){\nreturn type;\n   }\npublic String getId() {\nreturn id;\n   }\npublic void setId(String id) {\nthis.id = id;\n   }\npublic Object clone() {\nObject clone = null;\n      try {\nclone = super.clone();\n      } catch (CloneNotSupportedException e) {\ne.printStackTrace();\n      }\nreturn clone;\n   }\n}\n\n### 步骤 2\n\n创建扩展了上面抽象类的实体类。\n\n## Rectangle.java\n\npublic class Rectangle extends Shape {\npublic Rectangle(){\ntype = "Rectangle";\n   }\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Rectangle::draw() method.");\n   }\n}\n\n## Square.java\n\npublic class Square extends Shape {\npublic Square(){\ntype = "Square";\n   }\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Square::draw() method.");\n   }\n}\n\n## Circle.java\n\npublic class Circle extends Shape {\npublic Circle(){\ntype = "Circle";\n   }\n\n   @Override\npublic void draw() {\nSystem.out.println("Inside Circle::draw() method.");\n   }\n}\n\n### 步骤 3\n\n创建一个类，从数据库获取实体类，并把它们存储在一个 Hashtable 中。\n\n## ShapeCache.java\n\nimport java.util.Hashtable;\n\npublic class ShapeCache {\nprivate static Hashtable<String, Shape> shapeMap\n      = new Hashtable<String, Shape>();\n\n   public static Shape getShape(String shapeId) {\nShape cachedShape = shapeMap.get(shapeId);\n      return (Shape) cachedShape.clone();\n   }\n// 对每种形状都运行数据库查询，并创建该形状\n// shapeMap.put(shapeKey, shape);\n// 例如，我们要添加三种形状\npublic static void loadCache() {\nCircle circle = new Circle();\n      circle.setId("1");\n      shapeMap.put(circle.getId(),circle);\n\n      Square square = new Square();\n      square.setId("2");\n      shapeMap.put(square.getId(),square);\n\n      Rectangle rectangle = new Rectangle();\n      rectangle.setId("3");\n      shapeMap.put(rectangle.getId(),rectangle);\n   }\n}\n\n### 步骤 4\n\nPrototypePatternDemo 使用 ShapeCache 类来获取存储在 Hashtable 中的形状的克隆。\n\n## PrototypePatternDemo.java\n\npublic class PrototypePatternDemo {\npublic static void main(String[] args) {\nShapeCache.loadCache();\n\n      Shape clonedShape = (Shape) ShapeCache.getShape("1");\n      System.out.println("Shape : " + clonedShape.getType());\n\n      Shape clonedShape2 = (Shape) ShapeCache.getShape("2");\n      System.out.println("Shape : " + clonedShape2.getType());\n\n      Shape clonedShape3 = (Shape) ShapeCache.getShape("3");\n      System.out.println("Shape : " + clonedShape3.getType());\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nShape : Circle\nShape : Square\nShape : Rectangle\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/prototype-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-prototype-pattern','原型模式 - 设计模式教程','原型模式（Prototype Pattern）是用于创建重复的对象，同时又能保证性能。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式之一。 这种模式是实现了一个原型接口，该接口用于创建当前对象的克隆。当直接创建对象的代价比...',0,'PUBLISHED',3459,129,80,15,'2025-07-07 00:00:00','2025-07-07 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633007,1,'适配器模式','适配器模式（Adapter Pattern）充当两个不兼容接口之间的桥梁，属于结构型设计模式。它通过一个中间件（适配器）将一个类的接口转换成客户期望的另一个接口，使原本不能一起工作的类能够协同工作。 这种模式涉及到一个单一的类，该类负责加入独立的或不兼容的接口功能。举个真实的例子，读卡器是作为内存卡和笔记本之间的适配器。您将内存卡插入读卡器，再将读卡器插入笔记本，这样就可以通过笔记本来读取内存卡。 假设有一个音频播放器，它只能播放 MP3 文件。现在，我们需要播放 VLC 和 MP4 文件，可以通过创建一个适配器来实现： 适配器模式是一种软件设计模式，旨在解决不同接口之间的兼容性问题。','# 适配器模式\n\n适配器模式（Adapter Pattern）充当两个不兼容接口之间的桥梁，属于结构型设计模式。它通过一个中间件（适配器）将一个类的接口转换成客户期望的另一个接口，使原本不能一起工作的类能够协同工作。\n\n这种模式涉及到一个单一的类，该类负责加入独立的或不兼容的接口功能。举个真实的例子，读卡器是作为内存卡和笔记本之间的适配器。您将内存卡插入读卡器，再将读卡器插入笔记本，这样就可以通过笔记本来读取内存卡。\n\n假设有一个音频播放器，它只能播放 MP3 文件。现在，我们需要播放 VLC 和 MP4 文件，可以通过创建一个适配器来实现：\n\n- 目标接口：定义一个可以播放多种格式文件的音频播放器接口。\n- 适配者类：现有的音频播放器，只能播放 MP3 文件。\n- 适配器类：创建一个新的类，实现目标接口，并在内部使用适配者类来播放 MP3 文件，同时添加对 VLC 和 MP4 文件的支持。\n\n适配器模式是一种软件设计模式，旨在解决不同接口之间的兼容性问题。\n\n目的：将一个类的接口转换为另一个接口，使得原本不兼容的类可以协同工作。\n\n主要解决的问题：在软件系统中，需要将现有的对象放入新环境，而新环境要求的接口与现有对象不匹配。\n\n### 使用场景\n\n- 需要使用现有类，但其接口不符合系统需求。\n- 希望创建一个可复用的类，与多个不相关的类（包括未来可能引入的类）一起工作，这些类可能没有统一的接口。\n- 通过接口转换，将一个类集成到另一个类系中。\n\n### 实现方式\n\n- 继承或依赖：推荐使用依赖关系，而不是继承，以保持灵活性。\n\n### 关键代码\n\n适配器通过继承或依赖现有对象，并实现所需的目标接口。\n\n### 应用实例\n\n- 电压适配器：将 110V 电压转换为 220V，以适配不同国家的电器标准。\n- 接口转换：例如，将 Java JDK 1.1 的 Enumeration 接口转换为 1.2 的 Iterator 接口。\n- 跨平台运行：在Linux上运行Windows程序。\n- 数据库连接：Java 中的 JDBC 通过适配器模式与不同类型的数据库进行交互。\n\n### 优点\n\n- 促进了类之间的协同工作，即使它们没有直接的关联。\n- 提高了类的复用性。\n- 增加了类的透明度。\n- 提供了良好的灵活性。\n\n### 缺点\n\n- 过度使用适配器可能导致系统结构混乱，难以理解和维护。\n- 在Java中，由于只能继承一个类，因此只能适配一个类，且目标类必须是抽象的。\n\n### 使用建议\n\n- 适配器模式应谨慎使用，特别是在详细设计阶段，它更多地用于解决现有系统的问题。\n- 在考虑修改一个正常运行的系统接口时，适配器模式是一个合适的选择。\n\n通过这种方式，适配器模式可以清晰地表达其核心概念和应用，同时避免了不必要的复杂性。\n\n### 结构\n\n适配器模式包含以下几个主要角色：\n\n- 目标接口（Target）：定义客户需要的接口。\n- 适配者类（Adaptee）：定义一个已经存在的接口，这个接口需要适配。\n- 适配器类（Adapter）：实现目标接口，并通过组合或继承的方式调用适配者类中的方法，从而实现目标接口。\n\n我们有一个 MediaPlayer 接口和一个实现了 MediaPlayer 接口的实体类 AudioPlayer。默认情况下，AudioPlayer 可以播放 mp3 格式的音频文件。\n\n我们还有另一个接口 AdvancedMediaPlayer 和实现了 AdvancedMediaPlayer 接口的实体类。该类可以播放 vlc 和 mp4 格式的文件。\n\n我们想要让 AudioPlayer 播放其他格式的音频文件。为了实现这个功能，我们需要创建一个实现了 MediaPlayer 接口的适配器类 MediaAdapter，并使用 AdvancedMediaPlayer 对象来播放所需的格式。\n\nAudioPlayer 使用适配器类 MediaAdapter 传递所需的音频类型，不需要知道能播放所需格式音频的实际类。AdapterPatternDemo 类使用 AudioPlayer 类来播放各种格式。\n\n![适配器模式的 UML 图](/api/uploads/files/runoob/design_pattern/20210223-adapter-99359fd5be.png)\n\n### 步骤 1\n\n为媒体播放器和更高级的媒体播放器创建接口。\n\n## MediaPlayer.java\n\npublic interface MediaPlayer {\npublic void play(String audioType, String fileName);\n}\n\n## AdvancedMediaPlayer.java\n\npublic interface AdvancedMediaPlayer {\npublic void playVlc(String fileName);\n   public void playMp4(String fileName);\n}\n\n### 步骤 2\n\n创建实现了 AdvancedMediaPlayer 接口的实体类。\n\n## VlcPlayer.java\n\npublic class VlcPlayer implements AdvancedMediaPlayer{\n   @Override\npublic void playVlc(String fileName) {\nSystem.out.println("Playing vlc file. Name: "+ fileName);\n   }\n\n   @Override\npublic void playMp4(String fileName) {\n//什么也不做\n}\n}\n\n## Mp4Player.java\n\npublic class Mp4Player implements AdvancedMediaPlayer{\n\n   @Override\npublic void playVlc(String fileName) {\n//什么也不做\n}\n\n   @Override\npublic void playMp4(String fileName) {\nSystem.out.println("Playing mp4 file. Name: "+ fileName);\n   }\n}\n\n### 步骤 3\n\n创建实现了 MediaPlayer 接口的适配器类。\n\n## MediaAdapter.java\n\npublic class MediaAdapter implements MediaPlayer {\nAdvancedMediaPlayer advancedMusicPlayer;\n\n   public MediaAdapter(String audioType){\nif(audioType.equalsIgnoreCase("vlc") ){\nadvancedMusicPlayer = new VlcPlayer();\n      } else if (audioType.equalsIgnoreCase("mp4")){\nadvancedMusicPlayer = new Mp4Player();\n      }\n}\n\n   @Override\npublic void play(String audioType, String fileName) {\nif(audioType.equalsIgnoreCase("vlc")){\nadvancedMusicPlayer.playVlc(fileName);\n      }else if(audioType.equalsIgnoreCase("mp4")){\nadvancedMusicPlayer.playMp4(fileName);\n      }\n}\n}\n\n### 步骤 4\n\n创建实现了 MediaPlayer 接口的实体类。\n\n## AudioPlayer.java\n\npublic class AudioPlayer implements MediaPlayer {\nMediaAdapter mediaAdapter;\n\n   @Override\npublic void play(String audioType, String fileName) {\n//播放 mp3 音乐文件的内置支持\nif(audioType.equalsIgnoreCase("mp3")){\nSystem.out.println("Playing mp3 file. Name: "+ fileName);\n      }\n//mediaAdapter 提供了播放其他文件格式的支持\nelse if(audioType.equalsIgnoreCase("vlc")\n         || audioType.equalsIgnoreCase("mp4")){\nmediaAdapter = new MediaAdapter(audioType);\n         mediaAdapter.play(audioType, fileName);\n      }\nelse{\nSystem.out.println("Invalid media. "+\n            audioType + " format not supported");\n      }\n}\n}\n\n### 步骤 5\n\n使用 AudioPlayer 来播放不同类型的音频格式。\n\n## AdapterPatternDemo.java\n\npublic class AdapterPatternDemo {\npublic static void main(String[] args) {\nAudioPlayer audioPlayer = new AudioPlayer();\n\n      audioPlayer.play("mp3", "beyond the horizon.mp3");\n      audioPlayer.play("mp4", "alone.mp4");\n      audioPlayer.play("vlc", "far far away.vlc");\n      audioPlayer.play("avi", "mind me.avi");\n   }\n}\n\n### 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nPlaying mp3 file. Name: beyond the horizon.mp3\nPlaying mp4 file. Name: alone.mp4\nPlaying vlc file. Name: far far away.vlc\nInvalid media. avi format not supported\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/adapter-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-adapter-pattern','适配器模式 - 设计模式教程','适配器模式（Adapter Pattern）充当两个不兼容接口之间的桥梁，属于结构型设计模式。它通过一个中间件（适配器）将一个类的接口转换成客户期望的另一个接口，使原本不能一起工作的类能够协同工作。 这种模式涉及到一个单一的类，该类负责加入...',0,'PUBLISHED',3596,136,85,16,'2025-07-08 00:00:00','2025-07-08 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633008,1,'桥接模式','桥接（Bridge）是用于把抽象化与实现化解耦，使得二者可以独立变化。这种类型的设计模式属于结构型模式，它通过提供抽象化和实现化之间的桥接结构，来实现二者的解耦。 这种模式涉及到一个作为桥接的接口，使得实体类的功能独立于接口实现类，这两种类型的类可被结构化改变而互不影响。 桥接模式的目的是将抽象与实现分离，使它们可以独立地变化，该模式通过将一个对象的抽象部分与它的实现部分分离，使它们可以独立地改变。它通过组合的方式，而不是继承的方式，将抽象和实现的部分连接起来。 我们通过下面的实例来演示桥接模式（Bridge Pattern）的用法。其中，可以使用相同的抽象类方法但是不同的桥接实现类，来画出不...','# 桥接模式\n\n桥接（Bridge）是用于把抽象化与实现化解耦，使得二者可以独立变化。这种类型的设计模式属于结构型模式，它通过提供抽象化和实现化之间的桥接结构，来实现二者的解耦。\n\n这种模式涉及到一个作为桥接的接口，使得实体类的功能独立于接口实现类，这两种类型的类可被结构化改变而互不影响。\n\n桥接模式的目的是将抽象与实现分离，使它们可以独立地变化，该模式通过将一个对象的抽象部分与它的实现部分分离，使它们可以独立地改变。它通过组合的方式，而不是继承的方式，将抽象和实现的部分连接起来。\n\n我们通过下面的实例来演示桥接模式（Bridge Pattern）的用法。其中，可以使用相同的抽象类方法但是不同的桥接实现类，来画出不同颜色的圆。\n\n### 意图\n\n用于将抽象部分与实现部分分离，使得它们可以独立地变化。。\n\n### 主要解决的问题\n\n避免使用继承导致的类爆炸问题，提供更灵活的扩展方式。\n\n### 使用场景\n\n当系统可能从多个角度进行分类，且每个角度都可能独立变化时，桥接模式是合适的。\n\n### 实现方式\n\n- 分离多角度分类：将不同角度的分类逻辑分离，允许它们独立变化。\n- 减少耦合：降低抽象与实现之间的耦合度。\n\n### 关键代码\n\n- 抽象类：定义一个抽象类，作为系统的一部分。\n- 实现类：定义一个或多个实现类，与抽象类通过聚合（而非继承）关联。\n\n### 应用实例\n\n- 转世投胎：灵魂（抽象）与肉体（实现）的分离，允许灵魂选择不同的肉体。\n- 墙上的开关：开关（抽象）与内部实现（实现）的分离，用户无需关心开关的内部工作机制。\n\n### 优点\n\n- 抽象与实现分离：提高了系统的灵活性和可维护性。\n- 扩展能力强：可以独立地扩展抽象和实现。\n- 实现细节透明：用户不需要了解实现细节。\n\n### 缺点\n\n- 理解与设计难度：桥接模式增加了系统的理解与设计难度。\n- 聚合关联：要求开发者在抽象层进行设计与编程。\n\n### 使用建议\n\n- 当系统需要在抽象化角色和具体化角色之间增加灵活性时，考虑使用桥接模式。\n- 对于不希望使用继承或因多层次继承导致类数量急剧增加的系统，桥接模式特别适用。\n- 当一个类存在两个独立变化的维度，且这两个维度都需要扩展时，使用桥接模式。\n\n### 注意事项\n\n- 桥接模式适用于两个独立变化的维度，确保它们可以独立地扩展和变化。\n\n### 结构\n\n以下是桥接模式的几个关键角色：\n\n- 抽象（Abstraction）：定义抽象接口，通常包含对实现接口的引用。\n- 扩展抽象（Refined Abstraction）：对抽象的扩展，可以是抽象类的子类或具体实现类。\n- 实现（Implementor）：定义实现接口，提供基本操作的接口。\n- 具体实现（Concrete Implementor）：实现实现接口的具体类。\n\n我们有一个作为桥接实现的 DrawAPI 接口和实现了 DrawAPI 接口的实体类 RedCircle、GreenCircle。Shape 是一个抽象类，将使用 DrawAPI 的对象。BridgePatternDemo 类使用 Shape 类来画出不同颜色的圆。\n\n![桥接模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201015-bridge-5431104c36.svg)\n\n### 步骤 1\n\n创建桥接实现接口。\n\n## DrawAPI.java\n\npublic interface DrawAPI {\npublic void drawCircle(int radius, int x, int y);\n}\n\n### 步骤 2\n\n创建实现了 DrawAPI 接口的实体桥接实现类。\n\n## RedCircle.java\n\npublic class RedCircle implements DrawAPI {\n   @Override\npublic void drawCircle(int radius, int x, int y) {\nSystem.out.println("Drawing Circle[ color: red, radius: "\n         + radius +", x: " +x+", "+ y +"]");\n   }\n}\n\n## GreenCircle.java\n\npublic class GreenCircle implements DrawAPI {\n   @Override\npublic void drawCircle(int radius, int x, int y) {\nSystem.out.println("Drawing Circle[ color: green, radius: "\n         + radius +", x: " +x+", "+ y +"]");\n   }\n}\n\n### 步骤 3\n\n使用 DrawAPI 接口创建抽象类 Shape。\n\n## Shape.java\n\npublic abstract class Shape {\nprotected DrawAPI drawAPI;\n   protected Shape(DrawAPI drawAPI){\nthis.drawAPI = drawAPI;\n   }\npublic abstract void draw();\n}\n\n### 步骤 4\n\n创建实现了 Shape 抽象类的实体类。\n\n## Circle.java\n\npublic class Circle extends Shape {\nprivate int x, y, radius;\n\n   public Circle(int x, int y, int radius, DrawAPI drawAPI) {\nsuper(drawAPI);\n      this.x = x;\n      this.y = y;\n      this.radius = radius;\n   }\npublic void draw() {\ndrawAPI.drawCircle(radius,x,y);\n   }\n}\n\n### 步骤 5\n\n使用 Shape 和 DrawAPI 类画出不同颜色的圆。\n\n## BridgePatternDemo.java\n\npublic class BridgePatternDemo {\npublic static void main(String[] args) {\nShape redCircle = new Circle(100,100, 10, new RedCircle());\n      Shape greenCircle = new Circle(100,100, 10, new GreenCircle());\n\n      redCircle.draw();\n      greenCircle.draw();\n   }\n}\n\n### 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nDrawing Circle[ color: red, radius: 10, x: 100, 100]\nDrawing Circle[  color: green, radius: 10, x: 100, 100]\n```\n\n## 相关文章推荐\n\n> [桥接模式](https://www.runoob.com/w3cnote/bridge-pattern2.html)\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/bridge-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-bridge-pattern','桥接模式 - 设计模式教程','桥接（Bridge）是用于把抽象化与实现化解耦，使得二者可以独立变化。这种类型的设计模式属于结构型模式，它通过提供抽象化和实现化之间的桥接结构，来实现二者的解耦。 这种模式涉及到一个作为桥接的接口，使得实体类的功能独立于接口实现类，这两种类...',0,'PUBLISHED',3733,143,90,17,'2025-07-09 00:00:00','2025-07-09 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633009,1,'过滤器模式','过滤器模式（Filter Pattern）或标准模式（Criteria Pattern）是一种设计模式，这种模式允许开发人员使用不同的标准来过滤一组对象，通过逻辑运算以解耦的方式把它们连接起来。这种类型的设计模式属于结构型模式，它结合多个标准来获得单一标准。 用于将对象的筛选过程封装起来，允许使用不同的筛选标准动态地筛选对象。 当需要根据多个不同的条件或标准来筛选一组对象时，过滤器模式提供了一种灵活的方式来定义这些条件，避免在客户端代码中硬编码筛选逻辑。 1. 图书管理系统：根据作者、出版年份、类别等不同标准筛选图书。','# 过滤器模式\n\n过滤器模式（Filter Pattern）或标准模式（Criteria Pattern）是一种设计模式，这种模式允许开发人员使用不同的标准来过滤一组对象，通过逻辑运算以解耦的方式把它们连接起来。这种类型的设计模式属于结构型模式，它结合多个标准来获得单一标准。\n## 概要\n\n### 意图\n\n用于将对象的筛选过程封装起来，允许使用不同的筛选标准动态地筛选对象。\n\n### 主要解决的问题\n\n当需要根据多个不同的条件或标准来筛选一组对象时，过滤器模式提供了一种灵活的方式来定义这些条件，避免在客户端代码中硬编码筛选逻辑。\n\n### 使用场景\n\n- 当对象集合需要根据不同的标准进行筛选时。\n- 当筛选逻辑可能变化，或者需要动态地组合多个筛选条件时。\n\n### 实现方式\n\n- 定义筛选接口：创建一个筛选接口，定义一个筛选方法。\n- 实现具体筛选器：为每个筛选标准实现筛选接口，封装具体的筛选逻辑。\n- 组合筛选器：允许筛选器之间进行组合，形成复杂的筛选逻辑。\n\n### 关键代码\n\n- 筛选接口：定义筛选方法，如 `matches()`。\n- 具体筛选器类：实现筛选接口，封装具体的筛选逻辑。\n- 组合筛选器：实现筛选器的组合逻辑，如逻辑与（AND）、逻辑或（OR）等。\n\n### 应用实例\n\n1. 图书管理系统：根据作者、出版年份、类别等不同标准筛选图书。\n2. 在线购物平台：根据价格、品牌、用户评分等条件筛选商品。\n\n### 优点\n\n1. 封装性：筛选逻辑被封装在独立的筛选器对象中。\n2. 灵活性：可以动态地添加、修改或组合筛选条件。\n3. 可扩展性：容易添加新的筛选标准，无需修改现有代码。\n\n### 缺点\n\n- 复杂性：随着筛选条件的增加，系统可能变得复杂。\n- 性能问题：如果筛选器组合过于复杂，可能会影响性能。\n\n### 使用建议\n\n- 当筛选逻辑可能变化或需要根据不同标准动态筛选对象时，考虑使用过滤器模式。\n- 在设计时，确保筛选器的接口和实现保持一致，以便于组合和扩展。\n\n### 注意事项\n\n- 确保筛选器的组合逻辑正确无误，避免引入逻辑错误。\n- 在实现时，考虑性能影响，特别是在处理大量数据时。\n\n### 概要\n\n过滤器模式包含以下几个主要角色：\n\n- 过滤器接口（Filter/Criteria）：定义一个接口，用于筛选对象。该接口通常包含一个方法，用于根据特定条件过滤对象。\n- 具体过滤器类（Concrete Filter/Concrete Criteria）：实现过滤器接口，具体定义筛选对象的条件和逻辑。\n- 对象集合（Items/Objects to be filtered）：要被过滤的对象集合。这些对象通常是具有共同属性的实例，例如一组人、一组产品等。\n- 客户端（Client）：使用具体过滤器类来筛选对象集合。客户端将对象集合和过滤器结合起来，以获得符合条件的对象。\n\n我们将创建一个 Person 对象、Criteria 接口和实现了该接口的实体类，来过滤 Person 对象的列表。CriteriaPatternDemo 类使用 Criteria 对象，基于各种标准和它们的结合来过滤 Person 对象的列表。\n\n![过滤器模式的 UML 图](/api/uploads/files/runoob/design_pattern/20230510-filter-9d56ddb03b.svg)\n\n### 步骤 1\n\n创建一个类，在该类上应用标准。\n\n## Person.java\n\npublic class Person {\nprivate String name;\n   private String gender;\n   private String maritalStatus;\n\n   public Person(String name,String gender,String maritalStatus){\nthis.name = name;\n      this.gender = gender;\n      this.maritalStatus = maritalStatus;\n   }\npublic String getName() {\nreturn name;\n   }\npublic String getGender() {\nreturn gender;\n   }\npublic String getMaritalStatus() {\nreturn maritalStatus;\n   }\n}\n\n### 步骤 2\n\n为标准（Criteria）创建一个接口。\n\n## Criteria.java\n\nimport java.util.List;\n\npublic interface Criteria {\npublic List<Person> meetCriteria(List<Person> persons);\n}\n\n### 步骤 3\n\n创建实现了 Criteria 接口的实体类。\n\n## CriteriaMale.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class CriteriaMale implements Criteria {\n\n   @Override\npublic List<Person> meetCriteria(List<Person> persons) {\nList<Person> malePersons = new ArrayList<Person>();\n      for (Person person : persons) {\nif(person.getGender().equalsIgnoreCase("MALE")){\nmalePersons.add(person);\n         }\n}\nreturn malePersons;\n   }\n}\n\n## CriteriaFemale.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class CriteriaFemale implements Criteria {\n\n   @Override\npublic List<Person> meetCriteria(List<Person> persons) {\nList<Person> femalePersons = new ArrayList<Person>();\n      for (Person person : persons) {\nif(person.getGender().equalsIgnoreCase("FEMALE")){\nfemalePersons.add(person);\n         }\n}\nreturn femalePersons;\n   }\n}\n\n## CriteriaSingle.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class CriteriaSingle implements Criteria {\n\n   @Override\npublic List<Person> meetCriteria(List<Person> persons) {\nList<Person> singlePersons = new ArrayList<Person>();\n      for (Person person : persons) {\nif(person.getMaritalStatus().equalsIgnoreCase("SINGLE")){\nsinglePersons.add(person);\n         }\n}\nreturn singlePersons;\n   }\n}\n\n## AndCriteria.java\n\nimport java.util.List;\n\npublic class AndCriteria implements Criteria {\nprivate Criteria criteria;\n   private Criteria otherCriteria;\n\n   public AndCriteria(Criteria criteria, Criteria otherCriteria) {\nthis.criteria = criteria;\n      this.otherCriteria = otherCriteria;\n   }\n\n   @Override\npublic List<Person> meetCriteria(List<Person> persons) {\nList<Person> firstCriteriaPersons = criteria.meetCriteria(persons);\n      return otherCriteria.meetCriteria(firstCriteriaPersons);\n   }\n}\n\n## OrCriteria.java\n\nimport java.util.List;\n\npublic class OrCriteria implements Criteria {\nprivate Criteria criteria;\n   private Criteria otherCriteria;\n\n   public OrCriteria(Criteria criteria, Criteria otherCriteria) {\nthis.criteria = criteria;\n      this.otherCriteria = otherCriteria;\n   }\n\n   @Override\npublic List<Person> meetCriteria(List<Person> persons) {\nList<Person> firstCriteriaItems = criteria.meetCriteria(persons);\n      List<Person> otherCriteriaItems = otherCriteria.meetCriteria(persons);\n\n      for (Person person : otherCriteriaItems) {\nif(!firstCriteriaItems.contains(person)){\nfirstCriteriaItems.add(person);\n         }\n}\nreturn firstCriteriaItems;\n   }\n}\n\n### 步骤4\n\n使用不同的标准（Criteria）和它们的结合来过滤 Person 对象的列表。\n\n## CriteriaPatternDemo.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class CriteriaPatternDemo {\npublic static void main(String[] args) {\nList<Person> persons = new ArrayList<Person>();\n\n      persons.add(new Person("Robert","Male", "Single"));\n      persons.add(new Person("John","Male", "Married"));\n      persons.add(new Person("Laura","Female", "Married"));\n      persons.add(new Person("Diana","Female", "Single"));\n      persons.add(new Person("Mike","Male", "Single"));\n      persons.add(new Person("Bobby","Male", "Single"));\n\n      Criteria male = new CriteriaMale();\n      Criteria female = new CriteriaFemale();\n      Criteria single = new CriteriaSingle();\n      Criteria singleMale = new AndCriteria(single, male);\n      Criteria singleOrFemale = new OrCriteria(single, female);\n\n      System.out.println("Males: ");\n      printPersons(male.meetCriteria(persons));\n\n      System.out.println("\\nFemales: ");\n      printPersons(female.meetCriteria(persons));\n\n      System.out.println("\\nSingle Males: ");\n      printPersons(singleMale.meetCriteria(persons));\n\n      System.out.println("\\nSingle Or Females: ");\n      printPersons(singleOrFemale.meetCriteria(persons));\n   }\npublic static void printPersons(List<Person> persons){\nfor (Person person : persons) {\nSystem.out.println("Person : [ Name : " + person.getName()\n            +", Gender : " + person.getGender()\n            +", Marital Status : " + person.getMaritalStatus()\n            +" ]");\n      }\n}\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nMales: \nPerson : [ Name : Robert, Gender : Male, Marital Status : Single ]\nPerson : [ Name : John, Gender : Male, Marital Status : Married ]\nPerson : [ Name : Mike, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Bobby, Gender : Male, Marital Status : Single ]\n\nFemales: \nPerson : [ Name : Laura, Gender : Female, Marital Status : Married ]\nPerson : [ Name : Diana, Gender : Female, Marital Status : Single ]\n\nSingle Males: \nPerson : [ Name : Robert, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Mike, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Bobby, Gender : Male, Marital Status : Single ]\n\nSingle Or Females: \nPerson : [ Name : Robert, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Diana, Gender : Female, Marital Status : Single ]\nPerson : [ Name : Mike, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Bobby, Gender : Male, Marital Status : Single ]\nPerson : [ Name : Laura, Gender : Female, Marital Status : Married ]\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/filter-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-filter-pattern','过滤器模式 - 设计模式教程','过滤器模式（Filter Pattern）或标准模式（Criteria Pattern）是一种设计模式，这种模式允许开发人员使用不同的标准来过滤一组对象，通过逻辑运算以解耦的方式把它们连接起来。这种类型的设计模式属于结构型模式，它结合多个标...',0,'PUBLISHED',3870,150,95,18,'2025-07-10 00:00:00','2025-07-10 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633010,1,'组合模式','组合模式（Composite Pattern），又叫部分整体模式，是用于把一组相似的对象当作一个单一的对象。组合模式依据树形结构来组合对象，用来表示部分以及整体层次。这种类型的设计模式属于结构型模式，它创建了对象组的树形结构。 这种模式创建了一个包含自己对象组的类。该类提供了修改相同对象组的方式。 我们通过下面的实例来演示组合模式的用法。实例演示了一个组织中员工的层次结构。 将对象组合成树形结构以表示"部分-整体"的层次结构。组合模式使得用户对单个对象和组合对象的使用具有一致性。','# 组合模式\n\n组合模式（Composite Pattern），又叫部分整体模式，是用于把一组相似的对象当作一个单一的对象。组合模式依据树形结构来组合对象，用来表示部分以及整体层次。这种类型的设计模式属于结构型模式，它创建了对象组的树形结构。\n\n这种模式创建了一个包含自己对象组的类。该类提供了修改相同对象组的方式。\n\n我们通过下面的实例来演示组合模式的用法。实例演示了一个组织中员工的层次结构。\n\n### 意图\n\n将对象组合成树形结构以表示"部分-整体"的层次结构。组合模式使得用户对单个对象和组合对象的使用具有一致性。\n\n### 主要解决的问题\n\n- 简化树形结构中对象的处理，无论它们是单个对象还是组合对象。\n- 解耦客户端代码与复杂元素的内部结构，使得客户端可以统一处理所有类型的节点。\n\n### 使用场景\n\n- 当需要表示对象的层次结构时，如文件系统或组织结构。\n- 当希望客户端代码能够以一致的方式处理树形结构中的所有对象时。\n\n### 实现方式\n\n- 统一接口：定义一个接口，所有对象（树枝和叶子）都实现这个接口。\n- 组合结构：树枝对象包含一个接口的引用列表，这些引用可以是叶子或树枝。\n\n### 关键代码\n\n- Component接口：定义了所有对象必须实现的操作。\n- Leaf类：实现Component接口，代表树中的叶子节点。\n- Composite类：也实现Component接口，并包含其他Component对象的集合。\n\n### 应用实例\n\n1. 算术表达式：构建一个由操作数、操作符和子表达式组成的树形结构。\n2. GUI组件：在Java的AWT和Swing库中，容器（如Panel）可以包含其他组件（如按钮和复选框）。\n\n### 优点\n\n1. 简化客户端代码：客户端可以统一处理所有类型的节点。\n2. 易于扩展：可以轻松添加新的叶子类型或树枝类型。\n\n### 缺点\n\n- 违反依赖倒置原则：组件的声明是基于具体类而不是接口，这可能导致代码的灵活性降低。\n\n### 使用建议\n\n- 在设计时，优先使用接口而非具体类，以提高系统的灵活性和可维护性。\n- 适用于需要处理复杂树形结构的场景，如文件系统、组织结构等。\n\n### 注意事项\n\n- 在实现时，确保所有组件都遵循统一的接口，以保持一致性。\n- 考虑使用工厂模式来创建不同类型的组件，以进一步解耦组件的创建逻辑。\n\n### 结构\n\n组合模式的核心角色包括：\n\n- 组件（Component）:\n  - 定义了组合中所有对象的通用接口，可以是抽象类或接口。它声明了用于访问和管理子组件的方法，包括添加、删除、获取子组件等。\n- 叶子节点（Leaf）:\n  - 表示组合中的叶子节点对象，叶子节点没有子节点。它实现了组件接口的方法，但通常不包含子组件。\n- 复合节点（Composite）:\n  - 表示组合中的复合对象，复合节点可以包含子节点，可以是叶子节点，也可以是其他复合节点。它实现了组件接口的方法，包括管理子组件的方法。\n- 客户端（Client）:\n  - 通过组件接口与组合结构进行交互，客户端不需要区分叶子节点和复合节点，可以一致地对待整体和部分。\n\n我们有一个类 Employee，该类被当作组合模型类。CompositePatternDemo 类使用 Employee 类来添加部门层次结构，并打印所有员工。\n\n![组合模式的 UML 图](/api/uploads/files/runoob/design_pattern/20210817-composite-composite-e6b9ac1e13.svg)\n\n### 步骤 1\n\n创建 Employee 类，该类带有 Employee 对象的列表。\n\n## Employee.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Employee {\nprivate String name;\n   private String dept;\n   private int salary;\n   private List<Employee> subordinates;\n\n   //构造函数\npublic Employee(String name,String dept, int sal) {\nthis.name = name;\n      this.dept = dept;\n      this.salary = sal;\n      subordinates = new ArrayList<Employee>();\n   }\npublic void add(Employee e) {\nsubordinates.add(e);\n   }\npublic void remove(Employee e) {\nsubordinates.remove(e);\n   }\npublic List<Employee> getSubordinates(){\nreturn subordinates;\n   }\npublic String toString(){\nreturn ("Employee :[ Name : "+ name\n      +", dept : "+ dept + ", salary :"\n      + salary+" ]");\n   }\n}\n\n### 步骤 2\n\n使用 Employee 类来创建和打印员工的层次结构。\n\n## CompositePatternDemo.java\n\npublic class CompositePatternDemo {\npublic static void main(String[] args) {\nEmployee CEO = new Employee("John","CEO", 30000);\n\n      Employee headSales = new Employee("Robert","Head Sales", 20000);\n\n      Employee headMarketing = new Employee("Michel","Head Marketing", 20000);\n\n      Employee clerk1 = new Employee("Laura","Marketing", 10000);\n      Employee clerk2 = new Employee("Bob","Marketing", 10000);\n\n      Employee salesExecutive1 = new Employee("Richard","Sales", 10000);\n      Employee salesExecutive2 = new Employee("Rob","Sales", 10000);\n\n      CEO.add(headSales);\n      CEO.add(headMarketing);\n\n      headSales.add(salesExecutive1);\n      headSales.add(salesExecutive2);\n\n      headMarketing.add(clerk1);\n      headMarketing.add(clerk2);\n\n      //打印该组织的所有员工\nSystem.out.println(CEO);\n      for (Employee headEmployee : CEO.getSubordinates()) {\nSystem.out.println(headEmployee);\n         for (Employee employee : headEmployee.getSubordinates()) {\nSystem.out.println(employee);\n         }\n}\n}\n}\n\n### 步骤 3\n\n执行程序，输出结果为：\n\n```text\n\nEmployee :[ Name : John, dept : CEO, salary :30000 ]\nEmployee :[ Name : Robert, dept : Head Sales, salary :20000 ]\nEmployee :[ Name : Richard, dept : Sales, salary :10000 ]\nEmployee :[ Name : Rob, dept : Sales, salary :10000 ]\nEmployee :[ Name : Michel, dept : Head Marketing, salary :20000 ]\nEmployee :[ Name : Laura, dept : Marketing, salary :10000 ]\nEmployee :[ Name : Bob, dept : Marketing, salary :10000 ]\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/composite-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-composite-pattern','组合模式 - 设计模式教程','组合模式（Composite Pattern），又叫部分整体模式，是用于把一组相似的对象当作一个单一的对象。组合模式依据树形结构来组合对象，用来表示部分以及整体层次。这种类型的设计模式属于结构型模式，它创建了对象组的树形结构。 这种模式创建...',0,'PUBLISHED',4007,157,100,19,'2025-07-11 00:00:00','2025-07-11 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633011,1,'装饰器模式','装饰器模式（Decorator Pattern）允许向一个现有的对象添加新的功能，同时又不改变其结构。这种类型的设计模式属于结构型模式，它是作为现有的类的一个包装。 装饰器模式通过将对象包装在装饰器类中，以便动态地修改其行为。 这种模式创建了一个装饰类，用来包装原有的类，并在保持类方法签名完整性的前提下，提供了额外的功能。 我们通过下面的实例来演示装饰器模式的用法。其中，我们将把一个形状装饰上不同的颜色，同时又不改变形状类。','# 装饰器模式\n\n装饰器模式（Decorator Pattern）允许向一个现有的对象添加新的功能，同时又不改变其结构。这种类型的设计模式属于结构型模式，它是作为现有的类的一个包装。\n\n装饰器模式通过将对象包装在装饰器类中，以便动态地修改其行为。\n\n这种模式创建了一个装饰类，用来包装原有的类，并在保持类方法签名完整性的前提下，提供了额外的功能。\n\n我们通过下面的实例来演示装饰器模式的用法。其中，我们将把一个形状装饰上不同的颜色，同时又不改变形状类。\n\n### 意图\n\n动态地给一个对象添加额外的职责，同时不改变其结构。装饰器模式提供了一种灵活的替代继承方式来扩展功能。\n\n### 主要解决的问题\n\n- 避免通过继承引入静态特征，特别是在子类数量急剧膨胀的情况下。\n- 允许在运行时动态地添加或修改对象的功能。\n\n### 使用场景\n\n- 当需要在不增加大量子类的情况下扩展类的功能。\n- 当需要动态地添加或撤销对象的功能。\n\n### 实现方式\n\n- 定义组件接口：创建一个接口，规定可以动态添加职责的对象的标准。\n- 创建具体组件：实现该接口的具体类，提供基本功能。\n- 创建抽象装饰者：实现同样的接口，持有一个组件接口的引用，可以在任何时候动态地添加功能。\n- 创建具体装饰者：扩展抽象装饰者，添加额外的职责。\n\n### 关键代码\n\n- Component接口：定义了可以被装饰的对象的标准。\n- ConcreteComponent类：实现Component接口的具体类。\n- Decorator抽象类：实现Component接口，并包含一个Component接口的引用。\n- ConcreteDecorator类：扩展Decorator类，添加额外的功能。\n\n### 应用实例\n\n1. 孙悟空的72变：孙悟空（ConcreteComponent）通过变化（Decorator）获得新的能力。\n2. 画框装饰画：一幅画（ConcreteComponent）可以通过添加玻璃（ConcreteDecorator）和画框（ConcreteDecorator）来增强其展示效果。\n\n### 优点\n\n- 低耦合：装饰类和被装饰类可以独立变化，互不影响。\n- 灵活性：可以动态地添加或撤销功能。\n- 替代继承：提供了一种继承之外的扩展对象功能的方式。\n\n### 缺点\n\n- 复杂性：多层装饰可能导致系统复杂性增加。\n\n### 使用建议\n\n- 在需要动态扩展功能时，考虑使用装饰器模式。\n- 保持装饰者和具体组件的接口一致，以确保灵活性。\n\n### 注意事项\n\n- 装饰器模式可以替代继承，但应谨慎使用，避免过度装饰导致系统复杂。\n\n### 结构\n\n装饰器模式包含以下几个核心角色：\n\n- 抽象组件（Component）：定义了原始对象和装饰器对象的公共接口或抽象类，可以是具体组件类的父类或接口。\n- 具体组件（Concrete Component）：是被装饰的原始对象，它定义了需要添加新功能的对象。\n- 抽象装饰器（Decorator）：继承自抽象组件，它包含了一个抽象组件对象，并定义了与抽象组件相同的接口，同时可以通过组合方式持有其他装饰器对象。\n- 具体装饰器（Concrete Decorator）：实现了抽象装饰器的接口，负责向抽象组件添加新的功能。具体装饰器通常会在调用原始对象的方法之前或之后执行自己的操作。\n\n装饰器模式通过嵌套包装多个装饰器对象，可以实现多层次的功能增强。每个具体装饰器类都可以选择性地增加新的功能，同时保持对象接口的一致性。\n\n我们将创建一个 Shape 接口和实现了 Shape 接口的实体类。然后我们创建一个实现了 Shape 接口的抽象装饰类 ShapeDecorator，并把 Shape 对象作为它的实例变量。\n\nRedShapeDecorator 是实现了 ShapeDecorator 的实体类。\nDecoratorPatternDemo 类使用 RedShapeDecorator 来装饰 Shape 对象。\n\n![图片](/api/uploads/files/runoob/design_pattern/20210420-decorator-1-decorator-decorator-decorator.drawio-2-7a73269a3c.png)\n\n\n<img decoding="async" src="https://www.runoob.com/wp-content/uploads/2014/08/20210420-decorator-1-decorator-decorator.svg" alt="装饰器模式的 UML 图" />\n\n### 步骤 1\n\n创建一个接口：\n\n## Shape.java\n\npublic interface Shape {\nvoid draw();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## Rectangle.java\n\npublic class Rectangle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Shape: Rectangle");\n   }\n}\n\n## Circle.java\n\npublic class Circle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Shape: Circle");\n   }\n}\n\n### 步骤 3\n\n创建实现了 Shape 接口的抽象装饰类。\n\n## ShapeDecorator.java\n\npublic abstract class ShapeDecorator implements Shape {\nprotected Shape decoratedShape;\n\n   public ShapeDecorator(Shape decoratedShape){\nthis.decoratedShape = decoratedShape;\n   }\npublic void draw(){\ndecoratedShape.draw();\n   }\n}\n\n### 步骤 4\n\n创建扩展了 ShapeDecorator 类的实体装饰类。\n\n## RedShapeDecorator.java\n\npublic class RedShapeDecorator extends ShapeDecorator {\npublic RedShapeDecorator(Shape decoratedShape) {\nsuper(decoratedShape);\n   }\n\n   @Override\npublic void draw() {\ndecoratedShape.draw();\n      setRedBorder(decoratedShape);\n   }\nprivate void setRedBorder(Shape decoratedShape){\nSystem.out.println("Border Color: Red");\n   }\n}\n\n### 步骤 5\n\n使用 RedShapeDecorator 来装饰 Shape 对象。\n\n## DecoratorPatternDemo.java\n\npublic class DecoratorPatternDemo {\npublic static void main(String[] args) {\nShape circle = new Circle();\n      ShapeDecorator redCircle = new RedShapeDecorator(new Circle());\n      ShapeDecorator redRectangle = new RedShapeDecorator(new Rectangle());\n      //Shape redCircle = new RedShapeDecorator(new Circle());\n//Shape redRectangle = new RedShapeDecorator(new Rectangle());\nSystem.out.println("Circle with normal border");\n      circle.draw();\n\n      System.out.println("\\nCircle of red border");\n      redCircle.draw();\n\n      System.out.println("\\nRectangle of red border");\n      redRectangle.draw();\n   }\n}\n\n### 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nCircle with normal border\nShape: Circle\n\nCircle of red border\nShape: Circle\nBorder Color: Red\n\nRectangle of red border\nShape: Rectangle\nBorder Color: Red\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/decorator-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-decorator-pattern','装饰器模式 - 设计模式教程','装饰器模式（Decorator Pattern）允许向一个现有的对象添加新的功能，同时又不改变其结构。这种类型的设计模式属于结构型模式，它是作为现有的类的一个包装。 装饰器模式通过将对象包装在装饰器类中，以便动态地修改其行为。 这种模式创建...',0,'PUBLISHED',4144,164,105,20,'2025-07-12 00:00:00','2025-07-12 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633012,1,'外观模式','外观模式（Facade Pattern）隐藏系统的复杂性，并向客户端提供了一个客户端可以访问系统的接口。这种类型的设计模式属于结构型模式，它向现有的系统添加一个接口，来隐藏系统的复杂性。 这种模式涉及到一个单一的类，该类提供了客户端请求的简化方法和对现有系统类方法的委托调用。 为一个复杂的子系统提供一个一致的高层接口。这样，客户端代码就可以通过这个简化的接口与子系统交互，而不需要了解子系统内部的复杂性。 1. 医院接待：医院的接待人员简化了挂号、门诊、划价、取药等复杂流程。','# 外观模式\n\n外观模式（Facade Pattern）隐藏系统的复杂性，并向客户端提供了一个客户端可以访问系统的接口。这种类型的设计模式属于结构型模式，它向现有的系统添加一个接口，来隐藏系统的复杂性。\n\n这种模式涉及到一个单一的类，该类提供了客户端请求的简化方法和对现有系统类方法的委托调用。\n\n### 意图\n\n为一个复杂的子系统提供一个一致的高层接口。这样，客户端代码就可以通过这个简化的接口与子系统交互，而不需要了解子系统内部的复杂性。\n\n### 主要解决的问题\n\n- 降低客户端与复杂子系统之间的耦合度。\n- 简化客户端对复杂系统的操作，隐藏内部实现细节。\n\n### 使用场景\n\n- 当客户端不需要了解系统内部的复杂逻辑和组件交互时。\n- 当需要为整个系统定义一个清晰的入口点时。\n\n### 实现方式\n\n- 创建外观类：定义一个类（外观），作为客户端与子系统之间的中介。\n- 封装子系统操作：外观类将复杂的子系统操作封装成简单的方法。\n\n### 关键代码\n\n- Facade类：提供高层接口，简化客户端与子系统的交互。\n- 子系统类：实现具体的业务逻辑，被Facade类调用。\n\n### 应用实例\n\n1. 医院接待：医院的接待人员简化了挂号、门诊、划价、取药等复杂流程。\n2. Java三层架构：通过外观模式，可以简化对表示层、业务逻辑层和数据访问层的访问。\n\n### 优点\n\n1. 减少依赖：客户端与子系统之间的依赖减少。\n2. 提高灵活性：子系统的内部变化不会影响客户端。\n3. 增强安全性：隐藏了子系统的内部实现，只暴露必要的操作。\n\n### 缺点\n\n- 违反开闭原则：对子系统的修改可能需要对外观类进行相应的修改。\n\n### 使用建议\n\n- 在需要简化复杂系统访问时使用外观模式。\n- 确保外观类提供的方法足够简单，以便于客户端使用。\n\n### 注意事项\n\n- 外观模式适用于层次化结构，可以为每一层提供一个清晰的入口。\n- 避免过度使用外观模式，以免隐藏过多的细节，导致维护困难。\n\n### 结构\n\n外观模式涉及以下核心角色：\n\n- 外观（Facade）:\n  - 提供一个简化的接口，封装了系统的复杂性。外观模式的客户端通过与外观对象交互，而无需直接与系统的各个组件打交道。\n- 子系统（Subsystem）:\n  - 由多个相互关联的类组成，负责系统的具体功能。外观对象通过调用这些子系统来完成客户端的请求。\n- 客户端（Client）:\n  - 使用外观对象来与系统交互，而不需要了解系统内部的具体实现。\n\n我们将创建一个 Shape 接口和实现了 Shape 接口的实体类。下一步是定义一个外观类 ShapeMaker。\n\nShapeMaker 类使用实体类来代表用户对这些类的调用。FacadePatternDemo 类使用 ShapeMaker 类来显示结果。\n\n![外观模式的 UML 图](/api/uploads/files/runoob/design_pattern/20241015-facade-facade-a3b3706143.svg)\n\n### 步骤 1\n\n创建一个接口。\n\n## Shape.java\n\npublic interface Shape {\nvoid draw();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## Rectangle.java\n\npublic class Rectangle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Rectangle::draw()");\n   }\n}\n\n## Square.java\n\npublic class Square implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Square::draw()");\n   }\n}\n\n## Circle.java\n\npublic class Circle implements Shape {\n\n   @Override\npublic void draw() {\nSystem.out.println("Circle::draw()");\n   }\n}\n\n### 步骤 3\n\n创建一个外观类。\n\n## ShapeMaker.java\n\npublic class ShapeMaker {\nprivate Shape circle;\n   private Shape rectangle;\n   private Shape square;\n\n   public ShapeMaker() {\ncircle = new Circle();\n      rectangle = new Rectangle();\n      square = new Square();\n   }\npublic void drawCircle(){\ncircle.draw();\n   }\npublic void drawRectangle(){\nrectangle.draw();\n   }\npublic void drawSquare(){\nsquare.draw();\n   }\n}\n\n### 步骤 4\n\n使用该外观类画出各种类型的形状。\n\n## FacadePatternDemo.java\n\npublic class FacadePatternDemo {\npublic static void main(String[] args) {\nShapeMaker shapeMaker = new ShapeMaker();\n\n      shapeMaker.drawCircle();\n      shapeMaker.drawRectangle();\n      shapeMaker.drawSquare();\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nCircle::draw()\nRectangle::draw()\nSquare::draw()\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/facade-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-facade-pattern','外观模式 - 设计模式教程','外观模式（Facade Pattern）隐藏系统的复杂性，并向客户端提供了一个客户端可以访问系统的接口。这种类型的设计模式属于结构型模式，它向现有的系统添加一个接口，来隐藏系统的复杂性。 这种模式涉及到一个单一的类，该类提供了客户端请求的简...',0,'PUBLISHED',4281,171,110,21,'2025-07-13 00:00:00','2025-07-13 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633013,1,'享元模式','享元模式（Flyweight Pattern）主要用于减少创建对象的数量，以减少内存占用和提高性能。这种类型的设计模式属于结构型模式，它提供了减少对象数量从而改善应用所需的对象结构的方式。 享元模式尝试重用现有的同类对象，如果未找到匹配的对象，则创建新对象。我们将通过创建 5 个对象来画出 20 个分布于不同位置的圆来演示这种模式。由于只有 5 种可用的颜色，所以 color 属性被用来检查现有的 Circle 对象。 通过共享对象来减少创建大量相似对象时的内存消耗。。 1. Java中的String对象：字符串常量池中已经存在的字符串会被复用。','# 享元模式\n\n享元模式（Flyweight Pattern）主要用于减少创建对象的数量，以减少内存占用和提高性能。这种类型的设计模式属于结构型模式，它提供了减少对象数量从而改善应用所需的对象结构的方式。\n\n享元模式尝试重用现有的同类对象，如果未找到匹配的对象，则创建新对象。我们将通过创建 5 个对象来画出 20 个分布于不同位置的圆来演示这种模式。由于只有 5 种可用的颜色，所以 color 属性被用来检查现有的 Circle 对象。\n\n### 意图\n\n通过共享对象来减少创建大量相似对象时的内存消耗。。\n\n### 主要解决的问题\n\n- 避免因创建大量对象而导致的内存溢出问题。\n- 通过共享对象，提高内存使用效率。\n\n### 使用场景\n\n- 当系统中存在大量相似或相同的对象。\n- 对象的创建和销毁成本较高。\n- 对象的状态可以外部化，即对象的部分状态可以独立于对象本身存在。\n\n### 实现方式\n\n- 定义享元接口：创建一个享元接口，规定可以共享的状态。\n- 创建具体享元类：实现该接口的具体类，包含内部状态。\n- 使用享元工厂：创建一个工厂类，用于管理享元对象的创建和复用。\n\n### 关键代码\n\n- HashMap：使用哈希表存储已经创建的享元对象，以便快速检索。\n\n### 应用实例\n\n1. Java中的String对象：字符串常量池中已经存在的字符串会被复用。\n2. 数据库连接池：数据库连接被复用，避免频繁创建和销毁连接。\n\n### 优点\n\n- 减少内存消耗：通过共享对象，减少了内存中对象的数量。\n- 提高效率：减少了对象创建的时间，提高了系统效率。\n\n### 缺点\n\n- 增加系统复杂度：需要分离内部状态和外部状态，增加了设计和实现的复杂性。\n- 线程安全问题：如果外部状态处理不当，可能会引起线程安全问题。\n\n### 使用建议\n\n- 在创建大量相似对象时考虑使用享元模式。\n- 确保享元对象的内部状态是共享的，而外部状态是独立于对象的。\n\n### 注意事项\n\n- 状态分离：明确区分内部状态和外部状态，避免混淆。\n- 享元工厂：使用享元工厂来控制对象的创建和复用，确保对象的一致性和完整性。\n\n### 结构\n\n享元模式包含以下几个核心角色：\n\n- 享元工厂（Flyweight Factory）:\n  - 负责创建和管理享元对象，通常包含一个池（缓存）用于存储和复用已经创建的享元对象。\n- 具体享元（Concrete Flyweight）:\n  - 实现了抽象享元接口，包含了内部状态和外部状态。内部状态是可以被共享的，而外部状态则由客户端传递。\n- 抽象享元（Flyweight）:\n  - 定义了具体享元和非共享享元的接口，通常包含了设置外部状态的方法。\n- 客户端（Client）:\n  - 使用享元工厂获取享元对象，并通过设置外部状态来操作享元对象。客户端通常不需要关心享元对象的具体实现。\n\n我们将创建一个 Shape 接口和实现了 Shape 接口的实体类 Circle。下一步是定义工厂类 ShapeFactory。\n\nShapeFactory 有一个 Circle 的 HashMap，其中键名为 Circle 对象的颜色。无论何时接收到请求，都会创建一个特定颜色的圆。ShapeFactory 检查它的 HashMap 中的 circle 对象，如果找到 Circle 对象，则返回该对象，否则将创建一个存储在 hashmap 中以备后续使用的新对象，并把该对象返回到客户端。\n\nFlyWeightPatternDemo 类使用 ShapeFactory 来获取 Shape 对象。它将向 ShapeFactory 传递信息（red / green / blue/ black / white），以便获取它所需对象的颜色。\n\n![享元模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201015-fiyweight-69e52e176d.svg)\n\n### 步骤 1\n\n创建一个接口。\n\n## Shape.java\n\npublic interface Shape {\nvoid draw();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## Circle.java\n\npublic class Circle implements Shape {\nprivate String color;\n   private int x;\n   private int y;\n   private int radius;\n\n   public Circle(String color){\nthis.color = color;\n   }\npublic void setX(int x) {\nthis.x = x;\n   }\npublic void setY(int y) {\nthis.y = y;\n   }\npublic void setRadius(int radius) {\nthis.radius = radius;\n   }\n\n   @Override\npublic void draw() {\nSystem.out.println("Circle: Draw() [Color : " + color\n         +", x : " + x +", y :" + y +", radius :" + radius);\n   }\n}\n\n### 步骤 3\n\n创建一个工厂，生成基于给定信息的实体类的对象。\n\n## ShapeFactory.java\n\nimport java.util.HashMap;\n\npublic class ShapeFactory {\nprivate static final HashMap<String, Shape> circleMap = new HashMap<>();\n\n   public static Shape getCircle(String color) {\nCircle circle = (Circle)circleMap.get(color);\n\n      if(circle == null) {\ncircle = new Circle(color);\n         circleMap.put(color, circle);\n         System.out.println("Creating circle of color : " + color);\n      }\nreturn circle;\n   }\n}\n\n### 步骤 4\n\n使用该工厂，通过传递颜色信息来获取实体类的对象。\n\n## FlyweightPatternDemo.java\n\npublic class FlyweightPatternDemo {\nprivate static final String colors[] =\n      { "Red", "Green", "Blue", "White", "Black" };\n   public static void main(String[] args) {\nfor(int i=0; i < 20; ++i) {\nCircle circle =\n            (Circle)ShapeFactory.getCircle(getRandomColor());\n         circle.setX(getRandomX());\n         circle.setY(getRandomY());\n         circle.setRadius(100);\n         circle.draw();\n      }\n}\nprivate static String getRandomColor() {\nreturn colors[(int)(Math.random()*colors.length)];\n   }\nprivate static int getRandomX() {\nreturn (int)(Math.random()*100 );\n   }\nprivate static int getRandomY() {\nreturn (int)(Math.random()*100);\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nCreating circle of color : Black\nCircle: Draw() [Color : Black, x : 36, y :71, radius :100\nCreating circle of color : Green\nCircle: Draw() [Color : Green, x : 27, y :27, radius :100\nCreating circle of color : White\nCircle: Draw() [Color : White, x : 64, y :10, radius :100\nCreating circle of color : Red\nCircle: Draw() [Color : Red, x : 15, y :44, radius :100\nCircle: Draw() [Color : Green, x : 19, y :10, radius :100\nCircle: Draw() [Color : Green, x : 94, y :32, radius :100\nCircle: Draw() [Color : White, x : 69, y :98, radius :100\nCreating circle of color : Blue\nCircle: Draw() [Color : Blue, x : 13, y :4, radius :100\nCircle: Draw() [Color : Green, x : 21, y :21, radius :100\nCircle: Draw() [Color : Blue, x : 55, y :86, radius :100\nCircle: Draw() [Color : White, x : 90, y :70, radius :100\nCircle: Draw() [Color : Green, x : 78, y :3, radius :100\nCircle: Draw() [Color : Green, x : 64, y :89, radius :100\nCircle: Draw() [Color : Blue, x : 3, y :91, radius :100\nCircle: Draw() [Color : Blue, x : 62, y :82, radius :100\nCircle: Draw() [Color : Green, x : 97, y :61, radius :100\nCircle: Draw() [Color : Green, x : 86, y :12, radius :100\nCircle: Draw() [Color : Green, x : 38, y :93, radius :100\nCircle: Draw() [Color : Red, x : 76, y :82, radius :100\nCircle: Draw() [Color : Blue, x : 95, y :82, radius :100\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/flyweight-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-flyweight-pattern','享元模式 - 设计模式教程','享元模式（Flyweight Pattern）主要用于减少创建对象的数量，以减少内存占用和提高性能。这种类型的设计模式属于结构型模式，它提供了减少对象数量从而改善应用所需的对象结构的方式。 享元模式尝试重用现有的同类对象，如果未找到匹配的对...',0,'PUBLISHED',4418,178,115,22,'2025-07-14 00:00:00','2025-07-14 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633014,1,'代理模式','在代理模式（Proxy Pattern）中，一个类代表另一个类的功能，这种类型的设计模式属于结构型模式。 代理模式通过引入一个代理对象来控制对原对象的访问。代理对象在客户端和目标对象之间充当中介，负责将客户端的请求转发给目标对象，同时可以在转发请求前后进行额外的处理。 在代理模式中，我们创建具有现有对象的对象，以便向外界提供功能接口。 为其他对象提供一种代理以控制对这个对象的访问。','# 代理模式\n\n在代理模式（Proxy Pattern）中，一个类代表另一个类的功能，这种类型的设计模式属于结构型模式。\n\n代理模式通过引入一个代理对象来控制对原对象的访问。代理对象在客户端和目标对象之间充当中介，负责将客户端的请求转发给目标对象，同时可以在转发请求前后进行额外的处理。\n\n在代理模式中，我们创建具有现有对象的对象，以便向外界提供功能接口。\n\n### 意图\n\n为其他对象提供一种代理以控制对这个对象的访问。\n\n### 主要解决的问题\n\n- 代理模式解决的是在直接访问某些对象时可能遇到的问题，例如对象创建成本高、需要安全控制或远程访问等。\n\n### 使用场景\n\n- 当需要在访问一个对象时进行一些控制或额外处理时。\n\n### 实现方式\n\n- 增加中间层：创建一个代理类，作为真实对象的中间层。\n- 代理与真实对象组合：代理类持有真实对象的引用，并在访问时进行控制。\n\n### 关键代码\n\n- 代理类：实现与真实对象相同的接口，并添加额外的控制逻辑。\n- 真实对象：实际执行任务的对象。\n\n### 应用实例\n\n- 快捷方式：Windows系统中的快捷方式作为文件或程序的代理。\n- 角色扮演：孙悟空作为高翠兰的代理，猪八戒无法区分。\n- 代售点：购买火车票时，代售点作为火车站的代理。\n- 支票：作为银行账户资金的代理，控制资金的访问。\n- Spring AOP：使用代理模式来实现面向切面编程。\n\n### 优点\n\n- 职责分离：代理模式将访问控制与业务逻辑分离。\n- 扩展性：可以灵活地添加额外的功能或控制。\n- 智能化：可以智能地处理访问请求，如延迟加载、缓存等。\n\n### 缺点\n\n- 性能开销：增加了代理层可能会影响请求的处理速度。\n- 实现复杂性：某些类型的代理模式实现起来可能较为复杂。\n\n### 使用建议\n\n- 根据具体需求选择合适的代理类型，如远程代理、虚拟代理、保护代理等。\n- 确保代理类与真实对象接口一致，以便客户端透明地使用代理。\n\n### 注意事项\n\n- 与适配器模式的区别：适配器模式改变接口，而代理模式不改变接口。\n- 与装饰器模式的区别：装饰器模式用于增强功能，代理模式用于控制访问。\n\n### 结构\n\n主要涉及到以下几个核心角色：\n\n- 抽象主题（Subject）:\n  - 定义了真实主题和代理主题的共同接口，这样在任何使用真实主题的地方都可以使用代理主题。\n- 真实主题（Real Subject）:\n  - 实现了抽象主题接口，是代理对象所代表的真实对象。客户端直接访问真实主题，但在某些情况下，可以通过代理主题来间接访问。\n- 代理（Proxy）:\n  - 实现了抽象主题接口，并持有对真实主题的引用。代理主题通常在真实主题的基础上提供一些额外的功能，例如延迟加载、权限控制、日志记录等。\n- 客户端（Client）:\n  - 使用抽象主题接口来操作真实主题或代理主题，不需要知道具体是哪一个实现类。\n\n我们将创建一个 Image 接口和实现了 Image 接口的实体类。ProxyImage 是一个代理类，减少 RealImage 对象加载的内存占用。\n\nProxyPatternDemo 类使用 ProxyImage 来获取要加载的 Image 对象，并按照需求进行显示。\n\n![代理模式的 UML 图](/api/uploads/files/runoob/design_pattern/20211025-proxy-2888c6c3f8.svg)\n\n### 步骤 1\n\n创建一个接口。\n\n## Image.java\n\npublic interface Image {\nvoid display();\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## RealImage.java\n\npublic class RealImage implements Image {\nprivate String fileName;\n\n   public RealImage(String fileName){\nthis.fileName = fileName;\n      loadFromDisk(fileName);\n   }\n\n   @Override\npublic void display() {\nSystem.out.println("Displaying " + fileName);\n   }\nprivate void loadFromDisk(String fileName){\nSystem.out.println("Loading " + fileName);\n   }\n}\n\n## ProxyImage.java\n\npublic class ProxyImage implements Image{\nprivate RealImage realImage;\n   private String fileName;\n\n   public ProxyImage(String fileName){\nthis.fileName = fileName;\n   }\n\n   @Override\npublic void display() {\nif(realImage == null){\nrealImage = new RealImage(fileName);\n      }\nrealImage.display();\n   }\n}\n\n### 步骤 3\n\n当被请求时，使用 ProxyImage 来获取 RealImage 类的对象。\n\n## ProxyPatternDemo.java\n\npublic class ProxyPatternDemo {\npublic static void main(String[] args) {\nImage image = new ProxyImage("test_10mb.jpg");\n\n      // 图像将从磁盘加载\nimage.display();\n      System.out.println("");\n      // 图像不需要从磁盘加载\nimage.display();\n   }\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nLoading test_10mb.jpg\nDisplaying test_10mb.jpg\n\nDisplaying test_10mb.jpg\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/proxy-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-proxy-pattern','代理模式 - 设计模式教程','在代理模式（Proxy Pattern）中，一个类代表另一个类的功能，这种类型的设计模式属于结构型模式。 代理模式通过引入一个代理对象来控制对原对象的访问。代理对象在客户端和目标对象之间充当中介，负责将客户端的请求转发给目标对象，同时可以在...',0,'PUBLISHED',4555,185,120,23,'2025-07-15 00:00:00','2025-07-15 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633015,1,'责任链模式','责任链模式（Chain of Responsibility Pattern）为请求创建了一个接收者对象的链。这种模式给予请求的类型，对请求的发送者和接收者进行解耦。这种类型的设计模式属于行为型模式。 责任链模式通过将多个处理器（处理对象）以链式结构连接起来，使得请求沿着这条链传递，直到有一个处理器处理该请求为止。 责任链模式允许多个对象都有机会处理请求，从而避免请求的发送者和接收者之间的耦合关系。将这些对象连成一条链，并沿着这条链传递请求。 允许将请求沿着处理者链传递，直到请求被处理为止。。','# 责任链模式\n\n责任链模式（Chain of Responsibility Pattern）为请求创建了一个接收者对象的链。这种模式给予请求的类型，对请求的发送者和接收者进行解耦。这种类型的设计模式属于行为型模式。\n责任链模式通过将多个处理器（处理对象）以链式结构连接起来，使得请求沿着这条链传递，直到有一个处理器处理该请求为止。\n\n责任链模式允许多个对象都有机会处理请求，从而避免请求的发送者和接收者之间的耦合关系。将这些对象连成一条链，并沿着这条链传递请求。\n\n### 意图\n\n允许将请求沿着处理者链传递，直到请求被处理为止。。\n\n### 主要解决的问题\n\n- 解耦请求发送者和接收者，使多个对象都有可能接收请求，而发送者不需要知道哪个对象会处理它。\n\n### 使用场景\n\n- 当有多个对象可以处理请求，且具体由哪个对象处理由运行时决定时。\n- 当需要向多个对象中的一个提交请求，而不想明确指定接收者时。\n\n### 实现方式\n\n- 定义处理者接口：所有处理者必须实现同一个接口。\n- 创建具体处理者：实现接口的具体类，包含请求处理逻辑和指向链中下一个处理者的引用。\n\n### 关键代码\n\n- Handler接口：定义一个方法用于处理请求。\n- ConcreteHandler类：实现Handler接口，包含请求处理逻辑和对下一个处理者的引用。\n\n### 应用实例\n\n1. 击鼓传花：游戏中的传递行为，直到音乐停止。\n2. 事件冒泡：在JavaScript中，事件从最具体的元素开始，逐级向上传播。\n3. Web服务器：如Apache Tomcat处理字符编码，Struts2的拦截器，以及Servlet的Filter。\n\n### 优点\n\n1. 降低耦合度：发送者和接收者之间解耦。\n2. 简化对象：对象不需要知道链的结构。\n3. 灵活性：通过改变链的成员或顺序，动态地新增或删除责任。\n4. 易于扩展：增加新的请求处理类很方便。\n\n### 缺点\n\n1. 请求未被处理：不能保证请求一定会被链中的某个处理者接收。\n2. 性能影响：可能影响系统性能，且调试困难，可能导致循环调用。\n3. 难以观察：运行时特征不明显，可能妨碍除错。\n\n### 使用建议\n\n- 在处理请求时，如果有多个潜在的处理者，考虑使用责任链模式。\n- 确保链中的每个处理者都明确知道如何传递请求到链的下一个环节。\n\n### 注意事项\n\n- 在Java Web开发中，责任链模式有广泛应用，如过滤器链、拦截器等。\n\n### 结构\n\n主要涉及到以下几个核心角色：\n\n- 抽象处理者（Handler）:\n  - 定义一个处理请求的接口，通常包含一个处理请求的方法（如 `handleRequest`）和一个指向下一个处理者的引用（后继者）。\n- 具体处理者（ConcreteHandler）:\n  - 实现了抽象处理者接口，负责处理请求。如果能够处理该请求，则直接处理；否则，将请求传递给下一个处理者。\n- 客户端（Client）:\n  - 创建处理者对象，并将它们连接成一条责任链。通常，客户端只需要将请求发送给责任链的第一个处理者，无需关心请求的具体处理过程。\n\n我们创建抽象类 AbstractLogger，带有详细的日志记录级别。然后我们创建三种类型的记录器，都扩展了 AbstractLogger。每个记录器消息的级别是否属于自己的级别，如果是则相应地打印出来，否则将不打印并把消息传给下一个记录器。\n\n![责任链模式的 UML 图](/api/uploads/files/runoob/design_pattern/2021-chain-of-responsibility-b8f29fcc1e.svg)\n\n### 步骤 1\n\n创建抽象的记录器类。\n\n## AbstractLogger.java\n\npublic abstract class AbstractLogger {\npublic static int INFO = 1;\n   public static int DEBUG = 2;\n   public static int ERROR = 3;\n\n   protected int level;\n\n   //责任链中的下一个元素\nprotected AbstractLogger nextLogger;\n\n   public void setNextLogger(AbstractLogger nextLogger){\nthis.nextLogger = nextLogger;\n   }\npublic void logMessage(int level, String message){\nif(this.level <= level){\nwrite(message);\n      }\nif(nextLogger !=null){\nnextLogger.logMessage(level, message);\n      }\n}\nabstract protected void write(String message);\n\n}\n\n### 步骤 2\n\n创建扩展了该记录器类的实体类。\n\n## ConsoleLogger.java\n\npublic class ConsoleLogger extends AbstractLogger {\npublic ConsoleLogger(int level){\nthis.level = level;\n   }\n\n   @Override\nprotected void write(String message) {\nSystem.out.println("Standard Console::Logger: " + message);\n   }\n}\n\n## ErrorLogger.java\n\npublic class ErrorLogger extends AbstractLogger {\npublic ErrorLogger(int level){\nthis.level = level;\n   }\n\n   @Override\nprotected void write(String message) {\nSystem.out.println("Error Console::Logger: " + message);\n   }\n}\n\n## FileLogger.java\n\npublic class FileLogger extends AbstractLogger {\npublic FileLogger(int level){\nthis.level = level;\n   }\n\n   @Override\nprotected void write(String message) {\nSystem.out.println("File::Logger: " + message);\n   }\n}\n\n### 步骤 3\n\n创建不同类型的记录器。赋予它们不同的错误级别，并在每个记录器中设置下一个记录器。每个记录器中的下一个记录器代表的是链的一部分。\n\n## ChainPatternDemo.java\n\npublic class ChainPatternDemo {\nprivate static AbstractLogger getChainOfLoggers(){\nAbstractLogger errorLogger = new ErrorLogger(AbstractLogger.ERROR);\n      AbstractLogger fileLogger = new FileLogger(AbstractLogger.DEBUG);\n      AbstractLogger consoleLogger = new ConsoleLogger(AbstractLogger.INFO);\n\n      errorLogger.setNextLogger(fileLogger);\n      fileLogger.setNextLogger(consoleLogger);\n\n      return errorLogger;\n   }\npublic static void main(String[] args) {\nAbstractLogger loggerChain = getChainOfLoggers();\n\n      loggerChain.logMessage(AbstractLogger.INFO, "This is an information.");\n\n      loggerChain.logMessage(AbstractLogger.DEBUG,\n         "This is a debug level information.");\n\n      loggerChain.logMessage(AbstractLogger.ERROR,\n         "This is an error information.");\n   }\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nStandard Console::Logger: This is an information.\nFile::Logger: This is a debug level information.\nStandard Console::Logger: This is a debug level information.\nError Console::Logger: This is an error information.\nFile::Logger: This is an error information.\nStandard Console::Logger: This is an error information.\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/chain-of-responsibility-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-chain-of-responsibility-pattern','责任链模式 - 设计模式教程','责任链模式（Chain of Responsibility Pattern）为请求创建了一个接收者对象的链。这种模式给予请求的类型，对请求的发送者和接收者进行解耦。这种类型的设计模式属于行为型模式。 责任链模式通过将多个处理器（处理对象）以...',0,'PUBLISHED',4692,192,125,24,'2025-07-16 00:00:00','2025-07-16 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633016,1,'命令模式','命令模式（Command Pattern）是一种数据驱动的设计模式，它属于行为型模式。 命令模式将一个请求封装为一个对象，从而使你可以用不同的请求对客户进行参数化，对请求排队或记录请求日志，以及支持可撤销的操作。 将请求封装为一个对象，允许用户使用不同的请求对客户端进行参数化。 1. 降低耦合度：请求者和执行者之间的耦合度降低。','# 命令模式\n\n命令模式（Command Pattern）是一种数据驱动的设计模式，它属于行为型模式。\n命令模式将一个请求封装为一个对象，从而使你可以用不同的请求对客户进行参数化，对请求排队或记录请求日志，以及支持可撤销的操作。\n\n命令模式结构示意图:\n\n![图片](/api/uploads/files/runoob/design_pattern/commanduml-954b832304.jpg)\n\n### 意图\n\n将请求封装为一个对象，允许用户使用不同的请求对客户端进行参数化。\n\n### 主要解决的问题\n\n- 解决在软件系统中请求者和执行者之间的紧耦合问题，特别是在需要对行为进行记录、撤销/重做或事务处理等场景。\n\n### 使用场景\n\n- 当需要对行为进行记录、撤销/重做或事务处理时，使用命令模式来解耦请求者和执行者。\n\n### 实现方式\n\n- 定义命令接口：所有命令必须实现的接口。\n- 创建具体命令：实现命令接口的具体类，包含执行请求的方法。\n- 调用者：持有命令对象并触发命令的执行。\n- 接收者：实际执行命令的对象。\n\n### 关键代码\n\n- 接收者（Receiver）：执行命令的实际对象。\n- 命令（Command）：定义执行命令的接口。\n- 调用者（Invoker）：使用命令对象的入口点。\n\n### 应用实例\n\n- Struts 1：ActionServlet作为Invoker，模型层的类作为具体的Command。\n\n### 优点\n\n1. 降低耦合度：请求者和执行者之间的耦合度降低。\n2. 易于扩展：新命令可以很容易地添加到系统中。\n\n### 缺点\n\n- 过多命令类：系统可能会有过多的具体命令类，增加系统的复杂度。\n\n### 使用建议\n\n- 在GUI中，每个按钮或菜单项可以视为一条命令。\n- 在需要模拟命令行操作的场景中使用命令模式。\n\n### 注意事项\n\n- 如果系统需要支持命令的撤销（Undo）和恢复（Redo）操作，命令模式是一个合适的选择。\n\n### 结构\n\n主要涉及到以下几个核心角色：\n\n- 命令（Command）:\n  - 定义了执行操作的接口，通常包含一个 `execute` 方法，用于调用具体的操作。\n- 具体命令（ConcreteCommand）:\n  - 实现了命令接口，负责执行具体的操作。它通常包含了对接收者的引用，通过调用接收者的方法来完成请求的处理。\n- 接收者（Receiver）:\n  - 知道如何执行与请求相关的操作，实际执行命令的对象。\n- 调用者/请求者（Invoker）:\n  - 发送命令的对象，它包含了一个命令对象并能触发命令的执行。调用者并不直接处理请求，而是通过将请求传递给命令对象来实现。\n- 客户端（Client）:\n  - 创建具体命令对象并设置其接收者，将命令对象交给调用者执行。\n\n我们首先创建作为命令的接口 Order，然后创建作为请求的 Stock 类。实体命令类 BuyStock 和 SellStock，实现了 Order 接口，将执行实际的命令处理。创建作为调用对象的类 Broker，它接受订单并能下订单。\n\nBroker 对象使用命令模式，基于命令的类型确定哪个对象执行哪个命令。CommandPatternDemo 类使用 Broker 类来演示命令模式。\n\n![图片](/api/uploads/files/runoob/design_pattern/20220427-command-1-command-1-d4bf4183d0.svg)\n\n### 步骤 1\n\n创建一个命令接口。\n\n## Order.java\n\npublic interface Order {\nvoid execute();\n}\n\n### 步骤 2\n\n创建一个请求类。\n\n## Stock.java\n\npublic class Stock {\nprivate String name = "ABC";\n   private int quantity = 10;\n\n   public void buy(){\nSystem.out.println("Stock [ Name: "+name+",\n         Quantity: " + quantity +" ] bought");\n   }\npublic void sell(){\nSystem.out.println("Stock [ Name: "+name+",\n         Quantity: " + quantity +" ] sold");\n   }\n}\n\n### 步骤 3\n\n创建实现了 Order 接口的实体类。\n\n## BuyStock.java\n\npublic class BuyStock implements Order {\nprivate Stock abcStock;\n\n   public BuyStock(Stock abcStock){\nthis.abcStock = abcStock;\n   }\npublic void execute() {\nabcStock.buy();\n   }\n}\n\n## SellStock.java\n\npublic class SellStock implements Order {\nprivate Stock abcStock;\n\n   public SellStock(Stock abcStock){\nthis.abcStock = abcStock;\n   }\npublic void execute() {\nabcStock.sell();\n   }\n}\n\n### 步骤 4\n\n创建命令调用类。\n\n## Broker.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Broker {\nprivate List<Order> orderList = new ArrayList<Order>();\n\n   public void takeOrder(Order order){\norderList.add(order);\n   }\npublic void placeOrders(){\nfor (Order order : orderList) {\norder.execute();\n      }\norderList.clear();\n   }\n}\n\n### 步骤 5\n\n使用 Broker 类来接受并执行命令。\n\n## CommandPatternDemo.java\n\npublic class CommandPatternDemo {\npublic static void main(String[] args) {\nStock abcStock = new Stock();\n\n      BuyStock buyStockOrder = new BuyStock(abcStock);\n      SellStock sellStockOrder = new SellStock(abcStock);\n\n      Broker broker = new Broker();\n      broker.takeOrder(buyStockOrder);\n      broker.takeOrder(sellStockOrder);\n\n      broker.placeOrders();\n   }\n}\n\n### 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nStock [ Name: ABC, Quantity: 10 ] bought\nStock [ Name: ABC, Quantity: 10 ] sold\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/command-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-command-pattern','命令模式 - 设计模式教程','命令模式（Command Pattern）是一种数据驱动的设计模式，它属于行为型模式。 命令模式将一个请求封装为一个对象，从而使你可以用不同的请求对客户进行参数化，对请求排队或记录请求日志，以及支持可撤销的操作。 将请求封装为一个对象，允许...',0,'PUBLISHED',4829,199,130,25,'2025-07-17 00:00:00','2025-07-17 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633017,1,'解释器模式','解释器模式（Interpreter Pattern）提供了评估语言的语法或表达式的方式，它属于行为型模式。 解释器模式给定一个语言，定义它的文法的一种表示，并定义一个解释器，这个解释器使用该表示来解释语言中的句子。 这种模式被用在 SQL 解析、符号处理引擎等。 定义一种语言的文法表示，并创建一个解释器，该解释器能够解释该语言中的句子。。','# 解释器模式\n\n解释器模式（Interpreter Pattern）提供了评估语言的语法或表达式的方式，它属于行为型模式。\n\n解释器模式给定一个语言，定义它的文法的一种表示，并定义一个解释器，这个解释器使用该表示来解释语言中的句子。\n\n这种模式被用在 SQL 解析、符号处理引擎等。\n\n### 意图\n定义一种语言的文法表示，并创建一个解释器，该解释器能够解释该语言中的句子。。\n\n### 主要解决的问题\n\n- 解释器模式用于构建一个能够解释特定语言或文法的句子的解释器。\n\n### 使用场景\n\n- 当某一特定类型的问题频繁出现，并且可以通过一种简单的语言来表达这些问题的实例时。\n\n### 实现方式\n\n- 定义文法：明确语言的终结符和非终结符。\n- 构建语法树：根据语言的句子构建对应的语法树结构。\n- 创建环境类：包含解释过程中所需的全局信息，通常是一个HashMap。\n\n### 关键代码\n\n- 终结符与非终结符：定义语言的文法结构。\n- 环境类：存储解释过程中需要的外部环境信息。\n\n### 应用实例\n\n- 编译器：解释器模式可以用于编译器设计，将源代码解释为目标代码。\n- 正则表达式：解释器模式可以用于解析和执行正则表达式。\n- SQL解析：解释器模式可以用于解析和执行SQL语句。\n\n### 优点\n\n- 可扩展性好：容易添加新的解释表达式的方式。\n- 灵活性：可以根据需要轻松扩展或修改文法。\n- 易于实现简单文法：对于简单的语言，实现起来相对容易。\n\n### 缺点\n\n1. 使用场景有限：只适用于适合使用解释的简单文法。\n2. 维护困难：对于复杂的文法，维护和扩展变得困难。\n3. 类膨胀：可能会产生很多类，每个文法规则对应一个类。\n4. 递归调用：解释器模式通常使用递归调用，这可能难以理解和跟踪。\n\n### 使用建议\n\n- 在需要解释执行语言中的句子时，考虑使用解释器模式。\n- 确保文法简单，以避免系统变得过于复杂。\n\n### 注意事项\n\n- 解释器模式在 Java 中可能不是首选，如果遇到适用场景，可以考虑使用如expression4J之类的库来代替。\n\n### 结构\n\n解释器模式包含以下几个主要角色：\n\n- 抽象表达式（Abstract Expression）：定义了解释器的抽象接口，声明了解释操作的方法，通常是一个抽象类或接口。\n- 终结符表达式（Terminal Expression）：实现了抽象表达式接口的终结符表达式类，用于表示语言中的终结符（如变量、常量等），并实现了对应的解释操作。\n- 非终结符表达式（Non-terminal Expression）：实现了抽象表达式接口的非终结符表达式类，用于表示语言中的非终结符（如句子、表达式等），并实现了对应的解释操作。\n- 上下文（Context）：包含解释器之外的一些全局信息，在解释过程中提供给解释器使用，通常用于存储变量的值、保存解释器的状态等。\n- 客户端（Client）：创建并配置具体的解释器对象，并将需要解释的表达式传递给解释器进行解释。\n\n我们将创建一个接口 Expression 和实现了 Expression 接口的实体类。定义作为上下文中主要解释器的 TerminalExpression 类。其他的类 OrExpression、AndExpression 用于创建组合式表达式。\n\nInterpreterPatternDemo，我们的演示类使用 Expression 类创建规则和演示表达式的解析。\n\n![解释器模式的 UML 图](/api/uploads/files/runoob/design_pattern/interpreter_pattern_uml_diagram-269be17953.jpg)\n\n### 步骤 1\n\n创建一个表达式接口。\n\n## Expression.java\n\npublic interface Expression {\npublic boolean interpret(String context);\n}\n\n### 步骤 2\n\n创建实现了上述接口的实体类。\n\n## TerminalExpression.java\n\npublic class TerminalExpression implements Expression {\nprivate String data;\n\n   public TerminalExpression(String data){\nthis.data = data;\n   }\n\n   @Override\npublic boolean interpret(String context) {\nif(context.contains(data)){\nreturn true;\n      }\nreturn false;\n   }\n}\n\n## OrExpression.java\n\npublic class OrExpression implements Expression {\nprivate Expression expr1 = null;\n   private Expression expr2 = null;\n\n   public OrExpression(Expression expr1, Expression expr2) {\nthis.expr1 = expr1;\n      this.expr2 = expr2;\n   }\n\n   @Override\npublic boolean interpret(String context) {\nreturn expr1.interpret(context) || expr2.interpret(context);\n   }\n}\n\n## AndExpression.java\n\npublic class AndExpression implements Expression {\nprivate Expression expr1 = null;\n   private Expression expr2 = null;\n\n   public AndExpression(Expression expr1, Expression expr2) {\nthis.expr1 = expr1;\n      this.expr2 = expr2;\n   }\n\n   @Override\npublic boolean interpret(String context) {\nreturn expr1.interpret(context) && expr2.interpret(context);\n   }\n}\n\n### 步骤 3\n\nInterpreterPatternDemo 使用 Expression 类来创建规则，并解析它们。\n\n## InterpreterPatternDemo.java\n\npublic class InterpreterPatternDemo {\n//规则：Robert 和 John 是男性\npublic static Expression getMaleExpression(){\nExpression robert = new TerminalExpression("Robert");\n      Expression john = new TerminalExpression("John");\n      return new OrExpression(robert, john);\n   }\n//规则：Julie 是一个已婚的女性\npublic static Expression getMarriedWomanExpression(){\nExpression julie = new TerminalExpression("Julie");\n      Expression married = new TerminalExpression("Married");\n      return new AndExpression(julie, married);\n   }\npublic static void main(String[] args) {\nExpression isMale = getMaleExpression();\n      Expression isMarriedWoman = getMarriedWomanExpression();\n\n      System.out.println("John is male? " + isMale.interpret("John"));\n      System.out.println("Julie is a married women? "\n      + isMarriedWoman.interpret("Married Julie"));\n   }\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nJohn is male? true\nJulie is a married women? true\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/interpreter-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-interpreter-pattern','解释器模式 - 设计模式教程','解释器模式（Interpreter Pattern）提供了评估语言的语法或表达式的方式，它属于行为型模式。 解释器模式给定一个语言，定义它的文法的一种表示，并定义一个解释器，这个解释器使用该表示来解释语言中的句子。 这种模式被用在 SQL ...',0,'PUBLISHED',4966,206,135,26,'2025-07-18 00:00:00','2025-07-18 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633018,1,'迭代器模式','迭代器模式（Iterator Pattern）是 Java 和 .Net 编程环境中非常常用的设计模式。 迭代器模式提供一种方法顺序访问一个聚合对象中的各个元素，而又不暴露其内部的表示。 迭代器模式属于行为型模式。 允许顺序访问一个聚合对象中的元素，同时不暴露对象的内部表示。','# 迭代器模式\n\n迭代器模式（Iterator Pattern）是 Java 和 .Net 编程环境中非常常用的设计模式。\n\n迭代器模式提供一种方法顺序访问一个聚合对象中的各个元素，而又不暴露其内部的表示。\n\n迭代器模式属于行为型模式。\n\n### 意图\n\n允许顺序访问一个聚合对象中的元素，同时不暴露对象的内部表示。\n\n### 主要解决的问题\n\n- 提供一种统一的方法来遍历不同的聚合对象。\n\n### 使用场景\n\n- 当需要遍历一个聚合对象，而又不希望暴露其内部结构时。\n\n### 实现方式\n\n- 定义迭代器接口：包含`hasNext()`和`next()`等方法，用于遍历元素。\n- 创建具体迭代器：实现迭代器接口，定义如何遍历特定的聚合对象。\n- 聚合类：定义一个接口用于返回一个迭代器对象。\n\n### 关键代码\n\n- 迭代器接口：规定了遍历元素的方法。\n- 具体迭代器：实现了迭代器接口，包含遍历逻辑。\n\n### 应用实例\n\n- Java中的Iterator：Java集合框架中的迭代器用于遍历集合元素。\n\n### 优点\n\n1. 支持多种遍历方式：不同的迭代器可以定义不同的遍历方式。\n2. 简化聚合类：聚合类不需要关心遍历逻辑。\n3. 多遍历支持：可以同时对同一个聚合对象进行多次遍历。\n4. 扩展性：增加新的聚合类和迭代器类都很方便，无需修改现有代码。\n\n### 缺点\n\n- 系统复杂性：每增加一个聚合类，就需要增加一个对应的迭代器类，增加了类的数量。\n\n### 使用建议\n\n- 当需要访问聚合对象内容而不暴露其内部表示时，使用迭代器模式。\n- 当需要为聚合对象提供多种遍历方式时，考虑使用迭代器模式。\n\n### 注意事项\n\n- 迭代器模式通过分离集合对象的遍历行为，使得外部代码可以透明地访问集合内部数据，同时不暴露集合的内部结构。\n\n### 结构\n\n迭代器模式包含以下几个主要角色：\n\n- 迭代器接口（Iterator）：定义了访问和遍历聚合对象中各个元素的方法，通常包括获取下一个元素、判断是否还有元素、获取当前位置等方法。\n- 具体迭代器（Concrete Iterator）：实现了迭代器接口，负责对聚合对象进行遍历和访问，同时记录遍历的当前位置。\n- 聚合对象接口（Aggregate）：定义了创建迭代器对象的接口，通常包括一个工厂方法用于创建迭代器对象。\n- 具体聚合对象（Concrete Aggregate）：实现了聚合对象接口，负责创建具体的迭代器对象，并提供需要遍历的数据。\n\n我们将创建一个叙述导航方法的 Iterator 接口和一个返回迭代器的 Container 接口。实现了 Container 接口的实体类将负责实现 Iterator 接口。\n\nIteratorPatternDemo，我们的演示类使用实体类 NamesRepository 来打印 NamesRepository 中存储为集合的 Names。\n\n![迭代器模式的 UML 图](/api/uploads/files/runoob/design_pattern/202107-23-iterator-pattern-756d74abcb.png)\n\n### 步骤 1\n\n创建接口:\n\n## Iterator.java\n\npublic interface Iterator {\npublic boolean hasNext();\n   public Object next();\n}\n\n## Container.java\n\npublic interface Container {\npublic Iterator getIterator();\n}\n\n### 步骤 2\n\n创建实现了 Container 接口的实体类。该类有实现了 Iterator 接口的内部类 NameIterator。\n\n## NameRepository.java\n\npublic class NameRepository implements Container {\npublic String[] names = {"Robert" , "John" ,"Julie" , "Lora"};\n\n   @Override\npublic Iterator getIterator() {\nreturn new NameIterator();\n   }\nprivate class NameIterator implements Iterator {\nint index;\n\n      @Override\npublic boolean hasNext() {\nif(index < names.length){\nreturn true;\n         }\nreturn false;\n      }\n\n      @Override\npublic Object next() {\nif(this.hasNext()){\nreturn names[index++];\n         }\nreturn null;\n      }\n}\n}\n\n### 步骤 3\n\n使用 NameRepository 来获取迭代器，并打印名字。\n\n## IteratorPatternDemo.java\n\npublic class IteratorPatternDemo {\npublic static void main(String[] args) {\nNameRepository namesRepository = new NameRepository();\n\n      for(Iterator iter = namesRepository.getIterator(); iter.hasNext();){\nString name = (String)iter.next();\n         System.out.println("Name : " + name);\n      }\n}\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nName : Robert\nName : John\nName : Julie\nName : Lora\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/iterator-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-iterator-pattern','迭代器模式 - 设计模式教程','迭代器模式（Iterator Pattern）是 Java 和 .Net 编程环境中非常常用的设计模式。 迭代器模式提供一种方法顺序访问一个聚合对象中的各个元素，而又不暴露其内部的表示。 迭代器模式属于行为型模式。 允许顺序访问一个聚合对象...',0,'PUBLISHED',5103,213,140,27,'2025-07-19 00:00:00','2025-07-19 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633019,1,'中介者模式','中介者模式（Mediator Pattern）是用来降低多个对象和类之间的通信复杂性，属于行为型模式。 中介者模式定义了一个中介对象来封装一系列对象之间的交互。中介者使各对象之间不需要显式地相互引用，从而使其耦合松散，且可以独立地改变它们之间的交互。 通过引入一个中介者对象来封装和协调多个对象之间的交互，从而降低对象间的耦合度。 1. WTO：中国加入WTO后，各国通过WTO进行贸易，简化了双边关系。','# 中介者模式\n\n中介者模式（Mediator Pattern）是用来降低多个对象和类之间的通信复杂性，属于行为型模式。\n\n中介者模式定义了一个中介对象来封装一系列对象之间的交互。中介者使各对象之间不需要显式地相互引用，从而使其耦合松散，且可以独立地改变它们之间的交互。\n\n### 意图\n\n通过引入一个中介者对象来封装和协调多个对象之间的交互，从而降低对象间的耦合度。\n\n### 主要解决的问题\n\n- 解决对象间复杂的一对多关联问题，避免对象之间的高度耦合，简化系统结构。\n\n### 使用场景\n\n- 当系统中多个类相互耦合，形成网状结构时。\n\n### 实现方式\n\n- 定义中介者接口：规定中介者必须实现的接口。\n- 创建具体中介者：实现中介者接口，包含协调各同事对象交互的逻辑。\n- 定义同事类：各个对象不需要显式地相互引用，而是通过中介者来进行交互。\n\n### 关键代码\n\n- 中介者：封装了对象间的交互逻辑。\n- 同事类：通过中介者进行通信。\n\n### 应用实例\n\n1. WTO：中国加入WTO后，各国通过WTO进行贸易，简化了双边关系。\n2. 机场调度系统：协调飞机起降、跑道使用等。\n3. MVC框架：控制器作为模型和视图的中介者。\n\n### 优点\n\n1. 降低复杂度：将多个对象间的一对多关系转换为一对一关系。\n2. 解耦：对象之间不再直接引用，通过中介者进行交互。\n3. 符合迪米特原则：对象只需知道中介者，不需要知道其他对象。\n\n### 缺点\n\n- 中介者复杂性：中介者可能会变得庞大和复杂，难以维护。\n\n### 使用建议\n\n- 当系统中对象间存在复杂的引用关系时，考虑使用中介者模式。\n- 通过中介者封装多个类的行为，避免生成过多的子类。\n\n### 注意事项\n\n- 避免在职责不明确或混乱的情况下使用中介者模式，这可能导致中介者承担过多职责。\n\n### 结构\n\n中介者模式包含以下几个主要角色：\n\n- 中介者（Mediator）：定义了一个接口用于与各个同事对象通信，并管理各个同事对象之间的关系。通常包括一个或多个事件处理方法，用于处理各种交互事件。\n- 具体中介者（Concrete Mediator）：实现了中介者接口，负责实现各个同事对象之间的通信逻辑。它会维护一个对各个同事对象的引用，并协调它们的交互。\n- 同事对象（Colleague）：定义了一个接口，用于与中介者进行通信。通常包括一个发送消息的方法，以及一个接收消息的方法。\n- 具体同事对象（Concrete Colleague）：实现了同事对象接口，是真正参与到交互中的对象。它会将自己的消息发送给中介者，由中介者转发给其他同事对象。\n\n我们通过聊天室实例来演示中介者模式。实例中，多个用户可以向聊天室发送消息，聊天室向所有的用户显示消息。我们将创建两个类 ChatRoom 和 User。User 对象使用 ChatRoom 方法来分享他们的消息。\n\nMediatorPatternDemo，我们的演示类使用 User 对象来显示他们之间的通信。\n\n![中介者模式的 UML 图](/api/uploads/files/runoob/design_pattern/mediator_pattern_uml_diagram-8b3a95cebd.jpg)\n\n### 步骤 1\n\n创建中介类。\n\n## ChatRoom.java\n\nimport java.util.Date;\n\npublic class ChatRoom {\npublic static void showMessage(User user, String message){\nSystem.out.println(new Date().toString()\n         + " [" + user.getName() +"] : " + message);\n   }\n}\n\n### 步骤 2\n\n创建 user 类。\n\n## User.java\n\npublic class User {\nprivate String name;\n\n   public String getName() {\nreturn name;\n   }\npublic void setName(String name) {\nthis.name = name;\n   }\npublic User(String name){\nthis.name  = name;\n   }\npublic void sendMessage(String message){\nChatRoom.showMessage(this,message);\n   }\n}\n\n### 步骤 3\n\n使用 User 对象来显示他们之间的通信。\n\n## MediatorPatternDemo.java\n\npublic class MediatorPatternDemo {\npublic static void main(String[] args) {\nUser robert = new User("Robert");\n      User john = new User("John");\n\n      robert.sendMessage("Hi! John!");\n      john.sendMessage("Hello! Robert!");\n   }\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nThu Jan 31 16:05:46 IST 2013 [Robert] : Hi! John!\nThu Jan 31 16:05:46 IST 2013 [John] : Hello! Robert!\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/mediator-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-mediator-pattern','中介者模式 - 设计模式教程','中介者模式（Mediator Pattern）是用来降低多个对象和类之间的通信复杂性，属于行为型模式。 中介者模式定义了一个中介对象来封装一系列对象之间的交互。中介者使各对象之间不需要显式地相互引用，从而使其耦合松散，且可以独立地改变它们之...',0,'PUBLISHED',5240,220,145,28,'2025-07-20 00:00:00','2025-07-20 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633020,1,'备忘录模式','备忘录模式（Memento Pattern）保存一个对象的某个状态，以便在适当的时候恢复对象，备忘录模式属于行为型模式。 备忘录模式允许在不破坏封装性的前提下，捕获和恢复对象的内部状态。 在不破坏封装性的前提下，捕获一个对象的内部状态，并允许在对象之外保存和恢复这些状态。 备忘录模式包含以下几个主要角色：','# 备忘录模式\n\n备忘录模式（Memento Pattern）保存一个对象的某个状态，以便在适当的时候恢复对象，备忘录模式属于行为型模式。\n\n备忘录模式允许在不破坏封装性的前提下，捕获和恢复对象的内部状态。\n\n### 意图\n\n在不破坏封装性的前提下，捕获一个对象的内部状态，并允许在对象之外保存和恢复这些状态。\n\n### 主要解决的问题\n\n- 允许捕获并保存一个对象的内部状态，以便在将来可以恢复到该状态，实现撤销和回滚操作。\n\n### 使用场景\n\n- 当需要提供一种撤销机制，允许用户回退到之前的状态时。\n\n### 实现方式\n\n- 创建备忘录类：用于存储和封装对象的状态。\n- 创建发起人角色：负责创建备忘录，并根据需要恢复状态。\n- 创建备忘录管理类（可选）：负责管理所有备忘录对象。\n\n### 关键代码\n\n- 备忘录：存储发起人的状态信息。\n- 发起人：创建备忘录，并根据备忘录恢复状态。\n\n### 应用实例\n\n- 后悔药：提供一种撤销操作的功能。\n- 游戏存档：保存游戏进度，允许玩家加载之前的存档。\n- Windows中的Ctrl+Z：实现撤销操作。\n- IE浏览器的后退：允许用户回退到之前的页面。\n- 数据库事务管理：通过事务日志保存状态，实现回滚。\n\n### 优点\n\n- 提供状态恢复机制：允许用户方便地回到历史状态。\n- 封装状态信息：用户不需要关心状态的保存细节。\n\n### 缺点\n\n- 资源消耗：如果对象的状态复杂，保存状态可能会占用较多资源。\n\n### 使用建议\n\n- 在需要保存和恢复数据状态的场景中使用备忘录模式。\n- 考虑使用原型模式结合备忘录模式，以节约内存。\n\n### 注意事项\n\n- 为了降低耦合度，应通过备忘录管理类间接管理备忘录对象。\n- 备忘录模式应谨慎使用，避免过度消耗系统资源。\n\n### 结构\n\n备忘录模式包含以下几个主要角色：\n\n- 备忘录（Memento）：负责存储原发器对象的内部状态。备忘录可以保持原发器的状态的一部分或全部信息。\n- 原发器（Originator）：创建一个备忘录对象，并且可以使用备忘录对象恢复自身的内部状态。原发器通常会在需要保存状态的时候创建备忘录对象，并在需要恢复状态的时候使用备忘录对象。\n- 负责人（Caretaker）：负责保存备忘录对象，但是不对备忘录对象进行操作或检查。负责人只能将备忘录传递给其他对象。\n\n备忘录模式使用三个类 Memento、Originator 和 CareTaker。Memento 包含了要被恢复的对象的状态。Originator 创建并在 Memento 对象中存储状态。Caretaker 对象负责从 Memento 中恢复对象的状态。\n\nMementoPatternDemo，我们的演示类使用 CareTaker 和 Originator 对象来显示对象的状态恢复。\n\n![备忘录模式的 UML 图](/api/uploads/files/runoob/design_pattern/memento-20220601-memento-035c4d9fb7.svg)\n\n### 步骤 1\n\n创建 Memento 类。\n\n## Memento.java\n\npublic class Memento {\nprivate String state;\n\n   public Memento(String state){\nthis.state = state;\n   }\npublic String getState(){\nreturn state;\n   }\n}\n\n### 步骤 2\n\n创建 Originator 类。\n\n## Originator.java\n\npublic class Originator {\nprivate String state;\n\n   public void setState(String state){\nthis.state = state;\n   }\npublic String getState(){\nreturn state;\n   }\npublic Memento saveStateToMemento(){\nreturn new Memento(state);\n   }\npublic void getStateFromMemento(Memento Memento){\nstate = Memento.getState();\n   }\n}\n\n### 步骤 3\n\n创建 CareTaker 类。\n\n## CareTaker.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class CareTaker {\nprivate List<Memento> mementoList = new ArrayList<Memento>();\n\n   public void add(Memento state){\nmementoList.add(state);\n   }\npublic Memento get(int index){\nreturn mementoList.get(index);\n   }\n}\n\n### 步骤 4\n\n使用 CareTaker 和 Originator 对象。\n\n## MementoPatternDemo.java\n\npublic class MementoPatternDemo {\npublic static void main(String[] args) {\nOriginator originator = new Originator();\n      CareTaker careTaker = new CareTaker();\n      originator.setState("State #1");\n      originator.setState("State #2");\n      careTaker.add(originator.saveStateToMemento());\n      originator.setState("State #3");\n      careTaker.add(originator.saveStateToMemento());\n      originator.setState("State #4");\n\n      System.out.println("Current State: " + originator.getState());\n      originator.getStateFromMemento(careTaker.get(0));\n      System.out.println("First saved State: " + originator.getState());\n      originator.getStateFromMemento(careTaker.get(1));\n      System.out.println("Second saved State: " + originator.getState());\n   }\n}\n\n### 步骤 5\n\n验证输出。\n\n```text\n\nCurrent State: State #4\nFirst saved State: State #2\nSecond saved State: State #3\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/memento-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-memento-pattern','备忘录模式 - 设计模式教程','备忘录模式（Memento Pattern）保存一个对象的某个状态，以便在适当的时候恢复对象，备忘录模式属于行为型模式。 备忘录模式允许在不破坏封装性的前提下，捕获和恢复对象的内部状态。 在不破坏封装性的前提下，捕获一个对象的内部状态，并允...',0,'PUBLISHED',5377,227,150,29,'2025-07-21 00:00:00','2025-07-21 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633021,1,'观察者模式','观察者模式是一种行为型设计模式，它定义了一种一对多的依赖关系，当一个对象的状态发生改变时，其所有依赖者都会收到通知并自动更新。 当对象间存在一对多关系时，则使用观察者模式（Observer Pattern）。比如，当一个对象被修改时，则会自动通知依赖它的对象。观察者模式属于行为型模式。 创建了对象间的一种一对多的依赖关系，当一个对象状态改变时，所有依赖于它的对象都会得到通知并自动更新。。 观察者模式包含以下几个核心角色：','# 观察者模式\n\n观察者模式是一种行为型设计模式，它定义了一种一对多的依赖关系，当一个对象的状态发生改变时，其所有依赖者都会收到通知并自动更新。\n\n当对象间存在一对多关系时，则使用观察者模式（Observer Pattern）。比如，当一个对象被修改时，则会自动通知依赖它的对象。观察者模式属于行为型模式。\n\n### 意图\n\n创建了对象间的一种一对多的依赖关系，当一个对象状态改变时，所有依赖于它的对象都会得到通知并自动更新。。\n\n### 主要解决的问题\n\n- 观察者模式解决的是一个对象状态改变时，如何自动通知其他依赖对象的问题，同时保持对象间的低耦合和高协作性。\n\n### 使用场景\n\n- 当一个对象的状态变化需要同时更新其他对象时。\n\n### 实现方式\n\n- 定义观察者接口：包含一个更新方法。\n- 创建具体观察者：实现观察者接口，定义接收到通知时的行为。\n- 定义主题接口：包含添加、删除和通知观察者的方法。\n- 创建具体主题：实现主题接口，管理观察者列表，并在状态改变时通知它们。\n\n### 关键代码\n\n- 观察者列表：在主题中维护一个观察者列表。\n\n### 应用实例\n\n- 拍卖系统：拍卖师作为主题，竞价者作为观察者，拍卖价格更新时通知所有竞价者。\n- 西游记故事：菩萨洒水作为状态改变，老乌龟作为观察者，观察到这一变化。\n\n### 优点\n\n- 抽象耦合：观察者和主题之间是抽象耦合的。\n- 触发机制：建立了一套状态改变时的触发和通知机制。\n\n### 缺点\n\n- 性能问题：如果观察者众多，通知过程可能耗时。\n- 循环依赖：可能导致循环调用和系统崩溃。\n- 缺乏变化详情：观察者不知道主题如何变化，只知道变化发生。\n\n### 使用建议\n\n- 在需要降低对象间耦合度，并且对象状态变化需要触发其他对象变化时使用。\n- 考虑使用Java内置的观察者模式支持类，如`java.util.Observable`和`java.util.Observer`。\n\n### 注意事项\n\n- 避免循环引用：注意观察者和主题之间的依赖关系，避免循环引用。\n- 异步执行：考虑使用异步通知避免单点故障导致整个系统卡壳。\n\n### 结构\n\n观察者模式包含以下几个核心角色：\n\n- 主题（Subject）：也称为被观察者或可观察者，它是具有状态的对象，并维护着一个观察者列表。主题提供了添加、删除和通知观察者的方法。\n- 观察者（Observer）：观察者是接收主题通知的对象。观察者需要实现一个更新方法，当收到主题的通知时，调用该方法进行更新操作。\n- 具体主题（Concrete Subject）：具体主题是主题的具体实现类。它维护着观察者列表，并在状态发生改变时通知观察者。\n- 具体观察者（Concrete Observer）：具体观察者是观察者的具体实现类。它实现了更新方法，定义了在收到主题通知时需要执行的具体操作。\n\n观察者模式通过将主题和观察者解耦，实现了对象之间的松耦合。当主题的状态发生改变时，所有依赖于它的观察者都会收到通知并进行相应的更新。\n\n观察者模式使用三个类 Subject、Observer 和 Client。Subject 对象带有绑定观察者到 Client 对象和从 Client 对象解绑观察者的方法。我们创建 Subject 类、Observer 抽象类和扩展了抽象类 Observer 的实体类。\n\nObserverPatternDemo，我们的演示类使用 Subject 和实体类对象来演示观察者模式。\n\n![观察者模式的 UML 图](/api/uploads/files/runoob/design_pattern/observer_pattern_uml_diagram-0b9b7e8043.jpg)\n\n### 步骤 1\n\n创建 Subject 类。\n\n## Subject.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Subject {\nprivate List<Observer> observers\n      = new ArrayList<Observer>();\n   private int state;\n\n   public int getState() {\nreturn state;\n   }\npublic void setState(int state) {\nthis.state = state;\n      notifyAllObservers();\n   }\npublic void attach(Observer observer){\nobservers.add(observer);\n   }\npublic void notifyAllObservers(){\nfor (Observer observer : observers) {\nobserver.update();\n      }\n}\n}\n\n### 步骤 2\n\n创建 Observer 类。\n\n## Observer.java\n\npublic abstract class Observer {\nprotected Subject subject;\n   public abstract void update();\n}\n\n### 步骤 3\n\n创建实体观察者类。\n\n## BinaryObserver.java\n\npublic class BinaryObserver extends Observer{\npublic BinaryObserver(Subject subject){\nthis.subject = subject;\n      this.subject.attach(this);\n   }\n\n   @Override\npublic void update() {\nSystem.out.println( "Binary String: "\n      + Integer.toBinaryString( subject.getState() ) );\n   }\n}\n\n## OctalObserver.java\n\npublic class OctalObserver extends Observer{\npublic OctalObserver(Subject subject){\nthis.subject = subject;\n      this.subject.attach(this);\n   }\n\n   @Override\npublic void update() {\nSystem.out.println( "Octal String: "\n     + Integer.toOctalString( subject.getState() ) );\n   }\n}\n\n## HexaObserver.java\n\npublic class HexaObserver extends Observer{\npublic HexaObserver(Subject subject){\nthis.subject = subject;\n      this.subject.attach(this);\n   }\n\n   @Override\npublic void update() {\nSystem.out.println( "Hex String: "\n      + Integer.toHexString( subject.getState() ).toUpperCase() );\n   }\n}\n\n### 步骤 4\n\n使用 Subject 和实体观察者对象。\n\n## ObserverPatternDemo.java\n\npublic class ObserverPatternDemo {\npublic static void main(String[] args) {\nSubject subject = new Subject();\n\n      new HexaObserver(subject);\n      new OctalObserver(subject);\n      new BinaryObserver(subject);\n\n      System.out.println("First state change: 15");\n      subject.setState(15);\n      System.out.println("Second state change: 10");\n      subject.setState(10);\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nFirst state change: 15\nHex String: F\nOctal String: 17\nBinary String: 1111\nSecond state change: 10\nHex String: A\nOctal String: 12\nBinary String: 1010\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/observer-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-observer-pattern','观察者模式 - 设计模式教程','观察者模式是一种行为型设计模式，它定义了一种一对多的依赖关系，当一个对象的状态发生改变时，其所有依赖者都会收到通知并自动更新。 当对象间存在一对多关系时，则使用观察者模式（Observer Pattern）。比如，当一个对象被修改时，则会自...',0,'PUBLISHED',5514,234,155,30,'2025-07-22 00:00:00','2025-07-22 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633022,1,'状态模式','在状态模式（State Pattern）中，类的行为是基于它的状态改变的，这种类型的设计模式属于行为型模式。 在状态模式中，我们创建表示各种状态的对象和一个行为随着状态对象改变而改变的 context 对象。 状态模式允许对象在内部状态改变时改变其行为，使得对象在不同的状态下有不同的行为表现。通过将每个状态封装成独立的类，可以避免使用大量的条件语句来实现状态切换。 允许一个对象在其内部状态改变时改变其行为，看起来就像是改变了其类一样。','# 状态模式\n\n在状态模式（State Pattern）中，类的行为是基于它的状态改变的，这种类型的设计模式属于行为型模式。\n\n在状态模式中，我们创建表示各种状态的对象和一个行为随着状态对象改变而改变的 context 对象。\n\n状态模式允许对象在内部状态改变时改变其行为，使得对象在不同的状态下有不同的行为表现。通过将每个状态封装成独立的类，可以避免使用大量的条件语句来实现状态切换。\n\n### 意图\n\n允许一个对象在其内部状态改变时改变其行为，看起来就像是改变了其类一样。\n\n### 主要解决的问题\n\n- 状态模式解决对象行为依赖于其状态的问题，使得对象可以在状态变化时切换行为。\n\n### 使用场景\n\n- 当代码中存在大量条件语句，且这些条件语句依赖于对象的状态时。\n\n### 实现方式\n\n- 定义状态接口：声明一个或多个方法，用于封装具体状态的行为。\n- 创建具体状态类：实现状态接口，根据状态的不同实现具体的行为。\n- 定义上下文类：包含一个状态对象的引用，并在状态改变时更新其行为。\n\n### 关键代码\n\n- 状态接口：声明行为方法。\n- 具体状态类：实现状态接口，封装具体行为。\n- 上下文类：维护一个状态对象，并提供方法以改变其状态。\n\n### 应用实例\n\n- 篮球运动员状态：运动员可以有正常、不正常和超常等状态。\n- 曾侯乙编钟：编钟作为上下文，不同的钟（状态）有不同的演奏效果。\n\n### 优点\n\n- 封装状态转换规则：将状态转换逻辑封装在状态对象内部。\n- 易于扩展：增加新的状态类不会影响现有代码。\n- 集中状态相关行为：将所有与特定状态相关的行为集中到一个类中。\n- 简化条件语句：避免使用大量的条件语句来切换行为。\n- 状态共享：允许多个上下文对象共享同一个状态对象。\n\n### 缺点\n\n- 增加类和对象数量：每个状态都需要一个具体的状态类。\n- 实现复杂：模式结构和实现相对复杂。\n- 开闭原则支持不足：增加新状态或修改状态行为可能需要修改现有代码。\n\n### 使用建议\n\n- 当对象的行为随状态改变而变化时，考虑使用状态模式。\n- 状态模式适用于替代复杂的条件或分支语句。\n\n### 注意事项\n\n- 状态模式适用于状态数量有限（通常不超过5个）的情况。\n- 谨慎使用，以避免系统变得过于复杂。\n\n### 结构\n\n状态模式包含以下几个主要角色：\n\n- 上下文（Context）：定义了客户感兴趣的接口，并维护一个当前状态对象的引用。上下文可以通过状态对象来委托处理状态相关的行为。\n- 状态（State）：定义了一个接口，用于封装与上下文相关的一个状态的行为。\n- 具体状态（Concrete State）：实现了状态接口，负责处理与该状态相关的行为。具体状态对象通常会在内部维护一个对上下文对象的引用，以便根据不同的条件切换到不同的状态。\n\n我们将创建一个 State 接口和实现了 State 接口的实体状态类。Context 是一个带有某个状态的类。\n\nStatePatternDemo，我们的演示类使用 Context 和状态对象来演示 Context 在状态改变时的行为变化。\n\n![状态模式的 UML 图](/api/uploads/files/runoob/design_pattern/state_pattern_uml_diagram-6d95e5daf0.png)\n\n### 步骤 1\n\n创建一个接口。\n\n## State.java\n\npublic interface State {\npublic void doAction(Context context);\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## StartState.java\n\npublic class StartState implements State {\npublic void doAction(Context context) {\nSystem.out.println("Player is in start state");\n      context.setState(this);\n   }\npublic String toString(){\nreturn "Start State";\n   }\n}\n\n## StopState.java\n\npublic class StopState implements State {\npublic void doAction(Context context) {\nSystem.out.println("Player is in stop state");\n      context.setState(this);\n   }\npublic String toString(){\nreturn "Stop State";\n   }\n}\n\n### 步骤 3\n\n创建 Context 类。\n\n## Context.java\n\npublic class Context {\nprivate State state;\n\n   public Context(){\nstate = null;\n   }\npublic void setState(State state){\nthis.state = state;\n   }\npublic State getState(){\nreturn state;\n   }\n}\n\n### 步骤 4\n\n使用 Context 来查看当状态 State 改变时的行为变化。\n\n## StatePatternDemo.java\n\npublic class StatePatternDemo {\npublic static void main(String[] args) {\nContext context = new Context();\n\n      StartState startState = new StartState();\n      startState.doAction(context);\n\n      System.out.println(context.getState().toString());\n\n      StopState stopState = new StopState();\n      stopState.doAction(context);\n\n      System.out.println(context.getState().toString());\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nPlayer is in start state\nStart State\nPlayer is in stop state\nStop State\n```\n\n## 更多文章\n\n- [策略模式 VS 状态模式](https://www.runoob.com/w3cnote/state-vs-strategy.html)\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/state-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-state-pattern','状态模式 - 设计模式教程','在状态模式（State Pattern）中，类的行为是基于它的状态改变的，这种类型的设计模式属于行为型模式。 在状态模式中，我们创建表示各种状态的对象和一个行为随着状态对象改变而改变的 context 对象。 状态模式允许对象在内部状态改变...',0,'PUBLISHED',5651,241,160,31,'2025-07-23 00:00:00','2025-07-23 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633023,1,'空对象模式','在空对象模式（Null Object Pattern）中，一个空对象取代 NULL 对象实例的检查。Null 对象不是检查空值，而是反应一个不做任何动作的关系。这样的 Null 对象也可以在数据不可用的时候提供默认的行为。 在空对象模式中，我们创建一个指定各种要执行的操作的抽象类和扩展该类的实体类，还创建一个未对该类做任何实现的空对象类，该空对象类将无缝地使用在需要检查空值的地方。 使用一个空对象代替 null 值，这个空对象实现了相同的接口，但对请求不做任何操作或提供默认操作。 1. 避免空值检查：消除了代码中的null值检查。','# 空对象模式\n\n在空对象模式（Null Object Pattern）中，一个空对象取代 NULL 对象实例的检查。Null 对象不是检查空值，而是反应一个不做任何动作的关系。这样的 Null 对象也可以在数据不可用的时候提供默认的行为。\n\n在空对象模式中，我们创建一个指定各种要执行的操作的抽象类和扩展该类的实体类，还创建一个未对该类做任何实现的空对象类，该空对象类将无缝地使用在需要检查空值的地方。\n\n## 概要\n\n### 意图\n\n使用一个空对象代替 null 值，这个空对象实现了相同的接口，但对请求不做任何操作或提供默认操作。\n\n### 主要解决的问题\n\n- 空对象模式解决的是在系统中使用null值可能导致的问题，如NullPointerException异常。\n- 它允许系统在没有合适对象时，使用一个"安全"的空对象继续运行，而不是失败。\n\n### 使用场景\n\n- 当系统中需要处理null对象，但又希望避免null检查或处理null值时。\n\n### 实现方式\n\n- 定义协议：定义一个协议或接口，规定需要实现的行为。\n- 创建具体对象：实现协议的具体对象，提供实际的行为。\n- 创建空对象：也实现相同的协议，但提供"空"的实现，即不执行任何有意义的操作。\n\n### 关键代码\n\n- 协议或接口：规定对象需要实现的方法。\n- 具体对象：实现了协议，包含实际的业务逻辑。\n- 空对象：实现了协议，但方法实现为空或默认行为。\n\n### 应用实例\n\n- 日志系统：在日志系统中，空对象可能代表一个不执行任何操作的日志器。\n- 默认用户：在一个系统中，如果当前没有用户，可以使用一个空用户对象代替null。\n\n### 优点\n\n1. 避免空值检查：消除了代码中的null值检查。\n2. 简化客户端代码：客户端可以无视对象是否为空，直接调用方法。\n3. 扩展性：添加新的具体对象对客户端透明，无需修改现有代码。\n\n### 缺点\n\n- 可能隐藏错误：使用空对象可能隐藏了错误或异常情况，导致难以调试。\n- 增加设计复杂性：需要为每个可能返回null的接口实现一个空对象。\n\n### 使用建议\n\n- 在系统中需要处理null值，但又希望简化错误处理和避免null检查时，考虑使用空对象模式。\n\n### 注意事项\n\n- 空对象模式应该谨慎使用，确保它不会掩盖错误或隐藏系统的真实状态。\n- 空对象应该提供和具体对象相同的接口，使得客户端代码无需改变即可使用。\n\n### 结构\n\n空对象模式包含以下几个主要角色：\n\n- 抽象对象（Abstract Object）：定义了客户端所期望的接口。这个接口可以是一个抽象类或接口。\n- 具体对象（Concrete Object）：实现了抽象对象接口的具体类。这些类提供了真实的行为。\n- 空对象（Null Object）：实现了抽象对象接口的空对象类。这个类提供了默认的无效行为，以便在对象不可用或不可用时使用。它可以作为具体对象的替代者，在客户端代码中代替空值检查。\n\n我们将创建一个定义操作（在这里，是客户的名称）的 AbstractCustomer 抽象类，和扩展了 AbstractCustomer 类的实体类。工厂类 CustomerFactory 基于客户传递的名字来返回 RealCustomer 或 NullCustomer 对象。\n\nNullPatternDemo，我们的演示类使用 CustomerFactory 来演示空对象模式的用法。\n\n![空对象模式的 UML 图](/api/uploads/files/runoob/design_pattern/null_pattern_uml_diagram-a402e1e0d6.jpg)\n\n### 步骤 1\n\n创建一个抽象类。\n\n## AbstractCustomer.java\n\npublic abstract class AbstractCustomer {\nprotected String name;\n   public abstract boolean isNil();\n   public abstract String getName();\n}\n\n### 步骤 2\n\n创建扩展了上述类的实体类。\n\n## RealCustomer.java\n\npublic class RealCustomer extends AbstractCustomer {\npublic RealCustomer(String name) {\nthis.name = name;\n   }\n\n   @Override\npublic String getName() {\nreturn name;\n   }\n\n   @Override\npublic boolean isNil() {\nreturn false;\n   }\n}\n\n## NullCustomer.java\n\npublic class NullCustomer extends AbstractCustomer {\n\n   @Override\npublic String getName() {\nreturn "Not Available in Customer Database";\n   }\n\n   @Override\npublic boolean isNil() {\nreturn true;\n   }\n}\n\n### 步骤 3\n\n创建 CustomerFactory 类。\n\n## CustomerFactory.java\n\npublic class CustomerFactory {\npublic static final String[] names = {"Rob", "Joe", "Julie"};\n\n   public static AbstractCustomer getCustomer(String name){\nfor (int i = 0; i < names.length; i++) {\nif (names[i].equalsIgnoreCase(name)){\nreturn new RealCustomer(name);\n         }\n}\nreturn new NullCustomer();\n   }\n}\n\n### 步骤 4\n\n使用 CustomerFactory，基于客户传递的名字，来获取 RealCustomer 或 NullCustomer 对象。\n\n## NullPatternDemo.java\n\npublic class NullPatternDemo {\npublic static void main(String[] args) {\nAbstractCustomer customer1 = CustomerFactory.getCustomer("Rob");\n      AbstractCustomer customer2 = CustomerFactory.getCustomer("Bob");\n      AbstractCustomer customer3 = CustomerFactory.getCustomer("Julie");\n      AbstractCustomer customer4 = CustomerFactory.getCustomer("Laura");\n\n      System.out.println("Customers");\n      System.out.println(customer1.getName());\n      System.out.println(customer2.getName());\n      System.out.println(customer3.getName());\n      System.out.println(customer4.getName());\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nCustomers\nRob\nNot Available in Customer Database\nJulie\nNot Available in Customer Database\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/null-object-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-null-object-pattern','空对象模式 - 设计模式教程','在空对象模式（Null Object Pattern）中，一个空对象取代 NULL 对象实例的检查。Null 对象不是检查空值，而是反应一个不做任何动作的关系。这样的 Null 对象也可以在数据不可用的时候提供默认的行为。 在空对象模式中，...',0,'PUBLISHED',5788,248,165,32,'2025-07-24 00:00:00','2025-07-24 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633024,1,'策略模式','在策略模式（Strategy Pattern）中一个类的行为或其算法可以在运行时更改。这种类型的设计模式属于行为型模式。 在策略模式定义了一系列算法或策略，并将每个算法封装在独立的类中，使得它们可以互相替换。通过使用策略模式，可以在运行时根据需要选择不同的算法，而不需要修改客户端代码。 在策略模式中，我们创建表示各种策略的对象和一个行为随着策略对象改变而改变的 context 对象。策略对象改变 context 对象的执行算法。 将每个算法封装起来，使它们可以互换使用。','# 策略模式\n\n在策略模式（Strategy Pattern）中一个类的行为或其算法可以在运行时更改。这种类型的设计模式属于行为型模式。\n\n在策略模式定义了一系列算法或策略，并将每个算法封装在独立的类中，使得它们可以互相替换。通过使用策略模式，可以在运行时根据需要选择不同的算法，而不需要修改客户端代码。\n\n在策略模式中，我们创建表示各种策略的对象和一个行为随着策略对象改变而改变的 context 对象。策略对象改变 context 对象的执行算法。\n\n### 意图\n\n将每个算法封装起来，使它们可以互换使用。\n\n### 主要解决的问题\n\n- 解决在多种相似算法存在时，使用条件语句（如if...else）导致的复杂性和难以维护的问题。\n\n### 使用场景\n\n- 当一个系统中有许多类，它们之间的区别仅在于它们的行为时。\n\n### 实现方式\n\n- 定义策略接口：所有策略类都将实现这个统一的接口。\n- 创建具体策略类：每个策略类封装一个具体的算法或行为。\n- 上下文类：包含一个策略对象的引用，并通过该引用调用策略。\n\n### 关键代码\n\n- 策略接口：规定了所有策略类必须实现的方法。\n- 具体策略类：实现了策略接口，包含具体的算法实现。\n\n### 应用实例\n\n1. 锦囊妙计：每个锦囊代表一个策略，包含不同的计策。\n2. 旅行方式选择：骑自行车、坐汽车等，每种方式都是一个可替换的策略。\n3. Java AWT的LayoutManager：不同的布局管理器实现了相同的接口，但提供了不同的布局算法。\n\n### 优点\n\n1. 算法切换自由：可以在运行时根据需要切换算法。\n2. 避免多重条件判断：消除了复杂的条件语句。\n3. 扩展性好：新增算法只需新增一个策略类，无需修改现有代码。\n\n### 缺点\n\n1. 策略类数量增多：每增加一个算法，就需要增加一个策略类。\n2. 所有策略类都需要暴露：策略类需要对外公开，以便可以被选择和使用。\n\n### 使用建议\n\n- 当系统中有多种算法或行为，且它们之间可以相互替换时，使用策略模式。\n- 当系统需要动态选择算法时，策略模式是一个合适的选择。\n\n### 注意事项\n\n- 如果系统中策略类数量过多，考虑使用其他模式或设计技巧来解决类膨胀问题。\n\n### 结构\n\n策略模式包含以下几个核心角色：\n\n- 环境（Context）：维护一个对策略对象的引用，负责将客户端请求委派给具体的策略对象执行。环境类可以通过依赖注入、简单工厂等方式来获取具体策略对象。\n- 抽象策略（Abstract Strategy）：定义了策略对象的公共接口或抽象类，规定了具体策略类必须实现的方法。\n- 具体策略（Concrete Strategy）：实现了抽象策略定义的接口或抽象类，包含了具体的算法实现。\n\n策略模式通过将算法与使用算法的代码解耦，提供了一种动态选择不同算法的方法。客户端代码不需要知道具体的算法细节，而是通过调用环境类来使用所选择的策略。\n\n我们将创建一个定义活动的 Strategy 接口和实现了 Strategy 接口的实体策略类。Context 是一个使用了某种策略的类。\n\nStrategyPatternDemo，我们的演示类使用 Context 和策略对象来演示 Context 在它所配置或使用的策略改变时的行为变化。\n\n![策略模式的 UML 图](/api/uploads/files/runoob/design_pattern/strategy_pattern_uml_diagram-fb8cbe1e08.jpg)\n\n### 步骤 1\n\n创建一个接口。\n\n## Strategy.java\n\npublic interface Strategy {\npublic int doOperation(int num1, int num2);\n}\n\n### 步骤 2\n\n创建实现接口的实体类。\n\n## OperationAdd.java\n\npublic class OperationAdd implements Strategy{\n   @Override\npublic int doOperation(int num1, int num2) {\nreturn num1 + num2;\n   }\n}\n\n## OperationSubtract.java\n\npublic class OperationSubtract implements Strategy{\n   @Override\npublic int doOperation(int num1, int num2) {\nreturn num1 - num2;\n   }\n}\n\n## OperationMultiply.java\n\npublic class OperationMultiply implements Strategy{\n   @Override\npublic int doOperation(int num1, int num2) {\nreturn num1 * num2;\n   }\n}\n\n### 步骤 3\n\n创建 Context 类。\n\n## Context.java\n\npublic class Context {\nprivate Strategy strategy;\n\n   public Context(Strategy strategy){\nthis.strategy = strategy;\n   }\npublic int executeStrategy(int num1, int num2){\nreturn strategy.doOperation(num1, num2);\n   }\n}\n\n### 步骤 4\n\n使用 Context 来查看当它改变策略 Strategy 时的行为变化。\n\n## StrategyPatternDemo.java\n\npublic class StrategyPatternDemo {\npublic static void main(String[] args) {\nContext context = new Context(new OperationAdd());\n      System.out.println("10 + 5 = " + context.executeStrategy(10, 5));\n\n      context = new Context(new OperationSubtract());\n      System.out.println("10 - 5 = " + context.executeStrategy(10, 5));\n\n      context = new Context(new OperationMultiply());\n      System.out.println("10 * 5 = " + context.executeStrategy(10, 5));\n   }\n}\n\n### 步骤 5\n\n执行程序，输出结果：\n\n```text\n\n10 + 5 = 15\n10 - 5 = 5\n10 * 5 = 50\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/strategy-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-strategy-pattern','策略模式 - 设计模式教程','在策略模式（Strategy Pattern）中一个类的行为或其算法可以在运行时更改。这种类型的设计模式属于行为型模式。 在策略模式定义了一系列算法或策略，并将每个算法封装在独立的类中，使得它们可以互相替换。通过使用策略模式，可以在运行时根...',0,'PUBLISHED',5925,255,170,33,'2025-07-25 00:00:00','2025-07-25 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633025,1,'模板模式','在模板模式（Template Pattern）中，一个抽象类公开定义了执行它的方法的方式/模板。它的子类可以按需要重写方法实现，但调用将以抽象类中定义的方式进行。这种类型的设计模式属于行为型模式。 在父类中定义了算法的骨架，并允许子类在不改变算法结构的前提下重定义算法的某些特定步骤。 我们将创建一个定义操作的 Game 抽象类，其中，模板方法设置为 final，这样它就不会被重写。Cricket 和 Football 是扩展了 Game 的实体类，它们重写了抽象类的方法。 TemplatePatternDemo，我们的演示类使用 Game 来演示模板模式的用法。','# 模板模式\n\n在模板模式（Template Pattern）中，一个抽象类公开定义了执行它的方法的方式/模板。它的子类可以按需要重写方法实现，但调用将以抽象类中定义的方式进行。这种类型的设计模式属于行为型模式。\n\n### 意图\n\n在父类中定义了算法的骨架，并允许子类在不改变算法结构的前提下重定义算法的某些特定步骤。\n\n### 主要解决的问题\n\n- 解决在多个子类中重复实现相同的方法的问题，通过将通用方法抽象到父类中来避免代码重复。\n\n### 使用场景\n\n- 当存在一些通用的方法，可以在多个子类中共用时。\n\n### 实现方式\n\n- 定义抽象父类：包含模板方法和一些抽象方法或具体方法。\n- 实现子类：继承抽象父类并实现抽象方法，不改变算法结构。\n\n### 关键代码\n\n- 模板方法：在抽象父类中定义，调用抽象方法和具体方法。\n- 抽象方法：由子类实现，代表算法的可变部分。\n- 具体方法：在抽象父类中实现，代表算法的不变部分。\n\n### 应用实例\n\n- 建筑流程：地基、走线、水管等步骤相同，后期建筑如加壁橱、栅栏等步骤不同。\n- 西游记的81难：菩萨定好的81难代表一个顶层逻辑骨架。\n- Spring对Hibernate的支持：封装了如开启事务、获取Session、关闭Session等通用方法。\n\n### 优点\n\n- 封装不变部分：算法的不变部分被封装在父类中。\n- 扩展可变部分：子类可以扩展或修改算法的可变部分。\n- 提取公共代码：减少代码重复，便于维护。\n\n### 缺点\n\n- 类数目增加：每个不同的实现都需要一个子类，可能导致系统庞大。\n\n### 使用建议\n\n- 当有多个子类共有的方法且逻辑相同时，考虑使用模板方法模式。\n- 对于重要或复杂的方法，可以考虑作为模板方法定义在父类中。\n\n### 注意事项\n\n- 为了防止恶意修改，模板方法通常使用`final`关键字修饰，避免被子类重写。\n\n### 包含的几个主要角色\n\n- 抽象父类（Abstract Class）：\n  - 定义了模板方法和一些抽象方法或具体方法。\n- 具体子类（Concrete Classes）：\n  - 继承自抽象父类，并实现抽象方法。\n- 钩子方法（Hook Method）（可选）：\n  - 在抽象父类中定义，可以被子类重写，以影响模板方法的行为。\n- 客户端（Client）（可选）：\n  - 使用抽象父类和具体子类，无需关心模板方法的细节。\n\n我们将创建一个定义操作的 Game 抽象类，其中，模板方法设置为 final，这样它就不会被重写。Cricket 和 Football 是扩展了 Game 的实体类，它们重写了抽象类的方法。\n\nTemplatePatternDemo，我们的演示类使用 Game 来演示模板模式的用法。\n\n![模板模式的 UML 图](/api/uploads/files/runoob/design_pattern/template_pattern_uml_diagram-612dcff69c.jpg)\n\n### 步骤 1\n\n创建一个抽象类，它的模板方法被设置为 final。\n\n## Game.java\n\npublic abstract class Game {\nabstract void initialize();\n   abstract void startPlay();\n   abstract void endPlay();\n\n   //模板\npublic final void play(){\n//初始化游戏\ninitialize();\n\n      //开始游戏\nstartPlay();\n\n      //结束游戏\nendPlay();\n   }\n}\n\n### 步骤 2\n\n创建扩展了上述类的实体类。\n\n## Cricket.java\n\npublic class Cricket extends Game {\n\n   @Override\nvoid endPlay() {\nSystem.out.println("Cricket Game Finished!");\n   }\n\n   @Override\nvoid initialize() {\nSystem.out.println("Cricket Game Initialized! Start playing.");\n   }\n\n   @Override\nvoid startPlay() {\nSystem.out.println("Cricket Game Started. Enjoy the game!");\n   }\n}\n\n## Football.java\n\npublic class Football extends Game {\n\n   @Override\nvoid endPlay() {\nSystem.out.println("Football Game Finished!");\n   }\n\n   @Override\nvoid initialize() {\nSystem.out.println("Football Game Initialized! Start playing.");\n   }\n\n   @Override\nvoid startPlay() {\nSystem.out.println("Football Game Started. Enjoy the game!");\n   }\n}\n\n### 步骤 3\n\n使用 Game 的模板方法 play() 来演示游戏的定义方式。\n\n## TemplatePatternDemo.java\n\npublic class TemplatePatternDemo {\npublic static void main(String[] args) {\nGame game = new Cricket();\n      game.play();\n      System.out.println();\n      game = new Football();\n      game.play();\n   }\n}\n\n### 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nCricket Game Initialized! Start playing.\nCricket Game Started. Enjoy the game!\nCricket Game Finished!\n\nFootball Game Initialized! Start playing.\nFootball Game Started. Enjoy the game!\nFootball Game Finished!\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/template-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-template-pattern','模板模式 - 设计模式教程','在模板模式（Template Pattern）中，一个抽象类公开定义了执行它的方法的方式/模板。它的子类可以按需要重写方法实现，但调用将以抽象类中定义的方式进行。这种类型的设计模式属于行为型模式。 在父类中定义了算法的骨架，并允许子类在不改...',0,'PUBLISHED',6062,262,175,34,'2025-07-26 00:00:00','2025-07-26 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633026,1,'访问者模式','在访问者模式（Visitor Pattern）中，我们使用了一个访问者类，它改变了元素类的执行算法。通过这种方式，元素的执行算法可以随着访问者改变而改变。这种类型的设计模式属于行为型模式。根据模式，元素对象已接受访问者对象，这样访问者对象就可以处理元素对象上的操作。 旨在将数据结构与在该数据结构上执行的操作分离，从而使得添加新的操作变得更容易，而无需修改数据结构本身。 我们将创建一个定义接受操作的 ComputerPart 接口。Keyboard、Mouse、Monitor 和 Computer 是实现了 ComputerPart 接口的实体类。我们将定义另一个接口 ComputerPartV...','# 访问者模式\n\n在访问者模式（Visitor Pattern）中，我们使用了一个访问者类，它改变了元素类的执行算法。通过这种方式，元素的执行算法可以随着访问者改变而改变。这种类型的设计模式属于行为型模式。根据模式，元素对象已接受访问者对象，这样访问者对象就可以处理元素对象上的操作。\n\n### 意图\n\n旨在将数据结构与在该数据结构上执行的操作分离，从而使得添加新的操作变得更容易，而无需修改数据结构本身。\n\n### 主要解决的问题\n\n- 解决在稳定数据结构和易变操作之间的耦合问题，使得操作可以独立于数据结构变化。\n\n### 使用场景\n\n- 当需要对一个对象结构中的对象执行多种不同的且不相关的操作时，尤其是这些操作需要避免"污染"对象类本身。\n\n### 实现方式\n\n- 定义访问者接口：声明一系列访问方法，一个访问方法对应数据结构中的一个元素类。\n- 创建具体访问者：实现访问者接口，为每个访问方法提供具体实现。\n- 定义元素接口：声明一个接受访问者的方法。\n- 创建具体元素：实现元素接口，每个具体元素类对应数据结构中的一个具体对象。\n\n### 关键代码\n\n- 访问者接口：包含访问不同元素的方法。\n- 具体访问者：实现了访问者接口，包含对每个元素类的访问逻辑。\n- 元素接口：包含一个接受访问者的方法。\n- 具体元素：实现了元素接口，提供给访问者访问的入口。\n\n### 应用实例\n\n- 做客场景：访问者（如您）访问朋友家，朋友作为元素提供信息，访问者根据信息做出判断。\n\n### 优点\n\n- 单一职责原则：访问者模式符合单一职责原则，每个类只负责一项职责。\n- 扩展性：容易为数据结构添加新的操作。\n- 灵活性：访问者可以独立于数据结构变化。\n\n### 缺点\n\n- 违反迪米特原则：元素需要向访问者公开其内部信息。\n- 元素类难以变更：元素类需要维持与访问者的兼容。\n- 依赖具体类：访问者模式依赖于具体类而不是接口，违反了依赖倒置原则。\n\n### 使用建议\n\n- 当对象结构稳定，但需要在其上定义多种新操作时，考虑使用访问者模式。\n- 当需要避免操作"污染"对象类时，使用访问者模式封装操作。\n\n### 注意事项\n\n- 访问者模式可以用于功能统一，如报表生成、用户界面显示、拦截器和过滤器等。\n\n### 包含的几个主要角色\n\n- 访问者（Visitor）：\n  - 定义了访问元素的接口。\n- 具体访问者（Concrete Visitor）：\n  - 实现访问者接口，提供对每个具体元素类的访问和相应操作。\n- 元素（Element）：\n  - 定义了一个接受访问者的方法。\n- 具体元素（Concrete Element）：\n  - 实现元素接口，提供一个`accept`方法，允许访问者访问并操作。\n- 对象结构（Object Structure）（可选）：\n  - 定义了如何组装具体元素，如一个组合类。\n- 客户端（Client）（可选）：\n  - 使用访问者模式对对象结构进行操作。\n\n我们将创建一个定义接受操作的 ComputerPart 接口。Keyboard、Mouse、Monitor 和 Computer 是实现了 ComputerPart 接口的实体类。我们将定义另一个接口 ComputerPartVisitor，它定义了访问者类的操作。Computer 使用实体访问者来执行相应的动作。\n\nVisitorPatternDemo，我们的演示类使用 Computer、ComputerPartVisitor 类来演示访问者模式的用法。\n\n![访问者模式的 UML 图](/api/uploads/files/runoob/design_pattern/visitor_pattern_uml_diagram-ec30d6c9bd.jpg)\n\n### 步骤 1\n\n定义一个表示元素的接口。\n\n## ComputerPart.java\n\npublic interface ComputerPart {\npublic void accept(ComputerPartVisitor computerPartVisitor);\n}\n\n### 步骤 2\n\n创建扩展了上述类的实体类。\n\n## Keyboard.java\n\npublic class Keyboard implements ComputerPart {\n\n   @Override\npublic void accept(ComputerPartVisitor computerPartVisitor) {\ncomputerPartVisitor.visit(this);\n   }\n}\n\n## Monitor.java\n\npublic class Monitor implements ComputerPart {\n\n   @Override\npublic void accept(ComputerPartVisitor computerPartVisitor) {\ncomputerPartVisitor.visit(this);\n   }\n}\n\n## Mouse.java\n\npublic class Mouse implements ComputerPart {\n\n   @Override\npublic void accept(ComputerPartVisitor computerPartVisitor) {\ncomputerPartVisitor.visit(this);\n   }\n}\n\n## Computer.java\n\npublic class Computer implements ComputerPart {\nComputerPart[] parts;\n\n   public Computer(){\nparts = new ComputerPart[] {new Mouse(), new Keyboard(), new Monitor()};\n   }\n\n   @Override\npublic void accept(ComputerPartVisitor computerPartVisitor) {\nfor (int i = 0; i < parts.length; i++) {\nparts[i].accept(computerPartVisitor);\n      }\ncomputerPartVisitor.visit(this);\n   }\n}\n\n### 步骤 3\n\n定义一个表示访问者的接口。\n\n## ComputerPartVisitor.java\n\npublic interface ComputerPartVisitor {\npublic void visit(Computer computer);\n   public void visit(Mouse mouse);\n   public void visit(Keyboard keyboard);\n   public void visit(Monitor monitor);\n}\n\n### 步骤 4\n\n创建实现了上述类的实体访问者。\n\n## ComputerPartDisplayVisitor.java\n\npublic class ComputerPartDisplayVisitor implements ComputerPartVisitor {\n\n   @Override\npublic void visit(Computer computer) {\nSystem.out.println("Displaying Computer.");\n   }\n\n   @Override\npublic void visit(Mouse mouse) {\nSystem.out.println("Displaying Mouse.");\n   }\n\n   @Override\npublic void visit(Keyboard keyboard) {\nSystem.out.println("Displaying Keyboard.");\n   }\n\n   @Override\npublic void visit(Monitor monitor) {\nSystem.out.println("Displaying Monitor.");\n   }\n}\n\n### 步骤 5\n\n使用 ComputerPartDisplayVisitor 来显示 Computer 的组成部分。\n\n## VisitorPatternDemo.java\n\npublic class VisitorPatternDemo {\npublic static void main(String[] args) {\nComputerPart computer = new Computer();\n      computer.accept(new ComputerPartDisplayVisitor());\n   }\n}\n\n### 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nDisplaying Mouse.\nDisplaying Keyboard.\nDisplaying Monitor.\nDisplaying Computer.\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/visitor-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-visitor-pattern','访问者模式 - 设计模式教程','在访问者模式（Visitor Pattern）中，我们使用了一个访问者类，它改变了元素类的执行算法。通过这种方式，元素的执行算法可以随着访问者改变而改变。这种类型的设计模式属于行为型模式。根据模式，元素对象已接受访问者对象，这样访问者对象就...',0,'PUBLISHED',6199,269,180,35,'2025-07-27 00:00:00','2025-07-27 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633027,1,'MVC 模式','MVC 模式代表 Model-View-Controller（模型-视图-控制器） 模式。这种模式用于应用程序的分层开发。 将应用程序分为三个核心组件：模型（Model）、视图（View）和控制器（Controller），以实现关注点分离。 我们将创建一个作为模型的 Student 对象。StudentView 是一个把学生详细信息输出到控制台的视图类，StudentController 是负责存储数据到 Student 对象中的控制器类，并相应地更新视图 StudentView。 MVCPatternDemo，我们的演示类使用 StudentController 来演示 MVC 模式的用法。','# MVC 模式\n\nMVC 模式代表 Model-View-Controller（模型-视图-控制器） 模式。这种模式用于应用程序的分层开发。\n\n- Model（模型） - 模型代表一个存取数据的对象或 JAVA POJO。它也可以带有逻辑，在数据变化时更新控制器。\n- View（视图） - 视图代表模型包含的数据的可视化。\n- Controller（控制器） - 控制器作用于模型和视图上。它控制数据流向模型对象，并在数据变化时更新视图。它使视图与模型分离开。\n\n![图片](/api/uploads/files/runoob/design_pattern/1200px-ModelViewControllerDiagram2.svg-bb72da1cb8.png)\n\n## 概要\n\n### 意图\n\n将应用程序分为三个核心组件：模型（Model）、视图（View）和控制器（Controller），以实现关注点分离。\n\n### 主要解决的问题\n\n- 解决了应用程序中业务逻辑、数据和界面显示的耦合问题，使得开发和维护更加清晰和简单。\n\n### 使用场景\n\n- 当需要将数据、业务逻辑和界面显示分离，以便于独立开发和维护时。\n\n### 实现方式\n\n- 模型（Model）：负责数据和业务逻辑，通常包含数据存储、检索和业务规则。\n- 视图（View）：负责显示数据（模型）的用户界面，不包含业务逻辑。\n- 控制器（Controller）：接收用户的输入，调用模型和视图去完成用户的请求。\n\n### 关键代码\n\n- 模型：包含业务逻辑和数据状态。\n- 视图：包含展示逻辑，将模型的数据渲染为用户界面。\n- 控制器：包含逻辑，用于响应用户输入并更新模型和视图。\n\n### 应用实例\n\n- Web应用程序：用户通过浏览器（视图）发送请求，服务器端的控制器处理请求，模型进行数据处理。\n\n### 优点\n\n- 关注点分离：将数据、业务逻辑和界面显示分离，降低耦合度。\n- 易于维护：每个组件负责特定的任务，便于单独开发和维护。\n- 可扩展性：可以独立地替换或更新模型、视图或控制器。\n\n### 缺点\n\n- 可能增加复杂性：对于简单项目，引入MVC可能会增加不必要的复杂性。\n- 性能问题：如果不正确使用，可能会导致性能问题。\n\n### 使用建议\n\n- 当开发大型应用程序，需要清晰分离数据、业务逻辑和用户界面时，考虑使用MVC模式。\n\n### 注意事项\n\n- 确保模型、视图和控制器之间的交互清晰，避免相互依赖。\n\n### 包含的几个主要角色\n\n- 模型（Model）：\n  - 管理数据和业务逻辑。\n- 视图（View）：\n  - 显示模型中的数据，提供用户界面。\n- 控制器（Controller）：\n  - 接收用户输入，调用模型和视图进行处理。\n- 用户（User）（可选）：\n  - 与视图交互，触发应用程序的流程。\n\n## 实现\n\n我们将创建一个作为模型的 Student 对象。StudentView 是一个把学生详细信息输出到控制台的视图类，StudentController 是负责存储数据到 Student 对象中的控制器类，并相应地更新视图 StudentView。\n\nMVCPatternDemo，我们的演示类使用 StudentController 来演示 MVC 模式的用法。\n\n![MVC 模式的 UML 图](/api/uploads/files/runoob/design_pattern/mvc-3-e74fef0a9f.svg)\n\n## 步骤 1\n\n创建模型。\n\n## Student.java\n\npublic class Student {\nprivate String rollNo;\n   private String name;\n   public String getRollNo() {\nreturn rollNo;\n   }\npublic void setRollNo(String rollNo) {\nthis.rollNo = rollNo;\n   }\npublic String getName() {\nreturn name;\n   }\npublic void setName(String name) {\nthis.name = name;\n   }\n}\n\n## 步骤 2\n\n创建视图。\n\n## StudentView.java\n\npublic class StudentView {\npublic void printStudentDetails(String studentName, String studentRollNo){\nSystem.out.println("Student: ");\n      System.out.println("Name: " + studentName);\n      System.out.println("Roll No: " + studentRollNo);\n   }\n}\n\n## 步骤 3\n\n创建控制器。\n\n## StudentController.java\n\npublic class StudentController {\nprivate Student model;\n   private StudentView view;\n\n   public StudentController(Student model, StudentView view){\nthis.model = model;\n      this.view = view;\n   }\npublic void setStudentName(String name){\nmodel.setName(name);\n   }\npublic String getStudentName(){\nreturn model.getName();\n   }\npublic void setStudentRollNo(String rollNo){\nmodel.setRollNo(rollNo);\n   }\npublic String getStudentRollNo(){\nreturn model.getRollNo();\n   }\npublic void updateView(){\nview.printStudentDetails(model.getName(), model.getRollNo());\n   }\n}\n\n## 步骤 4\n\n使用 StudentController 方法来演示 MVC 设计模式的用法。\n\n## MVCPatternDemo.java\n\npublic class MVCPatternDemo {\npublic static void main(String[] args) {\n//从数据库获取学生记录\nStudent model  = retrieveStudentFromDatabase();\n\n      //创建一个视图：把学生详细信息输出到控制台\nStudentView view = new StudentView();\n\n      StudentController controller = new StudentController(model, view);\n\n      controller.updateView();\n\n      //更新模型数据\ncontroller.setStudentName("John");\n\n      controller.updateView();\n   }\nprivate static Student retrieveStudentFromDatabase(){\nStudent student = new Student();\n      student.setName("Robert");\n      student.setRollNo("10");\n      return student;\n   }\n}\n\n## 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nStudent: \nName: Robert\nRoll No: 10\nStudent: \nName: John\nRoll No: 10\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/mvc-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-mvc-pattern','MVC 模式 - 设计模式教程','MVC 模式代表 Model-View-Controller（模型-视图-控制器） 模式。这种模式用于应用程序的分层开发。 将应用程序分为三个核心组件：模型（Model）、视图（View）和控制器（Controller），以实现关注点分离。...',0,'PUBLISHED',6336,276,185,36,'2025-07-28 00:00:00','2025-07-28 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633028,1,'业务代表模式','业务代表模式（Business Delegate Pattern）用于对表示层和业务层解耦。它基本上是用来减少通信或对表示层代码中的业务层代码的远程查询功能。在业务层中我们有以下实体。 抽象和封装应用程序的访问逻辑，从而为表示层提供对业务逻辑层的访问。 业务代表模式通过提供一个抽象层来访问业务逻辑，有助于保持应用程序的灵活性和可维护性。 我们将创建 Client、BusinessDelegate、BusinessService、LookUpService、JMSService 和 EJBService 来表示业务代表模式中的各种实体。','# 业务代表模式\n\n业务代表模式（Business Delegate Pattern）用于对表示层和业务层解耦。它基本上是用来减少通信或对表示层代码中的业务层代码的远程查询功能。在业务层中我们有以下实体。\n\n- 客户端（Client） - 表示层代码可以是 JSP、servlet 或 UI java 代码。\n- 业务代表（Business Delegate） - 一个为客户端实体提供的入口类，它提供了对业务服务方法的访问。\n- 查询服务（LookUp Service） - 查找服务对象负责获取相关的业务实现，并提供业务对象对业务代表对象的访问。\n- 业务服务（Business Service） - 业务服务接口。实现了该业务服务的实体类，提供了实际的业务实现逻辑。\n\n## 概要\n\n### 意图\n\n抽象和封装应用程序的访问逻辑，从而为表示层提供对业务逻辑层的访问。\n\n### 主要解决的问题\n\n- 解决表示层与业务逻辑层之间的耦合问题，允许表示层通过业务代表间接访问业务逻辑层。\n\n### 使用场景\n\n- 当需要在多层应用程序中清晰地分离表示层和业务逻辑层时。\n\n### 实现方式\n\n- 业务代表接口：定义访问业务逻辑的方法。\n- 业务代表实现：实现业务代表接口，封装调用业务逻辑层的逻辑。\n- 业务服务：业务逻辑层的接口或类，包含业务操作。\n\n### 关键代码\n\n- 业务代表接口：声明访问业务逻辑的方法。\n- 业务代表实现：实现接口，包含调用业务服务的代码。\n- 业务服务：业务逻辑的具体实现。\n\n### 应用实例\n\n- Web应用程序：Web层作为表示层，通过业务代表访问后端服务层。\n\n### 优点\n\n- 表示层与业务逻辑层解耦：业务代表作为中间层，降低耦合度。\n- 集中访问逻辑：简化表示层的代码，将访问逻辑集中在业务代表中。\n- 易于维护和扩展：添加新的业务逻辑访问时，只需修改业务代表。\n\n### 缺点\n\n- 可能增加复杂性：对于简单应用程序，可能增加不必要的抽象层次。\n\n### 使用建议\n\n- 当开发多层应用程序，需要在表示层和业务逻辑层之间提供清晰分离时，考虑使用业务代表模式。\n\n### 注意事项\n\n- 业务代表应该尽量简洁，避免包含复杂的逻辑。\n\n### 包含的几个主要角色\n\n- 业务代表接口（Business Delegate Interface）：\n  - 声明访问业务逻辑的方法。\n- 业务代表实现（Business Delegate Implementation）：\n  - 实现业务代表接口，封装对业务服务的调用。\n- 业务服务（Business Service）：\n  - 业务逻辑层的接口或类，包含实际的业务操作。\n- 表示层（Presentation Layer）：\n  - 应用程序的前端，通过业务代表访问业务逻辑。\n- 业务逻辑层（Business Logic Layer）：\n  - 包含应用程序的核心业务逻辑。\n\n业务代表模式通过提供一个抽象层来访问业务逻辑，有助于保持应用程序的灵活性和可维护性。\n\n## 实现\n\n我们将创建 Client、BusinessDelegate、BusinessService、LookUpService、JMSService 和 EJBService 来表示业务代表模式中的各种实体。\n\nBusinessDelegatePatternDemo 类使用 BusinessDelegate 和 Client 来演示业务代表模式的用法。\n\n![业务代表模式的 UML 图](/api/uploads/files/runoob/design_pattern/business-edae43689f.svg)\n\n## 步骤 1\n\n创建 BusinessService 接口。\n\n## BusinessService.java\n\npublic interface BusinessService {\npublic void doProcessing();\n}\n\n## 步骤 2\n\n创建实体服务类。\n\n## EJBService.java\n\npublic class EJBService implements BusinessService {\n\n   @Override\npublic void doProcessing() {\nSystem.out.println("Processing task by invoking EJB Service");\n   }\n}\n\n## JMSService.java\n\npublic class JMSService implements BusinessService {\n\n   @Override\npublic void doProcessing() {\nSystem.out.println("Processing task by invoking JMS Service");\n   }\n}\n\n## 步骤 3\n\n创建业务查询服务。\n\n## BusinessLookUp.java\n\npublic class BusinessLookUp {\npublic BusinessService getBusinessService(String serviceType){\nif(serviceType.equalsIgnoreCase("EJB")){\nreturn new EJBService();\n      }else {\nreturn new JMSService();\n      }\n}\n}\n\n## 步骤 4\n\n创建业务代表。\n\n## BusinessDelegate.java\n\npublic class BusinessDelegate {\nprivate BusinessLookUp lookupService = new BusinessLookUp();\n   private BusinessService businessService;\n   private String serviceType;\n\n   public void setServiceType(String serviceType){\nthis.serviceType = serviceType;\n   }\npublic void doTask(){\nbusinessService = lookupService.getBusinessService(serviceType);\n      businessService.doProcessing();\n   }\n}\n\n## 步骤 5\n\n创建客户端。\n\n## Client.java\n\npublic class Client {\nBusinessDelegate businessService;\n\n   public Client(BusinessDelegate businessService){\nthis.businessService  = businessService;\n   }\npublic void doTask(){\nbusinessService.doTask();\n   }\n}\n\n## 步骤 6\n\n使用 BusinessDelegate 和 Client 类来演示业务代表模式。\n\n## BusinessDelegatePatternDemo.java\n\npublic class BusinessDelegatePatternDemo {\npublic static void main(String[] args) {\nBusinessDelegate businessDelegate = new BusinessDelegate();\n      businessDelegate.setServiceType("EJB");\n\n      Client client = new Client(businessDelegate);\n      client.doTask();\n\n      businessDelegate.setServiceType("JMS");\n      client.doTask();\n   }\n}\n\n## 步骤 7\n\n执行程序，输出结果：\n\n```text\n\nProcessing task by invoking EJB Service\nProcessing task by invoking JMS Service\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/business-delegate-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-business-delegate-pattern','业务代表模式 - 设计模式教程','业务代表模式（Business Delegate Pattern）用于对表示层和业务层解耦。它基本上是用来减少通信或对表示层代码中的业务层代码的远程查询功能。在业务层中我们有以下实体。 抽象和封装应用程序的访问逻辑，从而为表示层提供对业务逻...',0,'PUBLISHED',6473,283,190,37,'2025-07-29 00:00:00','2025-07-29 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633029,1,'组合实体模式','组合实体模式（Composite Entity Pattern）用在 EJB 持久化机制中。一个组合实体是一个 EJB 实体 bean，代表了对象的图解。当更新一个组合实体时，内部依赖对象 beans 会自动更新，因为它们是由 EJB 实体 bean 管理的。以下是组合实体 bean 的参与者。 将数据库中的表转换为应用程序中的组合对象，这些对象可以表示表中的单个记录或一组记录。 组合实体模式通过将数据库表映射为应用程序中的对象，提供了一种直观和灵活的方式来处理复杂的数据关系。 我们将创建作为组合实体的 CompositeEntity 对象。CoarseGrainedObject 是一个包含依...','# 组合实体模式\n\n组合实体模式（Composite Entity Pattern）用在 EJB 持久化机制中。一个组合实体是一个 EJB 实体 bean，代表了对象的图解。当更新一个组合实体时，内部依赖对象 beans 会自动更新，因为它们是由 EJB 实体 bean 管理的。以下是组合实体 bean 的参与者。\n\n- 组合实体（Composite Entity） - 它是主要的实体 bean。它可以是粗粒的，或者可以包含一个粗粒度对象，用于持续生命周期。\n- 粗粒度对象（Coarse-Grained Object） - 该对象包含依赖对象。它有自己的生命周期，也能管理依赖对象的生命周期。\n- 依赖对象（Dependent Object） - 依赖对象是一个持续生命周期依赖于粗粒度对象的对象。\n- 策略（Strategies） - 策略表示如何实现组合实体。\n\n## 概要\n\n### 意图\n\n将数据库中的表转换为应用程序中的组合对象，这些对象可以表示表中的单个记录或一组记录。\n\n### 主要解决的问题\n\n- 解决在对象关系映射中，如何高效地表示和管理数据库中的复杂数据结构，特别是当存在一对多或多对多关系时。\n\n### 使用场景\n\n- 当数据库表具有复杂的关系，或者需要将数据库表映射为应用程序中的复合对象时。\n\n### 实现方式\n\n- 组合实体类：代表数据库中的表，可以包含单个记录或一组记录。\n- 叶子实体类：代表表中的单个记录。\n- 容器实体类：代表表中的一组记录，可以包含其他叶子或容器实体。\n\n### 关键代码\n\n- 组合实体类：包含方法来添加、删除和访问子实体。\n- 叶子实体类：实现组合实体接口，代表单个记录。\n- 容器实体类：实现组合实体接口，可以包含多个叶子或容器实体。\n\n### 应用实例\n\n- 组织结构：员工可以是叶子节点，表示单个员工；部门可以是容器节点，包含多个员工。\n\n### 优点\n\n- 简化数据访问：通过对象的方式来简化数据库记录的访问和管理。\n- 提高代码可读性：使代码更贴近自然语言，易于理解和维护。\n- 易于扩展：可以方便地添加新的实体类型或修改现有实体。\n\n### 缺点\n\n- 性能问题：在处理大量数据时，可能会遇到性能瓶颈。\n- 复杂性：对于简单的数据模型，可能会增加不必要的复杂性。\n\n### 使用建议\n\n- 当需要表示和管理数据库中的复杂数据结构时，考虑使用组合实体模式。\n\n### 注意事项\n\n- 确保组合实体模式的使用不会引入性能问题，特别是在处理大量数据时。\n\n### 包含的几个主要角色\n\n- 组合实体（Composite Entity）：\n  - 代表数据库中的表，可以包含单个或多个记录。\n- 叶子实体（Leaf Entity）：\n  - 代表表中的单个记录，不包含子实体。\n- 容器实体（Container Entity）：\n  - 代表表中的一组记录，可以包含其他叶子或容器实体。\n- 数据访问对象（Data Access Object）（可选）：\n  - 用于访问和操作数据库，封装了数据访问逻辑。\n- 客户端（Client）（可选）：\n  - 使用组合实体模式来访问和操作数据库记录。\n\n组合实体模式通过将数据库表映射为应用程序中的对象，提供了一种直观和灵活的方式来处理复杂的数据关系。\n\n## 实现\n\n我们将创建作为组合实体的 CompositeEntity 对象。CoarseGrainedObject 是一个包含依赖对象的类。\n\nCompositeEntityPatternDemo，我们的演示类使用 Client 类来演示组合实体模式的用法。\n\n![组合实体模式的 UML 图](/api/uploads/files/runoob/design_pattern/compositeentity_pattern_uml_diagram-b98ce338a6.jpg)\n\n## 步骤 1\n\n创建依赖对象。\n\n## DependentObject1.java\n\npublic class DependentObject1 {\nprivate String data;\n\n   public void setData(String data){\nthis.data = data;\n   }\npublic String getData(){\nreturn data;\n   }\n}\n\n## DependentObject2.java\n\npublic class DependentObject2 {\nprivate String data;\n\n   public void setData(String data){\nthis.data = data;\n   }\npublic String getData(){\nreturn data;\n   }\n}\n\n## 步骤 2\n\n创建粗粒度对象。\n\n## CoarseGrainedObject.java\n\npublic class CoarseGrainedObject {\nDependentObject1 do1 = new DependentObject1();\n   DependentObject2 do2 = new DependentObject2();\n\n   public void setData(String data1, String data2){\ndo1.setData(data1);\n      do2.setData(data2);\n   }\npublic String[] getData(){\nreturn new String[] {do1.getData(),do2.getData()};\n   }\n}\n\n## 步骤 3\n\n创建组合实体。\n\n## CompositeEntity.java\n\npublic class CompositeEntity {\nprivate CoarseGrainedObject cgo = new CoarseGrainedObject();\n\n   public void setData(String data1, String data2){\ncgo.setData(data1, data2);\n   }\npublic String[] getData(){\nreturn cgo.getData();\n   }\n}\n\n## 步骤 4\n\n创建使用组合实体的客户端类。\n\n## Client.java\n\npublic class Client {\nprivate CompositeEntity compositeEntity = new CompositeEntity();\n\n   public void printData(){\nfor (int i = 0; i < compositeEntity.getData().length; i++) {\nSystem.out.println("Data: " + compositeEntity.getData()[i]);\n      }\n}\npublic void setData(String data1, String data2){\ncompositeEntity.setData(data1, data2);\n   }\n}\n\n## 步骤 5\n\n使用 Client 来演示组合实体设计模式的用法。\n\n## CompositeEntityPatternDemo.java\n\npublic class CompositeEntityPatternDemo {\npublic static void main(String[] args) {\nClient client = new Client();\n       client.setData("Test", "Data");\n       client.printData();\n       client.setData("Second Test", "Data1");\n       client.printData();\n   }\n}\n\n## 步骤 6\n\n执行程序，输出结果：\n\n```text\n\nData: Test\nData: Data\nData: Second Test\nData: Data1\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/composite-entity-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-composite-entity-pattern','组合实体模式 - 设计模式教程','组合实体模式（Composite Entity Pattern）用在 EJB 持久化机制中。一个组合实体是一个 EJB 实体 bean，代表了对象的图解。当更新一个组合实体时，内部依赖对象 beans 会自动更新，因为它们是由 EJB 实体...',0,'PUBLISHED',6610,290,195,38,'2025-07-30 00:00:00','2025-07-30 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633030,1,'数据访问对象模式','数据访问对象模式（Data Access Object Pattern）或 DAO 模式用于把低级的数据访问 API 或操作从高级的业务服务中分离出来。以下是数据访问对象模式的参与者。 将数据访问逻辑从业务逻辑中分离出来，并将数据访问操作封装在一个专用的类中。 1. 分离关注点：将数据访问逻辑与业务逻辑分离，降低系统的耦合度。 2. 易于维护：数据访问逻辑集中管理，便于维护和更新。','# 数据访问对象模式\n\n数据访问对象模式（Data Access Object Pattern）或 DAO 模式用于把低级的数据访问 API 或操作从高级的业务服务中分离出来。以下是数据访问对象模式的参与者。\n\n- 数据访问对象接口（Data Access Object Interface） - 该接口定义了在一个模型对象上要执行的标准操作。\n- 数据访问对象实体类（Data Access Object concrete class） - 该类实现了上述的接口。该类负责从数据源获取数据，数据源可以是数据库，也可以是 xml，或者是其他的存储机制。\n- 模型对象/数值对象（Model Object/Value Object） - 该对象是简单的 POJO，包含了 get/set 方法来存储通过使用 DAO 类检索到的数据。\n\n## 概要\n\n### 意图\n\n将数据访问逻辑从业务逻辑中分离出来，并将数据访问操作封装在一个专用的类中。\n\n### 主要解决的问题\n\n- 解决业务逻辑与数据访问逻辑紧密耦合的问题，提高代码的可维护性和可重用性。\n\n### 使用场景\n\n- 当需要将应用程序的数据访问逻辑集中管理，以便简化业务逻辑并易于进行数据操作时。\n\n### 实现方式\n\n- 定义DAO接口：声明数据访问操作的方法。\n- 实现DAO类：实现DAO接口，封装对数据源（如数据库）的所有访问逻辑。\n- 数据传输对象（DTO）：可选，用于封装从数据源检索的数据。\n\n### 关键代码\n\n- DAO接口：声明数据访问和操作的方法。\n- DAO实现：提供DAO接口的具体实现，包含对数据库的访问代码。\n\n### 应用实例\n\n- 用户管理应用：用户DAO类负责与数据库交互，管理用户数据的增删改查。\n\n### 优点\n\n1. 分离关注点：将数据访问逻辑与业务逻辑分离，降低系统的耦合度。\n2. 易于维护：数据访问逻辑集中管理，便于维护和更新。\n3. 可扩展性：更换数据源或修改数据访问逻辑时，不影响业务逻辑层。\n\n### 缺点\n\n- 可能增加复杂性：对于简单的应用程序，引入DAO模式可能增加额外的抽象层次。\n\n### 使用建议\n\n- 当应用程序需要与多种数据源交互，或者数据访问逻辑较为复杂时，使用DAO模式。\n\n### 注意事项\n\n- DAO类应该尽量简单，只包含数据访问逻辑，不包含业务逻辑。\n\n### 包含的几个主要角色\n\n1. DAO接口（DAO Interface）：\n  - 声明数据访问和操作的方法。\n2. DAO实现（DAO Implementation）：\n  - 实现DAO接口，封装对数据源的所有访问逻辑。\n3. 数据传输对象（Data Transfer Object, DTO）（可选）：\n  - 封装从数据源检索的数据，用于业务逻辑层与数据访问层之间的数据传输。\n4. 业务逻辑层（Business Logic Layer）：\n  - 使用DAO接口与数据源交互，不直接依赖于数据访问的具体实现。\n5. 数据源（Data Source）：\n  - 数据库或其他持久化存储，DAO实现与之交互以存取数据。\n\n数据访问对象模式通过提供一个清晰的数据访问层，有助于保持应用程序的整洁和可管理性。\n\n## 实现\n\n我们将创建一个作为模型对象或数值对象的 Student 对象。StudentDao 是数据访问对象接口。StudentDaoImpl 是实现了数据访问对象接口的实体类。DaoPatternDemo，我们的演示类使用 StudentDao 来演示数据访问对象模式的用法。\n\n![数据访问对象模式的 UML 图](/api/uploads/files/runoob/design_pattern/dao_pattern_uml_diagram-989171e1db.jpg)\n\n## 步骤 1\n\n创建数值对象。\n\n## Student.java\n\npublic class Student {\nprivate String name;\n   private int rollNo;\n\n   Student(String name, int rollNo){\nthis.name = name;\n      this.rollNo = rollNo;\n   }\npublic String getName() {\nreturn name;\n   }\npublic void setName(String name) {\nthis.name = name;\n   }\npublic int getRollNo() {\nreturn rollNo;\n   }\npublic void setRollNo(int rollNo) {\nthis.rollNo = rollNo;\n   }\n}\n\n## 步骤 2\n\n创建数据访问对象接口。\n\n## StudentDao.java\n\nimport java.util.List;\n\npublic interface StudentDao {\npublic List<Student> getAllStudents();\n   public Student getStudent(int rollNo);\n   public void updateStudent(Student student);\n   public void deleteStudent(Student student);\n}\n\n## 步骤 3\n\n创建实现了上述接口的实体类。\n\n## StudentDaoImpl.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class StudentDaoImpl implements StudentDao {\n//列表是当作一个数据库\nList<Student> students;\n\n   public StudentDaoImpl(){\nstudents = new ArrayList<Student>();\n      Student student1 = new Student("Robert",0);\n      Student student2 = new Student("John",1);\n      students.add(student1);\n      students.add(student2);\n   }\n   @Override\npublic void deleteStudent(Student student) {\nstudents.remove(student.getRollNo());\n      System.out.println("Student: Roll No " + student.getRollNo()\n         +", deleted from database");\n   }\n//从数据库中检索学生名单\n   @Override\npublic List<Student> getAllStudents() {\nreturn students;\n   }\n\n   @Override\npublic Student getStudent(int rollNo) {\nreturn students.get(rollNo);\n   }\n\n   @Override\npublic void updateStudent(Student student) {\nstudents.get(student.getRollNo()).setName(student.getName());\n      System.out.println("Student: Roll No " + student.getRollNo()\n         +", updated in the database");\n   }\n}\n\n## 步骤 4\n\n使用 StudentDao 来演示数据访问对象模式的用法。\n\n## DaoPatternDemo.java\n\npublic class DaoPatternDemo {\npublic static void main(String[] args) {\nStudentDao studentDao = new StudentDaoImpl();\n\n      //输出所有的学生\nfor (Student student : studentDao.getAllStudents()) {\nSystem.out.println("Student: [RollNo : "\n            +student.getRollNo()+", Name : "+student.getName()+" ]");\n      }\n//更新学生\nStudent student =studentDao.getAllStudents().get(0);\n      student.setName("Michael");\n      studentDao.updateStudent(student);\n\n      //获取学生\nstudentDao.getStudent(0);\n      System.out.println("Student: [RollNo : "\n         +student.getRollNo()+", Name : "+student.getName()+" ]");\n   }\n}\n\n## 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nStudent: [RollNo : 0, Name : Robert ]\nStudent: [RollNo : 1, Name : John ]\nStudent: Roll No 0, updated in the database\nStudent: [RollNo : 0, Name : Michael ]\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/data-access-object-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-data-access-object-pattern','数据访问对象模式 - 设计模式教程','数据访问对象模式（Data Access Object Pattern）或 DAO 模式用于把低级的数据访问 API 或操作从高级的业务服务中分离出来。以下是数据访问对象模式的参与者。 将数据访问逻辑从业务逻辑中分离出来，并将数据访问操作封...',0,'PUBLISHED',6747,297,200,39,'2025-07-31 00:00:00','2025-07-31 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633031,1,'前端控制器模式','前端控制器模式（Front Controller Pattern）是用来提供一个集中的请求处理机制，所有的请求都将由一个单一的处理程序处理。该处理程序可以做认证/授权/记录日志，或者跟踪请求，然后把请求传给相应的处理程序。以下是这种设计模式的实体。 使用一个中心控制器（或处理器）来转发客户端请求到适当的处理程序。 1. 集中请求处理：简化请求处理流程，易于管理和维护。 2. 减少代码重复：通过重用控制器减少视图和处理程序中的重复代码。','# 前端控制器模式\n\n前端控制器模式（Front Controller Pattern）是用来提供一个集中的请求处理机制，所有的请求都将由一个单一的处理程序处理。该处理程序可以做认证/授权/记录日志，或者跟踪请求，然后把请求传给相应的处理程序。以下是这种设计模式的实体。\n\n- 前端控制器（Front Controller） - 处理应用程序所有类型请求的单个处理程序，应用程序可以是基于 web 的应用程序，也可以是基于桌面的应用程序。\n- 调度器（Dispatcher） - 前端控制器可能使用一个调度器对象来调度请求到相应的具体处理程序。\n- 视图（View） - 视图是为请求而创建的对象。\n\n## 概要\n\n### 意图\n\n使用一个中心控制器（或处理器）来转发客户端请求到适当的处理程序。\n\n### 主要解决的问题\n\n- 解决Web应用程序中请求处理分散的问题，提供统一的请求处理入口。\n\n### 使用场景\n\n- 当需要对Web应用程序中的请求进行统一管理和分发时。\n\n### 实现方式\n\n- 前端控制器：作为请求的单一入口点，负责请求的接收和转发。\n- 视图：用于呈现处理结果。\n- 处理程序：实际执行请求处理的组件。\n\n### 关键代码\n\n- 前端控制器：包含逻辑以决定将请求转发到哪个处理程序。\n- 处理程序映射：将请求映射到相应的处理程序。\n\n### 应用实例\n\n- Web框架：如Spring MVC中的DispatcherServlet，作为前端控制器。\n\n### 优点\n\n1. 集中请求处理：简化请求处理流程，易于管理和维护。\n2. 减少代码重复：通过重用控制器减少视图和处理程序中的重复代码。\n3. 易于扩展：新增请求处理逻辑时，只需添加新的处理程序。\n\n### 缺点\n\n- 可能成为性能瓶颈：所有请求都通过前端控制器，可能影响性能。\n\n### 使用建议\n\n- 当需要构建一个具有清晰请求处理流程的Web应用程序时，考虑使用前端控制器模式。\n\n### 注意事项\n\n- 确保前端控制器不会由于集中处理所有请求而成为性能瓶颈。\n\n### 包含的几个主要角色\n\n1. 前端控制器（Front Controller）：\n  - 作为请求的单一入口点，负责接收请求并决定如何处理。\n2. 处理程序（Handler）：\n  - 实际执行请求处理的组件。\n3. 视图（View）：\n  - 用于呈现处理程序生成的响应。\n4. 处理程序映射（Handler Mapping）（可选）：\n  - 将请求映射到相应的处理程序。\n5. 客户端（Client）（可选）：\n  - 发出请求的Web浏览器或API客户端。\n\n前端控制器模式通过提供一个集中的请求处理机制，有助于构建易于维护和扩展的Web应用程序。\n\n## 实现\n\n我们将创建 FrontController、Dispatcher 分别当作前端控制器和调度器。HomeView 和 StudentView 表示各种为前端控制器接收到的请求而创建的视图。\n\nFrontControllerPatternDemo，我们的演示类使用 FrontController 来演示前端控制器设计模式。\n\n![前端控制器模式的 UML 图](/api/uploads/files/runoob/design_pattern/frontcontroller_pattern_uml_diagram-df1d22f5db.jpg)\n\n## 步骤 1\n\n创建视图。\n\n## HomeView.java\n\npublic class HomeView {\npublic void show(){\nSystem.out.println("Displaying Home Page");\n   }\n}\n\n## StudentView.java\n\npublic class StudentView {\npublic void show(){\nSystem.out.println("Displaying Student Page");\n   }\n}\n\n## 步骤 2\n\n创建调度器 Dispatcher。\n\n## Dispatcher.java\n\npublic class Dispatcher {\nprivate StudentView studentView;\n   private HomeView homeView;\n   public Dispatcher(){\nstudentView = new StudentView();\n      homeView = new HomeView();\n   }\npublic void dispatch(String request){\nif(request.equalsIgnoreCase("STUDENT")){\nstudentView.show();\n      }else{\nhomeView.show();\n      }\n}\n}\n\n## 步骤 3\n\n创建前端控制器 FrontController。\n\n## FrontController.java\n\npublic class FrontController {\nprivate Dispatcher dispatcher;\n\n   public FrontController(){\ndispatcher = new Dispatcher();\n   }\nprivate boolean isAuthenticUser(){\nSystem.out.println("User is authenticated successfully.");\n      return true;\n   }\nprivate void trackRequest(String request){\nSystem.out.println("Page requested: " + request);\n   }\npublic void dispatchRequest(String request){\n//记录每一个请求\ntrackRequest(request);\n      //对用户进行身份验证\nif(isAuthenticUser()){\ndispatcher.dispatch(request);\n      }\n}\n}\n\n## 步骤 4\n\n使用 FrontController 来演示前端控制器设计模式。\n\n## FrontControllerPatternDemo.java\n\npublic class FrontControllerPatternDemo {\npublic static void main(String[] args) {\nFrontController frontController = new FrontController();\n      frontController.dispatchRequest("HOME");\n      frontController.dispatchRequest("STUDENT");\n   }\n}\n\n## 步骤 5\n\n执行程序，输出结果：\n\n```text\n\nPage requested: HOME\nUser is authenticated successfully.\nDisplaying Home Page\nPage requested: STUDENT\nUser is authenticated successfully.\nDisplaying Student Page\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/front-controller-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-front-controller-pattern','前端控制器模式 - 设计模式教程','前端控制器模式（Front Controller Pattern）是用来提供一个集中的请求处理机制，所有的请求都将由一个单一的处理程序处理。该处理程序可以做认证/授权/记录日志，或者跟踪请求，然后把请求传给相应的处理程序。以下是这种设计模式...',0,'PUBLISHED',6884,304,205,40,'2025-08-01 00:00:00','2025-08-01 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633032,1,'拦截过滤器模式','拦截过滤器模式（Intercepting Filter Pattern）用于对应用程序的请求或响应做一些预处理/后处理。定义过滤器，并在把请求传给实际目标应用程序之前应用在请求上。过滤器可以做认证/授权/记录日志，或者跟踪请求，然后把请求传给相应的处理程序。以下是这种设计模式的实体。 用于在请求到达最终目的地之前，通过一系列过滤器对请求进行预处理和后处理。 1. 职责分离：将通用操作与业务逻辑分离，提高代码的可维护性。 2. 可扩展性：可以灵活地添加、删除或修改过滤器。','# 拦截过滤器模式\n\n拦截过滤器模式（Intercepting Filter Pattern）用于对应用程序的请求或响应做一些预处理/后处理。定义过滤器，并在把请求传给实际目标应用程序之前应用在请求上。过滤器可以做认证/授权/记录日志，或者跟踪请求，然后把请求传给相应的处理程序。以下是这种设计模式的实体。\n\n- 过滤器（Filter） - 过滤器在请求处理程序执行请求之前或之后，执行某些任务。\n- 过滤器链（Filter Chain） - 过滤器链带有多个过滤器，并在 Target 上按照定义的顺序执行这些过滤器。\n- Target - Target 对象是请求处理程序。\n- 过滤管理器（Filter Manager） - 过滤管理器管理过滤器和过滤器链。\n- 客户端（Client） - Client 是向 Target 对象发送请求的对象。\n\n## 概要\n\n### 意图\n\n用于在请求到达最终目的地之前，通过一系列过滤器对请求进行预处理和后处理。\n\n### 主要解决的问题\n\n- 解决Web应用程序中需要在请求处理前后执行通用操作（如日志记录、安全检查、事务管理等）的问题。\n\n### 使用场景\n\n- 当需要在请求处理流程中插入额外的逻辑，而这些逻辑与业务逻辑无关时。\n\n### 实现方式\n\n- 过滤器链：一系列过滤器按照特定顺序执行。\n- 过滤器：对请求和响应进行预处理和后处理的组件。\n- 目标对象：请求处理的最终目的地。\n\n### 关键代码\n\n- 过滤器接口：定义了过滤器必须实现的方法，如`before()`和`after()`。\n- 具体过滤器：实现过滤器接口，包含具体的处理逻辑。\n- 过滤器管理器：负责过滤器链的维护和过滤器的调用顺序。\n\n### 应用实例\n\n- Web应用服务器：如Tomcat使用过滤器进行请求的拦截处理，例如权限检查、日志记录等。\n\n### 优点\n\n1. 职责分离：将通用操作与业务逻辑分离，提高代码的可维护性。\n2. 可扩展性：可以灵活地添加、删除或修改过滤器。\n3. 复用性：过滤器可以在不同的请求处理中重用。\n\n### 缺点\n\n- 性能影响：如果过滤器链过长或过滤器执行的操作复杂，可能会影响性能。\n\n### 使用建议\n\n- 当需要在请求处理流程中插入与业务逻辑无关的通用操作时，考虑使用拦截过滤器模式。\n\n### 注意事项\n\n- 确保过滤器的执行顺序符合预期，以避免逻辑错误。\n\n### 包含的几个主要角色\n\n1. 过滤器接口（Filter Interface）：\n  - 定义了过滤器必须实现的方法。\n2. 具体过滤器（Concrete Filter）：\n  - 实现过滤器接口，包含具体的处理逻辑。\n3. 过滤器管理器（Filter Manager）：\n  - 负责维护过滤器链和调用过滤器。\n4. 目标对象（Target）：\n  - 请求处理的最终目的地，业务逻辑的实现。\n5. 客户端（Client）（可选）：\n  - 发出请求的Web浏览器或API客户端。\n\n拦截过滤器模式通过在请求处理流程中插入通用操作，有助于保持业务逻辑的清晰和专注。\n\n## 实现\n\n我们将创建 FilterChain、FilterManager、Target、Client 作为表示实体的各种对象。AuthenticationFilter 和 DebugFilter 表示实体过滤器。\n\nInterceptingFilterDemo 类使用 Client 来演示拦截过滤器设计模式。\n\n![拦截过滤器模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201015-intercepting-e4c66b7f24.svg)\n\n## 步骤 1\n\n创建过滤器接口 Filter。\n\n## Filter.java\n\npublic interface Filter {\npublic void execute(String request);\n}\n\n## 步骤 2\n\n创建实体过滤器。\n\n## AuthenticationFilter.java\n\npublic class AuthenticationFilter implements Filter {\npublic void execute(String request){\nSystem.out.println("Authenticating request: " + request);\n   }\n}\n\n## DebugFilter.java\n\npublic class DebugFilter implements Filter {\npublic void execute(String request){\nSystem.out.println("request log: " + request);\n   }\n}\n\n## 步骤 3\n\n创建 Target。\n\n## Target.java\n\npublic class Target {\npublic void execute(String request){\nSystem.out.println("Executing request: " + request);\n   }\n}\n\n## 步骤 4\n\n创建过滤器链。\n\n## FilterChain.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class FilterChain {\nprivate List<Filter> filters = new ArrayList<Filter>();\n   private Target target;\n\n   public void addFilter(Filter filter){\nfilters.add(filter);\n   }\npublic void execute(String request){\nfor (Filter filter : filters) {\nfilter.execute(request);\n      }\ntarget.execute(request);\n   }\npublic void setTarget(Target target){\nthis.target = target;\n   }\n}\n\n## 步骤 5\n\n创建过滤管理器。\n\n## FilterManager.java\n\npublic class FilterManager {\nFilterChain filterChain;\n\n   public FilterManager(Target target){\nfilterChain = new FilterChain();\n      filterChain.setTarget(target);\n   }\npublic void setFilter(Filter filter){\nfilterChain.addFilter(filter);\n   }\npublic void filterRequest(String request){\nfilterChain.execute(request);\n   }\n}\n\n## 步骤 6\n\n创建客户端 Client。\n\n## Client.java\n\npublic class Client {\nFilterManager filterManager;\n\n   public void setFilterManager(FilterManager filterManager){\nthis.filterManager = filterManager;\n   }\npublic void sendRequest(String request){\nfilterManager.filterRequest(request);\n   }\n}\n\n## 步骤 7\n\n使用 Client 来演示拦截过滤器设计模式。\n\n## InterceptingFilterDemo.java\n\npublic class InterceptingFilterDemo {\npublic static void main(String[] args) {\nFilterManager filterManager = new FilterManager(new Target());\n      filterManager.setFilter(new AuthenticationFilter());\n      filterManager.setFilter(new DebugFilter());\n\n      Client client = new Client();\n      client.setFilterManager(filterManager);\n      client.sendRequest("HOME");\n   }\n}\n\n## 步骤 8\n\n执行程序，输出结果：\n\n```text\n\nAuthenticating request: HOME\nrequest log: HOME\nExecuting request: HOME\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/intercepting-filter-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-intercepting-filter-pattern','拦截过滤器模式 - 设计模式教程','拦截过滤器模式（Intercepting Filter Pattern）用于对应用程序的请求或响应做一些预处理/后处理。定义过滤器，并在把请求传给实际目标应用程序之前应用在请求上。过滤器可以做认证/授权/记录日志，或者跟踪请求，然后把请求传...',0,'PUBLISHED',7021,311,210,41,'2025-08-02 00:00:00','2025-08-02 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633033,1,'服务定位器模式','服务定位器模式（Service Locator Pattern）用在我们想使用 JNDI 查询定位各种服务的时候。考虑到为某个服务查找 JNDI 的代价很高，服务定位器模式充分利用了缓存技术。在首次请求某个服务时，服务定位器在 JNDI 中查找服务，并缓存该服务对象。当再次请求相同的服务时，服务定位器会在它的缓存中查找，这样可以在很大程度上提高应用程序的性能。以下是这种设计模式的实体。 用于在应用程序中提供一个中心化的服务访问点，用以获取各种服务或资源。 1. 解耦服务访问：将服务访问逻辑与使用服务的业务逻辑分离。 2. 集中管理：服务的访问点集中管理，便于维护和扩展。','# 服务定位器模式\n\n服务定位器模式（Service Locator Pattern）用在我们想使用 JNDI 查询定位各种服务的时候。考虑到为某个服务查找 JNDI 的代价很高，服务定位器模式充分利用了缓存技术。在首次请求某个服务时，服务定位器在 JNDI 中查找服务，并缓存该服务对象。当再次请求相同的服务时，服务定位器会在它的缓存中查找，这样可以在很大程度上提高应用程序的性能。以下是这种设计模式的实体。\n\n- 服务（Service） - 实际处理请求的服务。对这种服务的引用可以在 JNDI 服务器中查找到。\n- Context / 初始的 Context - JNDI Context 带有对要查找的服务的引用。\n- 服务定位器（Service Locator） - 服务定位器是通过 JNDI 查找和缓存服务来获取服务的单点接触。\n- 缓存（Cache） - 缓存存储服务的引用，以便复用它们。\n- 客户端（Client） - Client 是通过 ServiceLocator 调用服务的对象。\n\n## 概要\n\n### 意图\n\n用于在应用程序中提供一个中心化的服务访问点，用以获取各种服务或资源。\n\n### 主要解决的问题\n\n- 解决在应用程序中需要访问各种服务或资源时，避免硬编码服务访问逻辑的问题。\n\n### 使用场景\n\n- 当应用程序需要访问多个外部服务或资源，并且希望将这些访问逻辑集中管理时。\n\n### 实现方式\n\n- 服务定位器接口：定义获取服务的方法。\n- 服务定位器实现：实现服务定位器接口，封装服务的查找和访问逻辑。\n- 服务接口：定义服务的接口或契约。\n- 具体服务：实现服务接口，提供具体的服务功能。\n\n### 关键代码\n\n- 服务定位器：包含逻辑以查找和返回请求的服务实例。\n- 服务接口：定义服务的抽象表示。\n\n### 应用实例\n\n- 企业应用程序：应用程序使用服务定位器来访问数据库服务、消息队列服务等。\n\n### 优点\n\n1. 解耦服务访问：将服务访问逻辑与使用服务的业务逻辑分离。\n2. 集中管理：服务的访问点集中管理，便于维护和扩展。\n3. 灵活性：易于添加、修改或替换服务。\n\n### 缺点\n\n- 性能问题：服务定位器可能引入性能开销，特别是在每次服务请求都进行查找时。\n- 过度使用：可能导致设计模式的滥用，从而隐藏系统结构。\n\n### 使用建议\n\n- 当应用程序需要以一种灵活且可维护的方式访问多个服务时，考虑使用服务定位器模式。\n\n### 注意事项\n\n- 避免过度依赖服务定位器，因为它可能掩盖系统的依赖关系，使得调试和优化变得困难。\n\n### 包含的几个主要角色\n\n1. 服务定位器接口（Service Locator Interface）：\n  - 定义获取服务的方法。\n2. 服务定位器实现（Service Locator Implementation）：\n  - 实现服务定位器接口，封装服务的查找和访问逻辑。\n3. 服务接口（Service Interface）：\n  - 定义服务的抽象表示。\n4. 具体服务（Concrete Service）：\n  - 实现服务接口，提供具体的服务功能。\n5. 客户端（Client）：\n  - 使用服务定位器来访问所需的服务。\n\n服务定位器模式通过提供一个集中的服务访问点，有助于简化服务访问逻辑，并提高应用程序的灵活性和可维护性。\n\n<\n\n## 实现\n\n我们将创建 ServiceLocator、InitialContext、Cache、Service 作为表示实体的各种对象。Service1 和 Service2 表示实体服务。\n\nServiceLocatorPatternDemo 类在这里是作为一个客户端，将使用 ServiceLocator 来演示服务定位器设计模式。\n\n![服务定位器模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201015-service-locator-3b29877ecd.svg)\n\n## 步骤 1\n\n创建服务接口 Service。\n\n## Service.java\n\npublic interface Service {\npublic String getName();\n   public void execute();\n}\n\n## 步骤 2\n\n创建实体服务。\n\n## Service1.java\n\npublic class Service1 implements Service {\npublic void execute(){\nSystem.out.println("Executing Service1");\n   }\n\n   @Override\npublic String getName() {\nreturn "Service1";\n   }\n}\n\n## Service2.java\n\npublic class Service2 implements Service {\npublic void execute(){\nSystem.out.println("Executing Service2");\n   }\n\n   @Override\npublic String getName() {\nreturn "Service2";\n   }\n}\n\n## 步骤 3\n\n为 JNDI 查询创建 InitialContext。\n\n## InitialContext.java\n\npublic class InitialContext {\npublic Object lookup(String jndiName){\nif(jndiName.equalsIgnoreCase("SERVICE1")){\nSystem.out.println("Looking up and creating a new Service1 object");\n         return new Service1();\n      }else if (jndiName.equalsIgnoreCase("SERVICE2")){\nSystem.out.println("Looking up and creating a new Service2 object");\n         return new Service2();\n      }\nreturn null;\n   }\n}\n\n## 步骤 4\n\n创建缓存 Cache。\n\n## Cache.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Cache {\nprivate List<Service> services;\n\n   public Cache(){\nservices = new ArrayList<Service>();\n   }\npublic Service getService(String serviceName){\nfor (Service service : services) {\nif(service.getName().equalsIgnoreCase(serviceName)){\nSystem.out.println("Returning cached  "+serviceName+" object");\n            return service;\n         }\n}\nreturn null;\n   }\npublic void addService(Service newService){\nboolean exists = false;\n      for (Service service : services) {\nif(service.getName().equalsIgnoreCase(newService.getName())){\nexists = true;\n         }\n}\nif(!exists){\nservices.add(newService);\n      }\n}\n}\n\n## 步骤 5\n\n创建服务定位器。\n\n## ServiceLocator.java\n\npublic class ServiceLocator {\nprivate static Cache cache;\n\n   static {\ncache = new Cache();\n   }\npublic static Service getService(String jndiName){\nService service = cache.getService(jndiName);\n\n      if(service != null){\nreturn service;\n      }\nInitialContext context = new InitialContext();\n      Service service1 = (Service)context.lookup(jndiName);\n      cache.addService(service1);\n      return service1;\n   }\n}\n\n## 步骤 6\n\n使用 ServiceLocator 来演示服务定位器设计模式。\n\n## ServiceLocatorPatternDemo.java\n\npublic class ServiceLocatorPatternDemo {\npublic static void main(String[] args) {\nService service = ServiceLocator.getService("Service1");\n      service.execute();\n      service = ServiceLocator.getService("Service2");\n      service.execute();\n      service = ServiceLocator.getService("Service1");\n      service.execute();\n      service = ServiceLocator.getService("Service2");\n      service.execute();\n   }\n}\n\n## 步骤 7\n\n执行程序，输出结果：\n\n```text\n\nLooking up and creating a new Service1 object\nExecuting Service1\nLooking up and creating a new Service2 object\nExecuting Service2\nReturning cached  Service1 object\nExecuting Service1\nReturning cached  Service2 object\nExecuting Service2\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/service-locator-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-service-locator-pattern','服务定位器模式 - 设计模式教程','服务定位器模式（Service Locator Pattern）用在我们想使用 JNDI 查询定位各种服务的时候。考虑到为某个服务查找 JNDI 的代价很高，服务定位器模式充分利用了缓存技术。在首次请求某个服务时，服务定位器在 JNDI 中...',0,'PUBLISHED',7158,318,215,42,'2025-08-03 00:00:00','2025-08-03 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633034,1,'传输对象模式','传输对象模式（Transfer Object Pattern）用于从客户端向服务器一次性传递带有多个属性的数据。传输对象也被称为数值对象。传输对象是一个具有 getter/setter 方法的简单的 POJO 类，它是可序列化的，所以它可以通过网络传输。它没有任何的行为。服务器端的业务类通常从数据库读取数据，然后填充 POJO，并把它发送到客户端或按值传递它。对于客户端，传输对象是只读的。客户端可以创建自己的传输对象，并把它传递给服务器，以便一次性更新数据库中的数值。以下是这种设计模式的实体。 用于简化网络或应用程序层之间的数据传输。它通过创建一个包含多个属性的类来封装数据，这些属性代表需要传...','# 传输对象模式\n\n传输对象模式（Transfer Object Pattern）用于从客户端向服务器一次性传递带有多个属性的数据。传输对象也被称为数值对象。传输对象是一个具有 getter/setter 方法的简单的 POJO 类，它是可序列化的，所以它可以通过网络传输。它没有任何的行为。服务器端的业务类通常从数据库读取数据，然后填充 POJO，并把它发送到客户端或按值传递它。对于客户端，传输对象是只读的。客户端可以创建自己的传输对象，并把它传递给服务器，以便一次性更新数据库中的数值。以下是这种设计模式的实体。\n\n- 业务对象（Business Object） - 为传输对象填充数据的业务服务。\n- 传输对象（Transfer Object） - 简单的 POJO，只有设置/获取属性的方法。\n- 客户端（Client） - 客户端可以发送请求或者发送传输对象到业务对象。\n\n## 概要\n\n### 意图\n\n用于简化网络或应用程序层之间的数据传输。它通过创建一个包含多个属性的类来封装数据，这些属性代表需要传输的数据。\n\n### 主要解决的问题\n\n- 解决在分布式系统中，尤其是多层应用程序中，数据在层与层之间传输时的效率和封装性问题。\n\n### 使用场景\n\n- 当需要在客户端和服务器之间传输大量数据时，特别是Web服务或远程过程调用（RPC）。\n\n### 实现方式\n\n- 传输对象类：定义一个包含多个属性的类，这些属性代表需要传输的数据。\n- 数据访问层：负责从数据库或其他数据源提取数据，并填充到传输对象中。\n- 业务逻辑层：可选，处理业务逻辑，可能需要使用传输对象。\n- 表示层或客户端：使用传输对象来显示数据或作为用户输入的数据载体。\n\n### 关键代码\n\n- 传输对象类：包含属性和可能的业务逻辑，用于数据的封装和传输。\n\n### 应用实例\n\n- Web应用程序：表示层通过传输对象从服务器获取或发送数据。\n\n### 优点\n\n1. 减少网络通信开销：通过一次性传输多个数据，减少网络请求次数。\n2. 封装性：传输对象作为数据的封装载体，隐藏了内部数据结构。\n3. 易于维护：集中管理传输数据，便于修改和扩展。\n\n### 缺点\n\n- 过度使用：可能会因为创建过多的传输对象而导致系统复杂性增加。\n\n### 使用建议\n\n- 当需要在多层应用程序的不同层之间传输大量数据时，考虑使用传输对象模式。\n\n### 注意事项\n\n- 传输对象应该保持轻量级，避免包含过多的业务逻辑。\n\n### 包含的几个主要角色\n\n1. 传输对象类（Transfer Object Class）：\n  - 封装了需要传输的数据。\n2. 数据访问层（Data Access Layer）：\n  - 提供数据，并可能负责将数据填充到传输对象中。\n3. 业务逻辑层（Business Logic Layer）（可选）：\n  - 可选，处理业务逻辑，可能使用传输对象。\n4. 表示层或客户端（Presentation Layer or Client）：\n  - 使用传输对象来显示数据或发送请求。\n\n传输对象模式通过封装传输数据为一个对象，提供了一种有效的方式来减少网络通信次数，并简化数据传输过程。\n\n## 实现\n\n我们将创建一个作为业务对象的 StudentBO 和作为传输对象的 StudentVO，它们都代表了我们的实体。\n\nTransferObjectPatternDemo 类在这里是作为一个客户端，将使用 StudentBO 和  Student 来演示传输对象设计模式。\n\n![传输对象模式的 UML 图](/api/uploads/files/runoob/design_pattern/20201015-transfer-5842dcba97.svg)\n\n## 步骤 1\n\n创建传输对象。\n\n## StudentVO.java\n\npublic class StudentVO {\nprivate String name;\n   private int rollNo;\n\n   StudentVO(String name, int rollNo){\nthis.name = name;\n      this.rollNo = rollNo;\n   }\npublic String getName() {\nreturn name;\n   }\npublic void setName(String name) {\nthis.name = name;\n   }\npublic int getRollNo() {\nreturn rollNo;\n   }\npublic void setRollNo(int rollNo) {\nthis.rollNo = rollNo;\n   }\n}\n\n## 步骤 2\n\n创建业务对象。\n\n## StudentBO.java\n\nimport java.util.ArrayList;\nimport java.util.List;\n\npublic class StudentBO {\n//列表是当作一个数据库\nList<StudentVO> students;\n\n   public StudentBO(){\nstudents = new ArrayList<StudentVO>();\n      StudentVO student1 = new StudentVO("Robert",0);\n      StudentVO student2 = new StudentVO("John",1);\n      students.add(student1);\n      students.add(student2);\n   }\npublic void deleteStudent(StudentVO student) {\nstudents.remove(student.getRollNo());\n      System.out.println("Student: Roll No "\n      + student.getRollNo() +", deleted from database");\n   }\n//从数据库中检索学生名单\npublic List<StudentVO> getAllStudents() {\nreturn students;\n   }\npublic StudentVO getStudent(int rollNo) {\nreturn students.get(rollNo);\n   }\npublic void updateStudent(StudentVO student) {\nstudents.get(student.getRollNo()).setName(student.getName());\n      System.out.println("Student: Roll No "\n      + student.getRollNo() +", updated in the database");\n   }\n}\n\n## 步骤 3\n\n使用 StudentBO 来演示传输对象设计模式。\n\n## TransferObjectPatternDemo.java\n\npublic class TransferObjectPatternDemo {\npublic static void main(String[] args) {\nStudentBO studentBusinessObject = new StudentBO();\n\n      //输出所有的学生\nfor (StudentVO student : studentBusinessObject.getAllStudents()) {\nSystem.out.println("Student: [RollNo : "\n         +student.getRollNo()+", Name : "+student.getName()+" ]");\n      }\n//更新学生\nStudentVO student =studentBusinessObject.getAllStudents().get(0);\n      student.setName("Michael");\n      studentBusinessObject.updateStudent(student);\n\n      //获取学生\nstudentBusinessObject.getStudent(0);\n      System.out.println("Student: [RollNo : "\n      +student.getRollNo()+", Name : "+student.getName()+" ]");\n   }\n}\n\n## 步骤 4\n\n执行程序，输出结果：\n\n```text\n\nStudent: [RollNo : 0, Name : Robert ]\nStudent: [RollNo : 1, Name : John ]\nStudent: Roll No 0, updated in the database\nStudent: [RollNo : 0, Name : Michael ]\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/design-pattern/transfer-object-pattern.html\n','https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=800','设计模式',NULL,0,NULL,'runoob-design-pattern-transfer-object-pattern','传输对象模式 - 设计模式教程','传输对象模式（Transfer Object Pattern）用于从客户端向服务器一次性传递带有多个属性的数据。传输对象也被称为数值对象。传输对象是一个具有 getter/setter 方法的简单的 POJO 类，它是可序列化的，所以它可以...',0,'PUBLISHED',7295,325,220,43,'2025-08-04 00:00:00','2025-08-04 00:00:00','2026-05-10 17:46:58',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (633035,1,'设计模式资源','本章列出了设计模式相关的网站、书籍和文章。 原文链接：https://www.runoob.com/design-pattern/design-pattern-resources.html','# 设计模式 资源\n\n本章列出了设计模式相关的网站、书籍和文章。\n\n## 设计模式相关的网站\n\n- [Wiki Page for Design Patterns](https://en.wikipedia.org/wiki/Design_pattern_(computer_science)) - 以一种非常通用的方式检查设计模式。\n- [Java Programming/Design Patterns](https://en.wikibooks.org/wiki/Java_Programming/Design_Patterns) - 一篇关于设计模式的好文章。\n- [The Java TM Tutorials](http://java.sun.com/docs/books/tutorial/index.html) - 该 Java 教程是为那些想用 Java 编程语言创建应用程序的编程人员提供的实用指南。\n- [Java TM 2 SDK, Standard Edition](http://java.sun.com/j2se/1.4.2/docs/index.html) - JavaTM 2 SDK, Standard Edition 的官网。\n\n- [Head First设计模式](https://union-click.jd.com/jdc?e=618%7Cpc%7C&p=JF8BAM0JK1olXwUFU1xdCE4TBl8IGVwVWAACVW4ZVxNJXF9RXh5UHw0cSgYYXBcIWDoXSQVJQwYAU15YDksWHDZNRwYlLnQFIV86fVF3Bz98HwUcAn0YFwxDaEcbM244GFkUXwYyZF5aOBl529m-w_6kQdKo24vVn3sWM28PHV0dXAUCXF9ZCUInBG8BKx5NDVlCDBcFV3snM2w4HFscSQBwFQxJDjknM284GGsVVQQDVl1eAEkLA24NHlMJXQEEUlZcC0sWAW4AE2sXXAcGXW5t)\n- [设计模式：可复用面向对象软件的基础](https://union-click.jd.com/jdc?e=618%7Cpc%7C&p=JF8BAM0JK1olXwUFU1xdCE4TBl8IGFwWXwILXW4ZVxNJXF9RXh5UHw0cSgYYXBcIWDoXSQVJQwYBU11fDEIeHDZNRwYlXxhWEBghTwJ3dhlMEl5KAVV4FhUAXkcbM244GFkUXwYyZF5aOBl529m-w_6kQdKo24vVn3sWM28PHV0dXAUBUV5fDE8nBG8BKx5NDVlCDBcFV3snM2w4HFscSQBwFQxJDjknM284GGsVVQQDVl1eAEkLA24NHlMJXQEEUlZcC0sWAW4AE2sXXAcGXW5t)\n- [图解Java多线程设计模式](https://union-click.jd.com/jdc?e=618%7Cpc%7C&p=JF8BAM0JK1olXwUFU1xdCE4TBl8IGFsSWQQCUm4ZVxNJXF9RXh5UHw0cSgYYXBcIWDoXSQVJQwYBVFlZCksRHDZNRwYlPwBALwwrWhFyUB1WZyRWHmN8KSw9aEcbM244GFkUXwYyZF5aOBl529m-w_6kQdKo24vVn3sWM28PHV0dXAUBUl1eDk4nBG8BKx5NDVlCDBcFV3snM2w4HFscSQBwFQxJDjknM284GGsVVQQDVl1eAEkLA24