SET NAMES utf8mb4;
USE `my_blog`;
START TRANSACTION;



UPDATE `blog_article_tag` SET `deleted_at`='2026-05-10 17:46:58',`updated_at`='2026-05-10 17:46:58' WHERE `article_id` IN (633000, 633001, 633002, 633003, 633004, 633005, 633006, 633007, 633008, 633009, 633010, 633011, 633012, 633013, 633014, 633015, 633016, 633017, 633018, 633019, 633020, 633021, 633022, 633023, 633024, 633025, 633026, 633027, 633028, 633029, 633030, 633031, 633032, 633033, 633034, 633035);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-10 17:46:58',`updated_at`='2026-05-10 17:46:58' WHERE `column_id`=9600014;
UPDATE `blog_topic_article` SET `deleted_at`='2026-05-10 17:46:58',`updated_at`='2026-05-10 17:46:58' WHERE `topic_id`=9700014;

UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg INNER JOIN `blog_article` a ON a.`id` = atg.`article_id` WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`name` IN ('设计模式', '架构', '面向对象', '代码设计');
UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE c.`id` = 9600014;
UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`id` = 9700014;
COMMIT;
